/** Etymology data for lemma IDs in chunk 0 */
export const etymologyChunk0: Record<number, string> = {
  "1": "آباءُ and related words stem from the root أ-ب-و, with the root verb أَبَوْتُ meaning \"I became a father\" or \"I nourished.\" آباءُ (plural of أَبٌ) refers to \"fathers\" or \"forefathers,\" emphasizing lineage and heritage. The root reflects concepts of origin and nurturing, highlighting the father’s role as a protector and provider. It includes both biological and nurturing roles, such as caring for orphans. The plural also extends to \"parents\" as a unit.",
  "2": "آتَى and related words stem from the root أ-ت-ى, with the root verb أَتَى meaning \"he came\" or \"he arrived.\" آتَى means \"he gave\" or \"he bestowed,\" reflecting the causative sense of \"causing something to come\" to someone. The root emphasizes purposeful arrival, which transitions into the act of delivering or granting. In the Qur'an, آتَى is frequently used to describe Allah’s (ﷻ) act of bestowing favors, provisions, or guidance, highlighting His generosity and the deliberate, continuous arrival of His blessings to creation.",
  "3": "آتِي and related words stem from the root أ-ت-ى, with the root verb أَتَى meaning \"he came\" or \"he arrived.\" The root also conveys the idea of approaching deliberately or being drawn toward something with purpose. آتِي means \"coming\" or \"one who comes.\" The connection lies in the ongoing action of arrival or approach, directly reflecting the root's emphasis on deliberate movement. In the Qur'an, آتِي is often used to refer to impending events or the coming of the Day of Judgment, emphasizing the inevitability and purposeful unfolding of divine decrees.",
  "4": "آثَرَ and related words stem from the root أ-ث-ر, with the root verb أَثَرَ meaning \"he left a mark\" or \"he tracked,\" or \"he followed a trace.\" آثَرَ means \"he preferred,\" \"he chose,\" or \"he gave preference to.\" The connection lies in the idea that when one chooses or gives preference to something, they follow what leaves a lasting impact or \"mark\" on their life and character. This reflects the root’s emphasis on leaving an imprint, as the choices one makes influence the path they follow and the legacy they leave behind.",
  "5": "آثِمٌ and related words stem from the root أ-ث-م, with the root verb أَثِمَ meaning \"he sinned\" or \"he committed a misdeed.\" آثِمٌ means \"sinner\" or \"one who commits sin.\" The root also conveys the idea of delaying, hindering, or depriving oneself of good, emphasizing the consequences of sin as a barrier to righteousness. In the Qur'an, آثِمٌ describes individuals who knowingly engage in prohibited actions, reflecting their moral accountability and the loss of spiritual benefit caused by their transgressions.",
  "6": "آخَرَ and related words stem from the root أ-خ-ر, with the root verb أَخَّرَ meaning \"he delayed,\" \"he postponed,\" or \"he put back.\" آخَرَ means \"other,\" \"another,\" or \"different.\" The connection lies in the concept of something following or being distinct in time, position, or kind, reflecting the root's emphasis on deferral or succession. آخَرَ signifies distinction from what is first or primary, emphasizing diversity or addition. It can also suggest progression or alternatives, encouraging the consideration of differing perspectives or possibilities.",
  "7": "آخِذٌ and related words stem from the root أ-خ-ذ, with the root verb أَخَذَ meaning \"he took,\" \"seized,\" or \"grasped.\" آخِذٌ means \"one who takes,\" \"taker,\" or \"recipient.\" The connection lies in the act of taking or receiving, embodying the root's concept of grasping or acquiring something. آخِذٌ can refer to someone who accepts guidance, knowledge, or responsibility. It emphasizes the agency in choosing to take hold of opportunities or obligations, and in a moral context, it highlights the importance of being receptive to truth and acting upon it.",
  "8": "آخِرُ and related words stem from the root أ-خ-ر, with the root verb أَخَّرَ meaning \"he delayed\" or \"he postponed.\" آخِرُ means \"last,\" \"end,\" or \"final,\" reflecting the idea of something coming after all others in time or sequence. Often associated with the Hereafter (الْآخِرَةُ), it emphasizes the culmination of events and ultimate accountability. From the same root is ٱلآخِرُ, one of Allah’s (ﷻ) perfect names, meaning \"The Last,\" highlighting His eternal nature. The root concept of deferral further reflects Allah’s (ﷻ) role as the ultimate end, reminding us that all creation will return to Him.",
  "9": "آدَمُ and related words stem from the root أ-د-م, with the root verb أَدَمَ meaning \"he reconciled\" or \"he made harmony.\" آدَمُ is the name of the first human and prophet, Adam (ﷺ). The root also relates to \"surface\" or \"skin,\" referring to the visible layer of the earth or human skin, highlighting the earthy color of human skin and humanity's creation from the earth's surface. In the Qur'an, the story of Adam (ﷺ) symbolizes human origin, moral responsibility, and the potential for repentance and divine forgiveness.",
  "10": "آزَرَ refers to the father of Prophet Abraham (ﷺ). Many scholars suggest this name is of foreign origin, potentially Assyrian, Akkadian, or Persian, reflecting the cultural influences of Mesopotamia (modern-day Iraq), where Prophet Abraham (ﷺ) lived. In the Qur'an, آزَرَ is mentioned in connection with idol worship, opposing Abraham’s (ﷺ) message of monotheism. Despite being his father, آزَرَ rejected his son’s calls to abandon idolatry and embrace Allah (ﷻ), illustrating the trials Abraham (ﷺ) faced in delivering truth, even within his family. His story serves as a lesson on wisdom and perseverance in spreading tawheed within one’s household, where resistance can often be the strongest.",
  "11": "آزَرَ and related words stem from the root أ-ز-ر, with the root verb أَزَرَ meaning \"it surrounded\" or \"it encompassed.\" آزَرَ means \"he aided, assisted, helped, or strengthened,\" often in the sense of actively supporting someone against opposition or in achieving a goal. The connection lies in the idea of surrounding with support, offering reinforcement and protection. Just as something that surrounds provides security and strength, these terms reflect the concept of surrounding a person with aid or backing, whether through physical assistance or moral support.",
  "12": "الآزِفَةُ and related words stem from the root أ-ز-ف, with the root verb أَزِفَ meaning \"it drew near\" or \"it approached,\" indicating something imminent. الآزِفَةُ means \"the Approaching Day,\" one of the names for the Day of Judgment. The root also conveys urgency, quickness, and inevitability, emphasizing the unstoppable progression of time. The connection lies in the Day of Judgment itself drawing near, emphasizing its certainty and the need for preparedness.",
  "13": "آسَفُوا and related words stem from the root أ-س-ف, with the root verb أَسِفَ meaning \"he was grieved,\" \"he was sorrowful,\" or \"he was regretful.\" It also conveys anger stemming from deep disappointment or sorrow. آسَفُوا means \"they caused grief\" or \"they angered,\" reflecting actions that provoke sorrow or indignation in others. The root emphasizes emotional intensity, encompassing both profound personal grief and the provocation of such feelings in others through words or actions.",
  "14": "آسِنٌ and related words stem from the root أ-س-ن, with the root verb أَسَنَ meaning \"it became altered for the worse in odor\" or \"it became foul,\" particularly describing water that has become foul or putrid due to stagnation or lack of flow. آسِنٌ means \"stagnant\" or \"stale,\" typically used for water that has ceased to flow, leading to impurity and decay. The connection lies in the transformation from freshness to degradation, emphasizing the root's focus on stagnation, deterioration, and the negative change due to lack of movement.",
  "15": "آفِلِينَ and related words stem from the root أ-ف-ل, with the root verb أَفَلَ meaning \"it was absent, hidden, or concealed.\" آفِلِينَ refers to celestial bodies, like stars or the moon, that eventually set and become concealed from view. The connection lies in the root's emphasis on disappearance, highlighting the temporary and fading nature of these objects. In the Qur'an, the term is used in the story of Prophet Abraham (ﷺ) to emphasize the temporary nature of celestial bodies, as they fade from sight, and to affirm that true worship is due only to Allah (ﷻ), who is Ever-Present and Eternal.",
  "16": "آكِلِينَ and related words stem from the root أ-ك-ل, with the root verb أَكَلَ meaning \"he ate\" or \"he consumed.\" آكِلِينَ highlights the act of eating as a defining characteristic, often referring to those who consume. In moral contexts, it can imply greed or injustice in the consumption of resources, emphasizing the ethical implications of one's consumption habits. The broader root meaning includes the depletion of resources and gradual destruction, reinforcing that unchecked consumption can lead to moral and societal harm.",
  "17": "آلُ and related words stem from the root أ-و-ل, with the root verb آلَ meaning \"he returned,\" \"resorted to,\" or \"went foremost.\" آلُ refers to \"family,\" \"people,\" or \"household,\" particularly those closely associated with a person. The connection lies in the idea of returning to one’s kin or close group, reflecting the root’s themes of return and association. This term highlights familial bonds and shared identity, emphasizing a natural connection to one’s origins. In the Qur'an, آلُ refers to those closely associated with a significant figure, highlighting a connection with those whom one follows.",
  "18": "آلَاءٌ and related words stem from the root أ-ل-و, with the root verb أَلَا carrying meanings such as \"he fell short\" or \"he was negligent or careless.\" Despite these initial meanings, آلَاءٌ, the plural of إِلًى, refers to \"favors\" or \"blessings,\" emphasizing the vast and countless bounties of Allah (ﷻ). The connection lies in the contrast between human negligence and Allah’s (ﷻ) unwavering generosity. While humans may neglect their duties or fall short, Allah’s (ﷻ) blessings remain abundant and ever-present. This contrast reminds us of the importance of reflection and gratitude, urging creation to recognize and appreciate the infinite mercy and sustenance provided by Allah (ﷻ).",
  "19": "آمَنَ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he was secure,\" or \"he trusted.\" آمَنَ translates to \"he believed\" or \"he had faith,\" emphasizing placing trust and finding security through belief. The connection lies in entrusting oneself to a higher power and finding peace in truth, reflecting the root’s themes of safety, trust, and assurance. Faith embodies inner security and deep trust in Allah (ﷻ), highlighting belief as a source of spiritual tranquility.",
  "20": "آمِرُونَ and related words stem from the root أ-م-ر, with the root verb أَمَرَ meaning \"he commanded,\" \"he ordered,\" or \"he enjoined.\" While أَمَرَ primarily refers to giving orders or directing others, آمِرُونَ refers to \"those who consult\" or \"those who advise.\" This meaning highlights a broader sense of guidance or leadership, where individuals provide counsel or instruction. The root connection reflects the concept of giving direction, whether through commanding or offering thoughtful advice.",
  "21": "آمِنٌ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he was secure,\" or \"he trusted.\" آمَنَ translates to \"he believed\" or \"he had faith,\" emphasizing the act of placing trust and finding security through belief. آمِنٌ means \"safe,\" \"secure,\" or \"peaceful,\" describing a state or person free from fear or danger. The connection reflects the root's emphasis on safety and trust, signifying that tranquility and reassurance come from believing and having faith. This highlights the root's core themes of peace, trust, and stability, derived from reliance on Allah (ﷻ) and the security of faith.",
  "22": "آمِنَةٌ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he was secure,\" or \"he trusted,\" emphasizing the state of being protected or free from harm. آمِنَ means \"he felt safe\" or \"he was at peace,\" focusing on the experience of safety and tranquility. آمِنَةٌ means \"safe,\" \"secure,\" or \"peaceful,\" describing a state or place characterized by peace and freedom from fear. The connection to the root lies in the expression of safety, trust, and protection, reflecting the root’s emphasis on security and tranquility as essential states of existence.",
  "23": "آمِّينَ and related words stem from the root أ-م-م, with the root verb أَمَّ meaning \"he intended,\" \"he aimed at,\" \"he directed his course toward,\" or \"he led.\" آمِّينَ means \"those who intend\" or \"those heading toward a destination.\" This reflects the root's concept of purposeful movement and intentional direction toward a goal. In the context of pilgrimage, it refers to individuals journeying toward a sacred place, embodying the root's emphasis on direction, intention, and guided purpose. This broader meaning encompasses themes of dedication and commitment to reaching a chosen destination.",
  "24": "The particle الْآنَ means \"now,\" marking the present moment with clarity and significance. In the Qur'an, it is used in various contexts to convey immediacy. It highlights the urgency of action, the critical timing of events, or a shift in realization, particularly in moments of regret or reproach when someone acknowledges the truth too late. الْآنَ draws attention to pivotal moments, urging mindfulness and prompt action while also reflecting the consequences of delayed recognition. Its usage serves as a profound reminder to seize opportunities and act with awareness before the moment passes.",
  "25": "آنَاءٌ and related words stem from the root أ-ن-ي, with the root verb أَنَىٰ meaning \"it matured,\" \"it became due,\" or \"it reached its time.\" آنَاءٌ means \"hours,\" \"periods,\" or \"times,\" specifically referring to portions of time that have reached their designated points.This root carries the sense of something arriving at its appointed moment or ripening at the proper time. The connection lies in the concept of time segments that unfold and reach their due or \"mature\" moments, highlighting the progression and appointed nature of these intervals.",
  "26": "آنَسَ and related words stem from the root أ-ن-س, with the root verb أَنِسَ meaning \"he was sociable\" or \"he became familiar.\" آنَسَ means \"he sensed,\" \"he consoled,\" or \"he made someone feel at ease.\" The distinction lies in أَنِسَ describing an internal state of comfort or sociability, while آنَسَ involves actively perceiving and responding—whether by sensing one’s surroundings or by offering comfort to others. Broader root concepts include familiarity, companionship, and awareness, reflecting how internal ease and external acts of comfort foster harmony and reassurance.",
  "27": "آنِفٌ and related words stem from the root أ-ن-ف, with the root verb أَنِفَ meaning \"he was proud,\" \"he felt disdain,\" or \"he took offense.\" آنِفٌ means \"the beginning of the present time\" or \"just now,\" indicating the recent past. The connection lies in the idea of being forward, distinct, or set apart, as the nose (أَنفٌ) is positioned at the front of the face. Just as pride or disdain can create a sense of separation or prominence, آنِفٌ captures this sense of something freshly present or set apart in time—something immediately before the present, recent and distinct. This term reflects the root’s emphasis on both prominence and immediacy.",
  "28": "آنِيَةٌ and related words stem from the root أ-ن-ي, with the root verb أَنَىٰ meaning \"it matured,\" \"it became due,\" or \"it reached its time.\" آنِيَةٌ (the plural of إِناءٌ) means \"vessels\" or \"containers.\" The root implies readiness and arriving at a designated moment, linking to vessels as items prepared for specific use, embodying suitability and timing. In the Qur'an, آنِيَةٌ appears in contrasting contexts: as exquisite silver vessels for Paradise and as an adjective describing a \"spring at peak heat,\" where the sense of maturity conveys extreme heat—emphasizing readiness for both reward and retribution.",
  "29": "آوَى and related words stem from the root أ-و-ي, with the root verb أَوَى meaning \"he took shelter\" or \"he sought refuge.\" آوَى means \"he gave shelter\" or \"he provided refuge.\" This term denotes the act of offering protection, safety, or a place of rest, especially for those in need. The root suggests bringing someone into a state of comfort, security, or stability, reflecting qualities of compassion, mercy, and a sense of belonging. آوَى emphasizes the importance of providing sanctuary and support, highlighting the value of offering solace and care to those in times of vulnerability.",
  "30": "آيَةٌ and related words stem from the root أ-ي-ي, with the root verb أَيَّا meaning \"to put or set a sign, token, or mark by which a person or thing might be known.\" آيَةٌ translates as \"sign,\" \"miracle,\" \"evidence,\" or \"verse,\" often directing attention to the existence and power of Allah (ﷻ). The word embodies the root’s concept of marking or signaling something beyond itself, pointing to a deeper reality. It emphasizes the importance of signs, both in the natural world and divine revelation, as means to guide people toward recognizing Allah’s (ﷻ) existence, wisdom, and authority.",
  "31": "The letter \"أ\" functions as a particle to pose questions, marking the beginning of an inquiry or request for information. It acts as an interrogative marker, equivalent to \"Is it...?\" or \"Do...?\" in English, prompting a response or reflection. This particle is essential for forming yes/no questions in Arabic, adding clarity, simplicity, and efficiency to the language. Its use ensures that the intent to seek information is immediately understood by the listener or reader. Allah (ﷻ) frequently employs this form of questioning in the Qur'an to engage the reader and provoke deep self-reflection.",
  "32": "أَبٌّ and related words stem from the root أ-ب-و, with the root verb أَبَوْتُ meaning \"I became a father\" or \"I nourished.\" أَبٌّ means \"father,\" signifying not only a biological parent but also a figure of guidance and support. It extends to nurturing roles, such as caring for orphans. The root conveys concepts of origin, foundation, and protection, emphasizing the father’s role as an originator and protector within the family. In the Qur'an, أَبٌّ highlighting the importance of honouring parents and recognizing their pivotal role in one’s life and upbringing.",
  "33": "أَبَابِيلٌ and related words stem from the root أ-ب-ل, with the root verb أَبِلَ meaning \"he became skilled in managing camels or sheep,\" \"became plentiful,\" or \"was abundant.\" The root conveys ideas of abundance, organization, and effective coordination. أَبَابِيلٌ refers to \"flocks\" or \"dispersed groups\" moving in a coordinated and purposeful manner, much like camels or birds under skilled management. In the Qur'an, it symbolizes Allah’s (ﷻ) supreme ability to control and direct creation with precision and harmony, illustrating His majestic power over all things.",
  "34": "أَبارِيقُ and related words stem from the root ب-ر-ق, with the root verb بَرَقَ meaning \"it shone, gleamed, or glistened.\" إِبْرِيقٌ translates as \"a jug or ewer,\" with أَبارِيقُ as its plural, referring to elegant vessels for pouring liquids. The root’s emphasis on gleaming or shining suggests these vessels are made of fine materials that catch the light, symbolizing luxury, refinement, and splendor. This imagery reflects the vessels’ association with comfort and the highest quality, often used to evoke a sense of opulence and exclusive privileges.",
  "35": "أَبَدًا and related words stem from the root أ-ب-د, with the root verb أَبَدَ meaning \"he became remote\" or \"he remained distant,\" conveying the sense of perpetuity or being far removed in time or place. أَبَدًا means \"forever\" or \"eternally,\" signifying an endless duration without interruption. The connection lies in the concept of remoteness extending infinitely, illustrating the root's emphasis on perpetual existence or continuance. In the Qur'an, أَبَدًا often emphasizes the eternal nature of the Hereafter, reminding us of the everlasting consequences of our actions.",
  "36": "أَبَقَ and related words stem from the root أ-ب-ق, meaning \"he ran away,\" especially referring to a slave fleeing from his master without being driven by fear or severe work. This specificity differentiates it from general forms of escape, signifying an unprovoked departure. The connection lies in the act of escape and abandonment, directly relating to the root's emphasis on fleeing. In the Qur'an, this term is used to describe Prophet Jonah (ﷺ) when he departed without awaiting Allah's (ﷻ) command, highlighting the consequences of impatience and the importance of steadfastness in the face of trials.",
  "37": "أَبَوَانِ and related words stem from the root أ-ب-و, with the root verb أَبَوْتُ meaning \"I became a father\" or \"I nourished.\" أَبَوَانِ is the dual form of أَبٌ, literally meaning \"two fathers,\" but in Arabic, it refers to \"parents,\" including both father and mother, and sometimes forefathers. It encompasses both biological and nurturing roles, such as raising orphans. The root emphasizes origin and foundation, highlighting parents as the pillars of a child’s upbringing. This form reflects the equal importance of both parents in guiding their children and the foundational role of family.",
  "38": "أَبَى and related words stem from the root أ-ب-ى, and as the root verb, it means \"he refused\" or \"he declined,\" embodying deliberate rejection or unwillingness to comply. The root also yields أُبِيَةٌ, meaning \"pride\" or \"self-magnification,\" connecting refusal to arrogance. This highlights that rejecting Allah’s (ﷻ) commands often stem from pride, reflecting a deeper issue of the heart. In the Qur'an, أَبَى describes those who reject faith, emphasizing the importance of humility and submission to Allah (ﷻ). The connection lies in how refusal, rooted in pride, prevents submission to Allah's (ﷻ) guidance.",
  "39": "أَبٌّ and related words stem from the root أ-ب-ب, with the root verb أَبَّ meaning \"it grew abundantly\" or \"he collected fodder.\" أَبٌّ refers to herbage or pasture—the vegetation that animals graze upon. The connection lies in the growth of vegetation providing sustenance for animals. In the Qur'an, Allah (ﷻ) mentions أَبًّا as part of the sustenance He provides, highlighting His care for all creatures and how all life is interconnected through His provisions.",
  "40": "أَبْتَرُ and related words stem from the root ب-ت-ر, with the root verb بَتَرَ meaning \"he cut off.\" أَبْتَرُ translates as \"cut off\" or \"without continuity,\" often describing someone without descendants or legacy. This term conveys incompleteness or severance, reflecting the root’s concept of being cut off or deprived of lasting continuation.",
  "41": "أَبْرَحَ and related words stem from the root ب-ر-ح, with the root verb بَرِحَ meaning \"he went away,\" \"departed,\" or \"ceased.\" The root conveys ideas of separation, movement, and leaving a particular state or place, often implying a significant shift. أَبْرَحَ translates as \"I will go away,\" \"depart,\" or \"withdraw.\" When combined with negations in the Qur'an, such as لَا or لَنْ, it conveys persistence, meaning \"I will not depart\" or \"I will not cease,\" emphasizing commitment and an unyielding stance.",
  "42": "أَبْرَصٌ and related words stem from the root ب-ر-ص, with the root verb بَرِصَ meaning \"he was or became affected with leprosy\" or \"he developed white patches on the skin, distinct from normal complexion.\" أَبْرَصٌ refers to a person afflicted with a skin condition like leprosy or vitiligo, which visibly marks the skin with discoloration. This root conveys visible distinction, as these conditions contrast with typical complexion. The same root also gives بُرْصٌ, referring to a type of gecko, symbolically linked to a mottled or distinct appearance.",
  "43": "أَبْرَمُوا and related words stem from the root ب-ر-م, with the root verb بَرِمَ meaning \"he was affected with disgust, loathing, or vexation,\" often implying irritation that leads to stubborn resolve. أَبْرَمَ means \"he made it of two strands and twisted it,\" or \"he made firm or strong,\" referring to intertwining ropes for added strength and security. أَبْرَمُوا means \"they twisted\" or \"they made firm,\" symbolizing reinforcement and determination, whether in physical actions like twisting ropes or in solidifying intentions. The root conveys themes of binding, strengthening, and resolve, highlighting a fixed determination that can arise from defiance or resistance.",
  "44": "أَبْشِرُوا and related words stem from the root ب-ش-ر, with the root verb بَشِرَ meaning \"he rejoiced\" or \"he was cheerful.\" أَبْشِرُوا means \"rejoice\" or \"receive glad tidings,\" used as an encouragement or command to embrace happiness. The root conveys themes of joy, gladness, and renewal, emphasizing positive transformation and uplifting emotions. أَبْشِرُوا reflects a call to welcome good news with a joyful and open heart, highlighting both the reception of blessings and the emotional upliftment they bring.",
  "45": "أَبْصَرَ and related words stem from the root ب-ص-ر, with the root verb بَصُرَ meaning \"he saw\" or \"he became endowed with mental perception, belief, firm belief, knowledge, understanding, intelligence, or skill.\" أَبْصَرَ means \"he saw\" or \"he observed,\" but it differs from بَصَرَ by emphasizing attentive, purposeful observation. This form implies seeing with intent and insight, where physical sight is combined with mental perception. In the Qur'an, أَبْصَرَ highlights the importance of looking beyond the surface to grasp deeper truths, linking observation to awareness and understanding.",
  "46": "أَبْقَىٰ and related words stem from the root ب-ق-ي, with the root verb بَقِيَ meaning \"he remained,\" \"he endured,\" or \"he stayed behind.\" أَبْقَىٰ means \"to make remain\" or \"to cause to endure,\" implying an active role in allowing something to persist, be preserved, or last over time. This root reflects concepts of continuity, preservation, and the choice to sustain or let endure. It highlights the contrast between what is temporary and what is allowed to last, often with a deeper sense of enduring purpose or intentionality in what remains.",
  "47": "أَبْكَمُ and related words stem from the root ب-ك-م, with the root verb بَكِمَ meaning 'he was mute,' 'unable to speak,' or 'weak in understanding.' أَبْكَمُ specifically refers to someone unable to express themselves verbally, whether due to a physical inability, ignorance, or an intentional choice to refrain from speaking. The root conveys ideas of muteness, silence, or inhibition, emphasizing a limitation in communication or self-expression. It reflects a state of restraint or constraint, where one’s ability to articulate thoughts or ideas is impeded, either by external factors, internal weakness, or deliberate avoidance.",
  "48": "أَبْكَىٰ and related words stem from the root ب-ك-ى, with the root verb بَكَىٰ meaning \"he cried\" or \"he wept.\" أَبْكَىٰ means \"he made someone cry\" or \"he caused weeping,\" describing the action of evoking tears or sadness in another. This causative form deepens the root’s themes of emotional release, vulnerability, and inner expression. Related forms within this root include not only direct expressions of crying but also ideas of intense yearning or sadness seeking expression.",
  "49": "أَبْلَغُوا and related words stem from the root ب-ل-غ, with the root verb بَلَغَ meaning \"he reached\" or \"he attained,\" and بَلَّغَ meaning \"he caused to reach\" or \"he conveyed.\" أَبْلَغُوا means \"they conveyed\" or \"they communicated,\" implying the act of reaching others with a message, insight, or information. Root meanings also involve completeness and achieving an intended goal, suggesting that أَبْلَغُوا conveys a sense of fully delivering something significant with eloquence and clarity. This word, therefore, highlights a purposeful, impactful communication that reaches its target completely.",
  "50": "أَبْيَضُ and related words stem from the root ب-ي-ض, with the root verb بَاضَ meaning \"it laid eggs,\" referring to the act of creation. أَبْيَضُ means \"white\", symbolizing purity, brightness, or clarity. In classical Arabic, whiteness can signify joy, honor, or light. The connection to the root reflects the idea of bringing forth or revealing something pure and clear, just as an egg signifies new life and creation.",
  "51": "أَتَمَّ and related words stem from the root ت-م-م, with the root verb تَمَّ meaning \"it became complete, entire, or full.\" أَتَمَّ means \"he completed\" or \"he perfected,\" signifying the act of bringing something to its full and perfect state. This root emphasizes reaching a final, whole form with nothing left incomplete, reflecting the idea of total fulfillment and precision. أَتَمَّ thus captures not only completion but also the process of refining something to its ideal state.",
  "52": "أَتَوَكَّأُ and related words stem from the root و-ك-أ, with the root verb وَكَأَ meaning \"he leaned.\" أَتَوَكَّأُ means \"I lean.\" The root conveys themes of seeking stability, physical reliance, and using an object or entity for dependable support. The connection lies in the act of seeking assistance or rest, directly reflecting the root's emphasis on leaning, dependence, and the idea of finding strength or steadiness through external support.",
  "53": "أَتَى and related words stem from the root أ-ت-ى, and as the root verb, it means \"he came\" or \"he arrived.\" The root embodies purposeful movement toward a destination or the act of approaching. When paired with بِ, it means \"to bring,\" adding the sense of delivering or presenting something. The connection lies in both the action of arrival and the act of bringing, emphasizing the transition from movement to fulfillment. In the Qur'an, أَتَى describes the coming of events, messages, or Allah’s (ﷻ) commands, while with بِ, it highlights the deliberate bringing or delivery of something significant.",
  "54": "أَتْبَعَ and related words stem from the root ت-ب-ع, with the root verb تَبِعَ meaning \"he followed.\" أَتْبَعَ means \"he caused to follow\" or \"he pursued,\" implying an intentional act of making something or someone continue in a sequence. Beyond just initiating a sequence, this term can highlight causation, where one event or person purposefully leads another. The broader meanings of تَبِعَ around pursuit and continuity reinforce the idea that أَتْبَعَ emphasizes a deliberate alignment of actions or people in a sustained course.",
  "55": "أَتْرَابٌ and related words stem from the root ت-ر-ب, with the root verb تَرِبَ meaning \"he became dusty\" or \"he was destitute,\" relating to تُرَابٌ (dust), symbolizing human origin and humility. تَارَبَ means \"he became [her] match or equal,\" while أَتْرَابٌ (plural of تِرْبٌ) means \"a match\" or \"those equal in age,\" describing companions in Paradise who are of the same age. The connection to the root reflects the idea of grounding and equality, emphasizing that these creations were intended as companions of the son of Adam (ﷺ). In Paradise, the term signifies a bond of companionship, highlighting harmonious equality and purity.",
  "56": "أَتْقَنَ and related words stem from the root ت-ق-ن, with the root verb تَقُنَ meaning \"he was precise, skilled, or proficient.\" أَتْقَنَ means \"he made [it] firm, stable, strong, or sound\" or \"he perfected it with precision and excellence.\" This term conveys the idea of establishing something with accuracy and thoroughness, emphasizing mastery and careful attention to detail. Rooted in the concept of precision, أَتْقَنَ implies a dedication to quality, where the outcome reflects skill and intentional refinement, ensuring it is both reliable and complete.",
  "57": "أَتْقَىٰ and related words stem from the root و-ق-ي, with the root verb وَقَىٰ meaning \"he guarded\" or \"he preserved.\" اتَّقَىٰ means \"he guarded himself\" or \"he was God-conscious,\" and أَتْقَىٰ means \"the most God-conscious.\" The connection lies in an intensified state of self-protection through profound mindfulness, where one diligently guards oneself from sin by being deeply aware of Allah (ﷻ). This reflects the root's core emphasis on protection, extended to spiritual safeguarding through elevated devotion and heightened awareness of Allah (ﷻ).",
  "58": "أَثَابَ and related words stem from the root ث-و-ب, with the root verb ثَابَ meaning \"he returned,\" \"he went back,\" or \"he came back to a place or state.\" This root embodies the idea of returning, restoration, and reciprocation. أَثَابَ means \"he rewarded,\" signifying the act of returning something as a recompense for deeds, whether good or bad. The connection lies in the root's sense of cycling back, where actions bring corresponding outcomes that are \"returned\" to their originator. This highlights a system of justice and reciprocity, where recompense reflects the balance and restoration inherent in the root meaning of returning to an original state or condition.",
  "59": "أَثَاثٌ and related words stem from the root أ-ث-ث, with the root verb أَثَّ meaning \"it became abundant or numerous.\" أَثَاثٌ means \"furnishings,\" \"goods,\" or \"possessions,\" particularly those that accumulate over time. The connection lies in the idea of abundance and growth, directly reflecting the root's emphasis on multiplication and accumulation.",
  "60": "أَثَارَةٌ and related words stem from the root أ-ث-ر, with the root verb أَثَرَ meaning \"he left a mark\" or \"he followed a trace.\" أَثَارَةٌ means \"remnant,\" \"trace,\" or \"legacy.\" The connection lies in the physical or metaphorical marks left by previous generations or actions, embodying the root’s concept of imprinting. أَثَارَةٌ refers specifically to remnants of ancient knowledge, records, or traditions passed down over time, continuing to influence the present as historical or cultural evidence.",
  "61": "أَثَارُوا and related words stem from the root ث-و-ر, with the root verb ثَارَ meaning \"he rose\" or \"he stirred up.\" أَثَارُوا means \"they stirred up\" or \"they aroused,\" directly tied to the root’s sense of causing movement, agitation, or rising. This term captures the act of setting something into motion or causing disruption, such as stirring up dust, emotions, or activity, emphasizing the dynamic and transformative nature of the action.",
  "62": "أَثَامٌ and related words stem from the root أ-ث-م, with the root verb أَثِمَ meaning \"he sinned\" or \"committed a misdeed.\" أَثَامٌ refers to \"penalty,\" \"punishment,\" or \"severe consequence,\" particularly as a result of sin. The root also conveys the idea of depriving oneself of good and hindering progress, emphasizing the harm that sin brings to both spiritual and worldly well-being. In the Qur'an, أَثَامٌ warns of the severe penalties awaiting persistent sinners, urging believers to reflect on the destructive nature of sin and strive for repentance and righteousness.",
  "63": "أَثَرٌ and related words stem from the root أ-ث-ر, with the root verb أَثَرَ meaning \"he left a mark,\" \"he tracked,\" or \"he followed a trace.\" أَثَرٌ means \"trace,\" \"mark,\" \"impression,\" or \"effect.\" The connection lies in the tangible or intangible marks left by actions, events, or words. It refers to the lasting impact one leaves on others or the world, whether through physical traces like footprints, or metaphorical ones like influence or consequences of actions.",
  "64": "أَثِيمٌ and related words stem from the root أ-ث-م, with the root verb أَثِمَ meaning \"he sinned\" or \"committed a misdeed.\" أَثِيمٌ means \"sinful\" or \"habitually sinning,\" describing someone characterized by persistent wrongdoing. The connection lies in the ongoing state of sinfulness, reflecting the root’s focus on transgression and moral corruption. It emphasizes a significant departure from ethical behavior and highlights the seriousness and gravity of these actions in distancing a person from righteousness.",
  "65": "أَثْخَنَ and related words stem from the root ث-خ-ن, with the root verb ثَخُنَ meaning \"it was thick\" or \"it was dense.\" أَثْخَنَ means \"he rendered [him] heavy or weakened him\" or \"he overpowered,\" reflecting the act of imposing such force that it leaves the opponent weakened or subdued. Building on the root's sense of thickness, it conveys the idea of making something heavy or burdensome, specifically in the context of battle. This highlights the intensity and overwhelming strength required to dominate and incapacitate, firmly establishing control in a situation.",
  "66": "أَثْقَلَتْ and related words stem from the root ث-ق-ل, with the root verb ثَقُلَ meaning \"it was heavy, weighty, burdensome.\" أَثْقَلَتْ means \"she became heavy,\" or \"her pregnancy became apparent, or manifest.\" Often referring to a pregnant woman approaching childbirth, it highlights the increasing weight and burden carried, directly tied to the root's meaning. This term symbolizes the culmination of a process leading to fruition or the bearing of significant responsibilities.",
  "67": "أَثْلٌ and related words stem from the root أ-ث-ل, with the root verb أَثَلَ meaning \"firm-rooted\" or \"noble in origin.\" أَثْلٌ refers to the tamarisk, known for its deep roots and resilience in arid environments, reflecting stability and nobility. In the Qur'an, tamarisks replaced the lush gardens of Saba’ as a sign of loss, symbolizing how transgressors lose blessings when they turn away from Allah (ﷻ). Interestingly, the Prophet’s (ﷺ) pulpit was made from tamarisk, emphasizing his standing and message as firm and noble, contrasting with its association with loss for the disobedient.",
  "68": "أَثْمَرَ and related words stem from the root ث-م-ر, with the root verb ثَمَرَ meaning \"it became ripe\" or \"it became abundant.\" أَثْمَرَ means \"it bore fruit\" or \"it began to yield its produce,\" signifying the act of generating results or benefits. While rooted in agricultural imagery, the term extends to convey broader concepts of growth, productivity, and tangible outcomes. Metaphorically, أَثْمَرَ symbolizes the rewards of effort, the culmination of hard work, and the realization of potential, emphasizing the root’s connection to abundance and fruitful endeavors.",
  "69": "أَجَلٌ and related words stem from the root أ-ج-ل, with the root verb أَجَلَ meaning \"he deferred\" or \"he delayed.\" أَجَلٌ means \"appointed time,\" \"term,\" or \"deadline,\" referring to a fixed or predetermined period. The connection lies in setting a specific time for an event, reflecting the root's emphasis on delay and timing. The root meaning of \"delay\" reflects Allah’s (ﷻ) mercy, as the appointed time itself is deferred, giving individuals extended chances to repent, seek forgiveness, and fulfill obligations, despite their repeated wrongs. This delay highlights Allah’s (ﷻ) patience and compassion toward His creation.",
  "70": "أَجِنَّةٌ and related words stem from the root ج-ن-ن, with the root verb جَنَّ meaning \"he covered\" or \"he concealed.\" أَجِنَّةٌ (plural of جَنِينٌ) means \"embryos\" or \"fetuses,\" referring to the unborn beings hidden within the womb. The root emphasizes hiddenness, concealment, and being veiled from view, which directly connects to the state of embryos as they are physically covered and protected within the mother’s womb. This term highlights themes of protection and the unseen stages of creation, reflecting the miracle of life developing in a concealed and safeguarded environment.",
  "71": "أَجَّلَ and related words stem from the root أ-ج-ل, with the root verb أَجَلَ meaning \"he deferred\" or \"he delayed.\" أَجَّلَ means \"he defined the term,\" \"assigned,\" \"appointed,\" or \"delayed,\" emphasizing the act of specifying or postponing something to a later time. The root meaning of \"delay\" reflects Allah’s (ﷻ) mercy, as the appointed time represents a deferral, giving individuals extended opportunities to repent, seek forgiveness, and fulfill obligations despite repeated wrongs. This inherent delay highlights Allah’s (ﷻ) patience and compassion toward His creation.",
  "72": "أَجْدَاثٌ and related words stem from the root ج-د-ث, with جَدَثٌ meaning \"grave.\" أَجْدَاثٌ, the plural form, specifically refers to \"graves\" and carries no broader associated meanings. This exclusivity highlights the inevitability and finality of death, serving as a powerful reminder of the universal fate that all souls must face. The simplicity of the term reflects the straightforward nature of the grave, leaving no room for ambiguity or deeper exploration—death and burial are certainties that transcend all complexities.",
  "73": "أَجْدَرُ and related words stem from the root ج-د-ر, with the root verb جَدُرَ meaning \"he was suitable\" or \"he was deserving.\" أَجْدَرُ means \"more suitable\" or \"more worthy,\" emphasizing comparative fitness or merit for a particular matter. The root reflects themes of propriety, worthiness, and appropriateness, often tied to fulfilling expectations or meeting standards. It conveys the idea of being specifically fit or qualified for a role or purpose, highlighting suitability in a way that distinguishes it from other forms of merit.",
  "74": "أَجْرٌ and related words stem from the root أ-ج-ر, with the root verb أَجَرَ meaning \"he rewarded\" or \"he hired.\" أَجْرٌ means \"reward,\" \"wage,\" or \"compensation\" given in return for work or service. The connection lies in the concept of recompense for effort or deeds, reflecting the root’s emphasis on hiring, compensation, and fair reward. In the Qur'an, أَجْرٌ frequently refers to the rewards awaiting believers for their righteous actions, highlighting the justice and generosity of Allah (ﷻ) in compensating His servants for their faith and good deeds, whether in this life or the Hereafter.",
  "75": "أَجْرَمُوا and related words stem from the root ج-ر-م, with the root verb جَرَمَ meaning \"he cut off\" or \"he committed a crime.\" أَجْرَمُوا means \"they committed crimes\" or \"they sinned,\" directly depicting acts of wrongdoing. The root conveys the idea of cutting off, particularly severing ties with morality, guidance, or what is right. It also highlights the deliberate nature of transgressing established boundaries. أَجْرَمُوا emphasizes the intentionality and gravity of such deeds, highlighting the destructive outcomes of willful transgressions.",
  "76": "أَجْلٌ and related words stem from the root أ-ج-ل, with the root verb أَجَلَ meaning \"he deferred\" or \"he delayed.\" أَجْلٌ means \"reason\" or \"purpose,\" highlighting the cause or intention behind an action, as distinct from أَجَلٌ, which refers to an appointed or fixed time. The connection lies in the root's focus on deliberate determination, whether of purpose or timing. This highlights how intention and understanding the reasons behind actions are essential in guiding human behavior.",
  "77": "أَجْلِبْ and related words stem from the root ج-ل-ب, with the root verb جَلَبَ meaning \"he drove, brought, conveyed, transported, or brought forth,\" \"he gained or earned,\" or \"it assembled or became collected together.\" أَجْلِبْ means \"mobilize\" or \"gather,\" emphasizing assembling or rallying resources, forces, or efforts for a specific purpose. The root conveys themes of movement, collection, and acquisition, reflecting purposeful actions that unify elements. أَجْلِبْ connects to these meanings by illustrating the process of gathering with intent, whether material, people, or efforts, to achieve a goal.",
  "78": "أَجْمَعُونَ and related words stem from the root ج-م-ع, with the root verb جَمَعَ meaning \"he gathered\" or \"he collected.\" The form أَجْمَعَ adds the nuance of \"he put together\" or \"he resolved,\" while أَجْمَعُونَ means \"all together\" or \"collectively,\" indicating the complete inclusion of all individuals or parts in unity. The root conveys the concept of bringing together dispersed elements into a cohesive whole, often with deliberation and purpose. The connection lies in the transition from the physical act of gathering to a state of wholeness and totality, symbolizing unanimity and collective action characterized by cohesion and shared intent.",
  "79": "أَجْمَعُوا and related words stem from the root ج-م-ع, with the root verb جَمَعَ meaning \"he gathered\" or \"he collected.\" أَجْمَعَ means \"he put together\" or \"he resolved,\" while أَجْمَعُوا specifically means \"they resolved\" or \"they agreed unanimously,\" highlighting a deliberate and purposeful gathering of thoughts, intentions, or decisions. The root conveys broader meanings of bringing together, uniting, and harmonizing, whether physically, intellectually, or emotionally. The connection lies in the transition from the physical act of gathering or collecting to the intentional act of unifying minds or decisions, reflecting the root’s overarching themes of unity, coherence, and shared purpose in achieving resolution.",
  "80": "أَحَاطَ and related words stem from the root ح-و-ط, with the root verb حَاطَ meaning \"he surrounded or encompassed,\" \"he protected,\" or \"he comprehended or had full knowledge.\" أَحَاطَ means \"He encompassed or surrounded completely,\" \"He protected it fully,\" or \"He comprehended it fully.\" The root conveys themes of encircling, guarding, or fully encompassing, signifying control and awareness. In the Qur'an, أَحَاطَ often describes Allah's (ﷻ) all-encompassing knowledge and power, illustrating His absolute authority and the inescapability of His knowledge and will.",
  "81": "أَحَبَّ and related words stem from the root ح-ب-ب, with the root verb حَبَّ meaning \"he was loved.\" أَحَبَّ means \"he loved,\" expressing an active and direct form of affection or preference. The root broadly conveys meanings of love, attraction, and desirability. Unlike حَبَّ, which primarily denotes becoming an object of love, أَحَبَّ is a more common and intensified form used to describe deliberate love or attachment. This highlights the distinction between passive endearment and active affection, emphasizing the depth of emotional connection inherent in the root.",
  "82": "أَحَدٌ and related words stem from the root أ-ح-د, with the root verb وَحَّدَ meaning \"he made one,\" \"he unified,\" or \"he declared the oneness (of God).\" The root also conveys the concept of uniqueness, indivisibility, and exclusivity, emphasizing the absence of likeness or equality. أَحَدٌ means \"one,\" \"someone,\" or \"anyone,\" and is especially significant in expressing Allah’s (ﷻ) uniqueness. ٱلْأَحَدُ is one of Allah’s (ﷻ) perfect names, meaning \"The One and Only\" or \"The Indivisible,\" signifying Allah (ﷻ) as absolutely unique, without division, partner, or equal. This highlights Allah’s (ﷻ) incomparable essence and the ultimate reality of His singularity in existence, attributes, and divinity.",
  "83": "أَحَسَّ and related words stem from the root ح-س-س, with the root verb حَسَّ meaning \"he was tender or compassionate.\" أَحَسَّ means \"he perceived\" or \"he sensed,\" indicating a deliberate or intensified act of becoming aware, often through heightened sensory or emotional attention. While حَسَّ conveys emotional sensitivity and tenderness, أَحَسَّ extends this idea to emphasize active perception or detection. This connection aligns with the root’s broader themes of feeling, awareness, and sensitivity, encompassing both emotional depth and deliberate recognition.",
  "84": "أَحَقُّ and related words stem from the root ح-ق-ق, with the root verb حَقَّ meaning \"it was true,\" \"it became established,\" or \"it was necessitated.\" أَحَقُّ is the comparative form meaning \"more deserving\" or \"most rightful.\" The connection lies in determining the greater legitimacy or priority of a claim, emphasizing the degree to which something is established as necessary, just, or rightful. This term reinforces the root’s essence of truth, obligation, and certainty, highlighting the rightful precedence of one matter over another.",
  "85": "أَحَلَّ and related words stem from the root ح-ل-ل, with the root verb حَلَّ meaning \"he untied,\" \"he loosened.\" أَحَلَّ means \"he made lawful\" or \"he permitted.\" The root dimensions encompass untying, resolving, and loosening, emphasizing the removal of restrictions. The connection lies in lifting constraints to transition from prohibition to permissibility, reflecting the granting of freedom or allowance within defined boundaries.",
  "86": "أَحِبَّاءُ and related words stem from the root ح-ب-ب, with the root verb حَبَّ meaning \"he was loved,\" and أَحَبَّ meaning \"he loved.\" حَبِيبٌ means \"beloved,\" and أَحِبَّاءُ means \"beloved ones\" or \"friends,\" signifying those held dear due to mutual affection and closeness. The root conveys themes of deep attachment, endearment, and desirability. It is also linked to حَبٌّ (grain or seed), symbolizing something small but essential, reflecting how love and close bonds nourish and sustain relationships. The connection emphasizes the foundational and nurturing nature of love and companionship, portraying relationships built on care, trust, and mutual affection.",
  "87": "أَحْبَارٌ and related words stem from the root ح-ب-ر, with the root verb حَبَرَ meaning \"he beautified or adorned\" or \"he embellished it or made it clear,\" especially handwriting, language, speech, and recitation. It also means \"he made [him] happy\" or \"he granted ease and plenty,\" extending to treating with honor. أَحْبَارٌ means \"scholars\" or \"scribes,\" referring to those who write, record, and preserve knowledge. Scholars not only preserve and transmit knowledge but beautify it through eloquence and clarity, making it impactful. Just as the root signifies joy and honor, Allah (ﷻ) grants ease and distinction to those who seek, teach, and share knowledge, elevating them in status and reward.",
  "88": "أَحْبَبْتَ and related words stem from the root ح-ب-ب, with the root verb حَبَّ meaning \"he was loved,\" and أَحَبَّ meaning \"he loved.\" أَحْبَبْتَ means \"you loved,\" referring to the act of expressing or feeling deep affection or attachment. The root conveys themes of endearment, desirability, and nurturing connections. It is also associated with حَبٌّ (grain or seed), symbolizing something essential and life-sustaining, reflecting how love grows and strengthens bonds. The connection lies in the idea of love as foundational and vital, emphasizing the personal act of forming strong and meaningful relationships.",
  "89": "أَحْبَطَ and related words stem from the root ح-ب-ط, with the root verb حَبِطَ meaning \"it became void.\" أَحْبَطَ means \"he nullified,\" referring to the act of making something ineffective or worthless. The root conveys meanings of becoming void, nullifying, or rendering ineffective. The connection lies in negating the value of an action, emphasizing the consequences of insincerity or wrongdoing that render good deeds void.",
  "90": "اِحْتَنَكَ and related words stem from the root ح-ن-كَ, with the root verb حَنَكَ meaning \"he became experienced or wise, through knowledge and understanding.\" اِحْتَنَكَ means \"he seized completely,\" or \"he gained mastery over,\" referring to overpowering something or someone and controlling and subduing entirely. This conveys a process of deliberate learning—gaining insight, observing, and understanding the target—until one becomes skilled enough to dominate completely. In the Qur'an, this term is used by Satan to express his intent to mislead humanity, emphasizing the real danger of deception and the necessity of safeguarding oneself through the remembrance of Allah (ﷻ).",
  "91": "أَحْرَصُ and related words stem from the root ح-ر-ص, with the root verb حَرَصَ meaning \"he desired vehemently, eagerly, or greedily\" or \"he strove with great effort to attain something.\" أَحْرَصُ means \"more eager\" or \"most covetous,\" referring to an intensified level of desire, longing, or striving. The connection lies in the root’s emphasis on persistent pursuit and excessive attachment, whether in seeking wealth, status, or any object of strong desire. Just as حَرَصَ conveys relentless effort, أَحْرَصُ signifies an even greater degree of eagerness or obsession in attaining what one seeks.",
  "92": "أَحْسَنُ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he became beautiful.\" أَحْسَنُ means \"better\" or \"best,\" and it is often used to compare or highlight the highest degree of goodness or beauty. The root conveys themes of goodness, beauty, and excellence, whether in character, action, or appearance. The connection lies in the root's emphasis on surpassing in goodness or beauty, which reflects striving for perfection. This term encourages aiming for the highest moral and ethical standards, aligning with the ideal of excelling in all aspects of life.",
  "93": "أَحْسَنَ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he became beautiful.\" أَحْسَنَ means \"he did good\" or \"he improved.\" The root conveys themes of goodness, beauty, and excellence, whether in character, action, or appearance. The connection is in the act of enhancing or excelling, reflecting the root's emphasis on goodness and beauty. This term encourages striving for excellence and goodness in actions, aligning with the ethical teachings of Islam.",
  "94": "أَحْصَنَتْ and related words stem from the root ح-ص-ن, with the root verb حَصُنَ meaning \"it was fortified,\" and حَصَّنَ meaning \"he fortified,\" \"he protected,\" or \"he made inaccessible.\" أَحْصَنَتْ means \"she safeguarded,\" reflecting the act of fortifying oneself against moral or physical transgression, directly relating to the root's emphasis on protection and fortification. The term embodies the virtue of purity and the strength to safeguard oneself from corruption, highlighting the moral fortitude required to remain untainted.",
  "95": "أَحْصَىٰ and related words stem from the root ح-ص-ى, with the verb حَصَى meaning \"he counted\" or \"he gathered small things (like pebbles).\" أَحْصَىٰ is a more intensive form, meaning \"he counted comprehensively,\" \"he recorded in full detail,\" or \"he precisely enumerated.\" The connection lies in the transition from simple counting to meticulous and exhaustive accounting, reflecting the root’s emphasis on precision and completeness. This term conveys absolute accuracy and careful record-keeping. ٱلْمُحْصِي, one of Allah’s (ﷻ) perfect names, means \"The Keeper of All Counts,\" signifying His infinite knowledge and ability to account for every action and creation, leaving nothing overlooked.",
  "96": "أَحْضَرَتْ and related words stem from the root ح-ض-ر, with the root verb حَضَرَ meaning \"he was present,\" \"he attended,\" or \"he came.\" أَحْضَرَتْ means \"she brought\" or \"it presented.\" This reflects the action of making something present or bringing it forth, directly connecting to the root's essence of presence and attendance. The term signifies the act of presenting or introducing something into a particular context or situation.",
  "97": "أَحْقَابٌ and related words stem from the root ح-ق-ب, with the root verb حَقِبَ meaning \"it was withheld,\" \"it became impeded,\" or \"it ceased or was delayed.\" أَحْقَابٌ is the plural of حُقْبٌ, meaning \"long periods,\" \"spans of time,\" or \"extended durations.\" The connection lies in the idea of time continuing while something remains withheld, obstructed, or delayed, reflecting cycles of prolonged phases. This term often refers to lengthy but finite durations, particularly in discussions about the afterlife or distant future matters, emphasizing periods that may feel indefinite but ultimately have an end.",
  "98": "أَحْقَافٌ and related words stem from the root ح-ق-ف, with the root verb حَقَفَ meaning \"it curved,\" or \"it bent.\" أَحْقَافٌ (plural of حِقْفٌ) means \"sand dunes\" or \"curved sand hills.\" This reflects the natural formations of the desert landscape, directly connecting to the root's emphasis on curvature and bending. الأَحْقَافُ refers to the area in which the people of 'Ad lived, characterized by rolling sand dunes and curved tracts of land.",
  "99": "أَحْكَمُ and related words stem from the root ح-ك-م, with the root verb حَكَمَ meaning \"he judged\" or \"he governed.\" أَحْكَمُ means \"most just\" or \"most perfect,\" reflecting the root's emphasis on exercising authority with fairness and ensuring stability and correctness. The root also conveys meanings of restraining, making firm, or establishing something with precision and authority. This term highlights the ultimate form of judgment and governance, where justice and perfection are upheld flawlessly, tying back to the root's focus on precision, restraint, and the balance inherent in sound judgment.",
  "100": "أَحْمَالٌ and related words stem from the root ح-م-ل, with the root verb حَمَلَ meaning \"he carried\" or \"he bore.\" أَحْمَالٌ (plural of حِمْلٌ) means \"loads\" or \"burdens\" and can also extend to \"pregnancies.\" The connection lies in the fundamental idea of bearing weight, whether physical, emotional, or symbolic. This includes carrying objects, responsibilities, or even life itself in the case of pregnancy. The root reflects effort, endurance, and responsibility, highlighting the essential role of carrying and sustaining in both literal and figurative senses.",
  "101": "أَحْمَدُ and related words stem from the root ح-م-د, with the root verb حَمِدَ meaning \"he praised\" or \"he thanked.\" أَحْمَدُ means \"most praiseworthy\" or \"more commendable.\" The connection lies in the elevated form of the root, signifying someone deserving the highest level of praise. In Islamic tradition, أَحْمَدُ is one of the names of Prophet Muhammad (ﷺ), highlighting his exemplary character that earns immense praise from Allah (ﷻ) and humanity. This name encapsulates the profound qualities that make him a continuous source of admiration and gratitude.",
  "102": "أَحْوَىٰ and related words stem from the root ح-و-ي, with the root verb حَوَىٰ meaning \"he collected, brought, or gathered together,\" or \"it became contracted or wasted away,\" referring to a state of being curved and compressed or withered. أَحْوَىٰ means \"dark\" or \"blackened,\" often used to describe something scorched or charred. The root conveys themes of contraction, withering, and containment. This reflects how something can shrink, dry up, or darken over time, emphasizing a transformation linked to depletion, compression, or the effects of burning.",
  "103": "أَحْيَا and related words stem from the root ح-ي-ي, with the root verb حَيِيَ meaning \"he lived\" or \"he was alive,\" reflecting the state of existence and vitality, and حَيَّا meaning \"he greeted,\" symbolizing the wish for life and well-being. أَحْيَا translates as \"He gave life\" or \"He revived,\" embodying the act of granting or restoring life. The connection lies in transitioning from the state of being alive (حَيِيَ) to the transformative act of bestowing life. This term highlights Allah’s (ﷻ) unparalleled ability to renew existence, whether through creation, revival, or spiritual awakening, emphasizing His power, mercy, and role as the ultimate source of vitality.",
  "104": "أَخٌ and related words stem from the root أ-خ-و, with the root verb آخَى meaning \"he took as a brother\" or \"he fraternized,\" describing the formation of a brotherly bond. أَخٌ means \"brother,\" referring to a male sibling or a close associate bound by kinship or shared beliefs. The root emphasizes unity and mutual support through familial or communal ties. In Islamic teachings, the term extends to the broader sense of brotherhood among believers, highlighting solidarity, compassion, and the duty to support one another in faith and actions.",
  "105": "أَخَذَ and related words stem from the root أ-خ-ذ, and as the root verb, it means \"he took,\" \"seized,\" \"grasped,\" or \"received.\" أَخَذَ embodies the action of taking possession, whether physically or metaphorically. The connection lies in the act of grasping, signifying control, acceptance, or acquisition. أَخَذَ can relate to accepting guidance, embracing responsibilities, or being held accountable. It highlights the significance of one's choices in taking or refraining from actions that have consequences for oneself and others.",
  "106": "أَخَّرَ and related words stem from the root أ-خ-ر, and as the root verb, it means \"he delayed,\" \"he postponed,\" or \"he deferred,\" reflecting the act of putting something off or moving it back. The root also conveys deliberate control over timing and outcomes, emphasizing order and purpose. This idea of intentional control is reflected in Allah’s (ﷻ) perfect name ٱلْمُؤَخِّرُ, meaning \"The Delayer\" or \"The One Who Puts Back,\" highlighting His authority over time as He delays or withholds according to His wisdom. It reminds us to trust in Allah’s (ﷻ) timing and see delays as opportunities for growth, encouraging patience and reliance on His plan.",
  "107": "أَخْبَارٌ and related words stem from the root خ-ب-ر, with the root verb خَبَرَ meaning \"he knew or had knowledge of,\" and أَخْبَرَ meaning \"he informed.\" أَخْبَارٌ (plural of خَبَرٌ) means \"news,\" \"reports,\" or \"affairs.\" The root conveys the idea of knowing something deeply, acquiring information through testing or experience, and becoming skillful or well-informed. The connection lies in the transmission of knowledge—just as knowing requires awareness and understanding, أَخْبَارٌ represents the spread of information, whether through spoken reports or written records, reflecting the role of news in conveying events, facts, or affairs to others.",
  "108": "أَخْدانٌ and related words stem from the root خ-د-ن, with the root verb خَدَنَ meaning \"he befriended intimately.\" أَخْدانٌ (plural of خِدْنٌ) means \"secret companions\" or \"illicit lovers.\" The root conveys themes of companionship, intimacy, and close association. The connection lies in how أَخْدانٌ refers to relationships built on secrecy and exclusivity, aligning with the root’s meaning of deep companionship. Just as true companionship involves trust and closeness, this word specifically highlights hidden or private bonds, emphasizing the aspect of concealed intimacy.",
  "109": "أَخْذٌ and related words stem from the root أ-خ-ذ, with the root verb أَخَذَ meaning \"he took,\" \"seized,\" or \"grasped.\" أَخْذٌ refers to \"taking,\" \"seizing,\" or \"grasping.\" The connection lies in the act of taking or acquiring something, emphasizing its manner and implications. أَخْذٌ can describe the appropriation of material objects, acceptance of ideas, or assumption of responsibilities. In the Qur'an, it often conveys divine retribution or punishment that \"takes\" hold of those who transgress, highlighting themes of justice and accountability.",
  "110": "أَخْرَجَ and related words stem from the root خ-ر-ج, with the root verb خَرَجَ meaning \"he went out\" or \"he exited.\" أَخْرَجَ means \"he made him/it come out\" or \"he expelled.\" The root conveys themes of exiting, emerging, and bringing forth. The connection lies in how أَخْرَجَ transforms the act of going out into an external force—causing someone or something to leave, be expelled, or be brought into existence. Whether referring to physical removal, extraction, or production, the word emphasizes an intentional act of making something emerge from its place.",
  "111": "أَخْزَىٰ and related words stem from the root خ-ز-ي, with the root verb خَزِيَ meaning \"he was ashamed\" or \"he was disgraced.\" أَخْزَىٰ means \"he disgraced\" or \"he humiliated,\" referring to the act of causing shame, dishonor, or a loss of dignity to someone else. The root conveys the concepts of shame, disgrace, and humiliation. It pertains to states of being degraded, dishonored, or despised, as well as feelings of being ashamed or deeply embarrassed. The connection lies in the active role of imposing shame upon others, emphasizing both the personal and social consequences of disgrace. This reflects themes of accountability, as disgrace often follows wrongdoing or rebellion.",
  "112": "أَخْزَيْتَ and related words stem from the root خ-ز-ي, with the root verb خَزِيَ meaning \"he was ashamed\" or \"he was disgraced.\" أَخْزَيْتَ means \"you disgraced\" or \"you humiliated,\" referring to the act of actively causing shame or dishonor to someone else. The root encompasses broader dimensions of shame, humiliation, and the loss of dignity, often highlighting the consequences of one's actions. The connection emphasizes the deliberate nature of imposing disgrace, whether as a response to wrongdoing or as an act of divine retribution.",
  "113": "الْأَخْسَرُونَ and related words stem from the root خ-س-ر, with the root verb خَسِرَ meaning \"he lost.\" أَخْسَرَ means \"he suffered a worse loss,\" and الْأَخْسَرُونَ means \"the greatest losers,\" referring to those who experience the most severe loss or failure, especially in a moral or spiritual sense. The root conveys themes of loss, ruin, and error, encompassing deprivation, deception, and misguidance. This word emphasizes a loss far beyond material decline, signifying a failure that results in ultimate ruin, particularly in missing out on lasting success or neglecting one's responsibilities.",
  "114": "أَخْضَرُ and related words stem from the root خ-ض-ر, with the root verb اِخْضَرَّ meaning \"it became green\" or \"it was fresh or flourishing.\" أَخْضَرُ means \"green,\" directly referring to the color associated with life, freshness, and growth. In classical Arabic, green symbolizes vitality, prosperity, and abundance, reflecting the lushness of vegetation and the blessings of nature provided by Allah (ﷻ).",
  "115": "أَخْطَأَ and related words stem from the root خ-ط-أ, with the root verb خَطِئَ meaning \"he committed a mistake\" or \"he sinned.\" أَخْطَأَ conveys the act of missing the mark or deviating from what is correct, whether intentionally or unintentionally. The root broadly reflects themes of error, wrongdoing, and straying from the right path, emphasizing human fallibility and the need for reflection and correction. This connection highlights the importance of striving for what is right while acknowledging the potential for missteps.",
  "116": "أَخْفَى and related words stem from the root خ-ف-ي, with the root verb خَفِيَ meaning \"he or it was hidden or concealed\" or \"he or it became unapparent.\" أَخْفَى means \"he hid\" or \"more hidden.\" The root conveys concepts of concealment, subtlety, and obscurity, referring to things that are veiled from sight or understanding. The connection lies in the degrees of hiddenness—while something may already be concealed, making it more hidden suggests an intentional deepening of its obscurity. This highlights the idea that some truths, actions, or realities remain unseen not just by circumstance but through deliberate concealment or divine wisdom.",
  "117": "أَخْلَدَ and related words stem from the root خ-ل-د, with the root verb خَلَدَ meaning \"he remained or stayed permanently\" or \"he became lasting or eternal.\" أَخْلَدَ means \"he caused to remain\" or \"he inclined towards.\" The root conveys permanence, eternity, and lasting existence, encompassing ideas of perpetual endurance and attachment. The connection lies in making something endure or clinging persistently, reflecting how one may become deeply attached to worldly desires. This serves as a caution against seeking permanence in what is temporary, reminding of the fleeting nature of worldly pursuits.",
  "118": "أَخْلَصُوا and related words stem from the root خ-ل-ص, with the root verb خَلَصَ meaning \"he became pure\" or \"he became safe or secure.\" أَخْلَصُوا means \"they purified\" or \"they made sincere,\" emphasizing the act of refining something to remove impurities or distractions. The root conveys concepts related to purity, clarity, and freedom from impurity or difficulty. It encompasses actions of purifying, refining, rescuing, and delivering from harm. The connection reflects the process of aligning intentions or actions to a pure and devoted purpose, free from ulterior motives or external influences, highlighting the importance of sincerity and purity in achieving true devotion.",
  "119": "أَخْلَفُوا and related words stem from the root خ-ل-ف, with the root verb خَلَفَ meaning \"he succeeded\" or \"he came after.\" This term means \"they broke (a promise),\" \"they failed to fulfill,\" or \"they replaced.\" It highlights the responsibilities of succession and continuity, emphasizing the impact of failing or altering commitments. أَخْلَفُوا reflects both the continuity of legacies and the potential for change, highlighting the importance of integrity in transitions.",
  "120": "أَداءٌ and related words stem from the root أ-د-ى, with the root verb أَدَّىٰ meaning \"he fulfilled,\" \"he performed,\" \"he delivered,\" or \"he paid.\" أَداءٌ signifies \"performance,\" \"fulfillment,\" or \"execution\" of a duty or obligation. The connection lies in faithfully carrying out a responsibility or conveying something to its rightful place, reflecting the root's essence of completion and trustworthiness. This term highlights the importance of integrity and reliability in fulfilling commitments, emphasizing the moral imperative to honor one's duties fully.",
  "121": "أَدْبَرَ and related words stem from the root د-ب-ر, with the root verb دَبَرَ meaning \"it came after or followed\" or \"he turned his back or went away.\" The root revolves around sequential occurrence, management, and decline, conveying the idea of things following one another, planning or administration, and retreat or deterioration over time. أَدْبَرَ means \"he turned away\" or \"he departed,\" reflecting the act of retreat or withdrawal. The connection to the root highlights both physical and metaphorical turning away—whether in movement, loss of position, or the fading of something once present, reinforcing themes of succession, planning, and decline.",
  "122": "The word أَدْرَكَ, related to the root درك, signifies the act of one thing overtaking another without interruption, reflecting how raindrops might closely follow one another without a gap, illustrating continuity and grasp without separation",
  "123": "أَدْرَىٰ and related words stem from the root د-ر-ي, with the root verb دَرَىٰ meaning \"he knew or was aware\" or \"he perceived or understood.\" أَدْرَىٰ means \"he informed\" or \"he made known,\" reflecting the act of transferring knowledge to others. The root conveys themes of awareness, understanding, and the dissemination of information, emphasizing clarity and comprehension in communication.",
  "124": "أَدْلَى and related words stem from the root د-ل-و, with the root verb دَلَا meaning \"he lowered, let down, or extended\" or \"he drew out, pulled up, or retrieved.\" أَدْلَى means \"he presented or put forward\" or \"he let down,\" emphasizing a deliberate and intentional action. The root revolves around lowering, extending, drawing up, leading, and persuading, conveying both physical actions (such as lowering a bucket to draw water) and metaphorical actions (such as presenting an argument, influencing, or enticing someone). Just as a bucket is lowered to retrieve what is hidden, this word reflects the act of offering or putting something forward with purpose, whether in speech, persuasion, or negotiation.",
  "125": "أَدْنَىٰ and related words stem from the root د-ن-و, with the root verb دَنَا meaning \"he or it drew near\" or \"he approached.\" أَدْنَىٰ means \"nearer\" or \"lower,\" reflecting the root’s emphasis on proximity or nearness. In the Qur'an, it conveys both physical and metaphorical meanings, including closeness in space, time, or relation, as well as lower status, value, or degree. The connection lies in the idea of comparative nearness or inferiority, capturing the dynamic interplay between proximity and rank. This term highlights contrasts between what is immediate or lesser and what is ultimate or higher, urging reflection on priorities and values.",
  "126": "أَدْهَىٰ and related words stem from the root د-ه-ي, with the root verb دَهِيَ meaning \"he was intelligent and cunning,\" and دَهَا meaning \"it befell.\" دَاهٍ means \"grievous,\" while أَدْهَىٰ means \"more grievous\" or \"more disastrous,\" emphasizing extreme misfortune or calamity. The root conveys both cunning intelligence and calamity, reflecting the dual nature of sharp-wittedness—capable of both strategic thinking and bringing about ruin. Just as intelligence can be used to navigate difficulties, it can also lead to dire consequences, making this word a powerful expression of overwhelming misfortune or an unparalleled disaster.",
  "127": "أَذَاعَ and related words stem from the root ذ-ي-ع, with the root verb ذَاعَ meaning \"it spread\" or \"it became public.\" أَذَاعَ means \"he broadcasted,\" \"he spread,\" or \"he made public.\" The connection lies in causing information to disseminate widely, reflecting the root's emphasis on spreading. This term highlights the power of communication and the impact of sharing information, whether beneficial or harmful, emphasizing the responsibility that comes with disseminating knowledge.",
  "128": "أَذاقَ and related words stem from the root ذ-و-ق, with the root verb ذَاقَ meaning \"he tasted.\" أَذاقَ means \"he made (someone) taste\" or \"he caused to taste.\" The connection lies in causing an experience or sensation to occur, reflecting the root's emphasis on tasting or experiencing. This term often implies making someone experience the consequences of their actions, whether reward or punishment, highlighting the principle of justice and the tangible outcomes of deeds.",
  "129": "أَذانٌ and related words stem from the root أ-ذ-ن, with the root verb أَذِنَ meaning \"he listened\" or \"he permitted.\" أَذانٌ means \"announcement,\" both generally and specifically the \"call to prayer.\" The connection lies in the act of proclaiming a message for others to hear, reflecting the root’s emphasis on listening and communication. In Islamic practice, it calls believers to prayer, serving as a reminder to worship and highlighting the importance of heeding spiritual calls.",
  "130": "أَذًى and related words stem from the root أ-ذ-ى, with the root verb أَذَى meaning \"he harmed,\" \"he injured,\" or \"it hurt.\" أَذًى means \"harm,\" \"injury,\" or \"annoyance.\" The root also encompasses broader meanings of causing slight discomfort, annoyance, or irritation, whether physical or emotional.  The connection lies in the manifestation of harm or discomfort conveyed by the root, whether through significant injury or minor irritations, highlighting the impact of actions or words that cause distress.",
  "131": "أَذِلَّةٌ and related words stem from the root ذ-ل-ل, with the root verb ذَلَّ meaning \"he was lowly, humbled, or became submissive.\" أَذِلَّةٌ is the plural of ذَلِيل, meaning \"humble ones\" or \"those who are subdued.\" Depending on the context, it can also convey being low in strength or numbers. The term reflects a collective state of humility or submission, emphasizing the root's focus on being subdued or tractable.",
  "132": "أَذِنَ and related words stem from the root أ-ذ-ن, and as the root verb, it means \"he listened,\" \"he heard,\" or \"he permitted.\" The connection between these meanings involves being receptive to sounds or requests and granting permission based on understanding, reflecting attentiveness and openness. This word embodies the dual concepts of receiving information and allowing actions, emphasizing the role of communication and consent in human interactions.",
  "133": "أَذَّنَ and related words stem from the root أ-ذ-ن, with the root verb أَذِنَ meaning \"he listened\" or \"he permitted.\" أَذَّنَ intensifies this to \"he proclaimed\" or \"he called out,\" especially in the context of \"calling to prayer.\" The connection lies in transforming listening into actively making others listen, emphasizing the responsibility of sharing important messages. آذَنَ also means \"he announced,\" but focuses more on formal declarations or granting permission. While أَذَّنَ is used for public or religious calls like the adhan, آذَنَ stresses formal notice or permission.",
  "134": "أَذْقَانٌ and related words stem from the root ذ-ق-ن, with the noun ذَقَنٌ meaning \"chin.\" أَذْقَانٌ means \"chins.\" The connection lies in the physical feature of the chin, which can symbolize humility when lowered or pride when raised. In the Qur'an, it is used to describe people who are humbled with their chins lowered, reflecting submission or contemplation.",
  "135": "أَذْهَبَ and related words stem from the root ذ-ه-ب, with the root verb ذَهَبَ meaning \"he went\" or \"he departed.\" أَذْهَبَ means \"he removed,\" \"he took away,\" or \"he caused to depart.\" The connection lies in causing something to go away or depart, extending the root's basic meaning of going. This term highlights the ability to eliminate or dispel something, often used in contexts of removing harm or difficulties, emphasizing the transformative power of action in changing circumstances.",
  "136": "أَرَائِكُ and related words stem from the root أ-ر-كَ, with the root verb أَرَكَ meaning \"he remained, continued, or abode in the place.\" أَرَائِكُ (plural of أَرِيكَةٌ) means \"raised couches, ornamentally furnished and decorated,\" placed in a tent, pavilion, chamber, or similar setting. The connection lies in the idea of abiding or remaining, indicating a sense of permanence and establishment, as these couches represent places where one settles comfortably. It refers to the luxurious, elevated couches upon which the successful will recline in Paradise, symbolizing comfort, dignity, and eternal reward.",
  "137": "أَرَادَ and related words stem from the root ر-و-د, with the root verb رَادَ meaning \"he desired\" or \"he sought.\" أَرَادَ means \"he intended\" or \"he willed.\" The connection lies in the purposeful act of seeking or desiring something, emphasizing intention, focus, and deliberate pursuit. The root reflects the concept of a conscious decision to pursue a goal or objective, highlighting not just the desire for something, but the active will and determination to achieve it. This term highlights the mental and volitional aspects of pursuing a specific aim, linking intention with action.",
  "138": "أَرَىٰ and related words stem from the root ر-أ-ي, with the root verb رَأَىٰ meaning \"he saw\" or \"he perceived.\" أَرَىٰ means \"he showed\" or \"he made someone see,\" extending the act of seeing to causing another to perceive, comprehend, or understand. The root encompasses broader meanings of sight, vision, perception, and insight, which can apply to both physical seeing and mental understanding. The connection highlights the act of guiding or enabling others to perceive a truth or reality, emphasizing themes of clarity, awareness, and enlightenment derived from facilitating sight or comprehension.",
  "139": "أَرْبَعٌ and related words stem from the root ر-ب-ع, with the root verb رَبَعَ meaning \"he became four\" or \"it became quadruple.\" أَرْبَعٌ refers to the number four in Arabic.",
  "140": "أَرْبَعَةٌ and related words stem from the root ر-ب-ع, with the root verb رَبَعَ meaning \"he became four\" or \"it became quadruple.\" أَرْبَعَةٌ refers to the number four in Arabic.",
  "141": "أَرْبَى and related words stem from the root ر-ب-و, with the root verb رَبَا meaning \"it increased\" or \"it grew.\" أَرْبَى means \"he increased\" or \"he caused to grow.\" The connection lies in the act of causing growth or augmentation, directly reflecting the root's emphasis on increase and expansion. This term often relates to financial contexts, highlighting themes of surplus and the ethical considerations of gain and interest.",
  "142": "أَرْجَاءُ and related words stem from the root ر-ج-و, with the root verb رَجَا meaning \"he hoped\" or \"he expected,\" and أَرْجَىٰ meaning \"he delayed\" or \"he postponed.\" The root conveys anticipation, expectation, and, at times, the idea of delay or distance. أَرْجَاءُ means \"regions\" or \"extremities,\" reflecting distant or far-reaching areas. The connection lies in the root's emphasis on extending, reaching, or delaying, symbolizing both the physical distance of far regions and the figurative distance of time or events yet to unfold. This term encompasses vast expanses, whether in space, time, or creation, highlighting the idea of something distant, expansive, and ungraspable, yet anticipated.",
  "143": "أَرْحَامٌ and related words stem from the root ر-ح-م, with the root verb رَحِمَ meaning \"he showed mercy\" or \"he had compassion.\" أَرْحَامٌ (plural of رَحِمٌ) means \"womb.\" The root conveys meanings of nurturing, tenderness, and connection, with the womb symbolizing the ultimate compassion a mother provides to her child. This term reflects familial ties and bonds of kinship, emphasizing the root’s essence of mercy in creating and sustaining human relationships. It highlights the interconnectedness of humanity through compassion and mutual care.",
  "144": "أَرْحَمُ and related words stem from the root ر-ح-م, with the root verb رَحِمَ meaning \"he showed mercy\" or \"he had compassion.\" أَرْحَمُ means \"more merciful\" or \"most merciful.\" The root conveys meanings of tenderness, care, and nurturing, often associated with the womb (رَحِم) as a symbol of profound connection and mercy. The connection emphasizes an elevated degree of mercy, highlighting unparalleled compassion and care inherent in the root. It reflects the ultimate mercy that surpasses all others, attributed to Allah (ﷻ) as the Most Merciful.",
  "145": "أَرْدَى and related words stem from the root ر-د-ي, with the root verb رَدِيَ meaning \"he perished\" or \"he fell into ruin.\" أَرْدَى means \"he caused to perish\" or \"he destroyed.\" The connection reflects the action of bringing about ruin or destruction, embodying the root's essence of perishing. It highlights the consequences of harmful actions and the gravity of causing others to fall into ruin.",
  "146": "أَرْذَلُ and related words stem from the root ر-ذ-ل, with the root verb رَذَلَ meaning \"he was base,\" \"he was ignoble,\" or \"he was lowly.\" أَرْذَلُ means \"most base\" or \"lowest.\" The connection emphasizes the extreme state of baseness or ignobility, reflecting the root's essence of lowness. In the Qur'an, it may refer to \"the most abject age,\" highlighting the frailty and weakness in old age or the lowest state of moral decline.",
  "147": "أَرْسَلَ and related words stem from the root ر-س-ل, with the root verb رَسَلَ meaning \"he sent.\" أَرْسَلَ means \"he sent forth\" or \"he dispatched.\" The connection emphasizes the act of sending or commissioning, reflecting the root's essence of sending. In the Islamic context, it often refers to Allah (ﷻ) sending prophets or messages, highlighting the divine communication with humanity.",
  "148": "أَرْسَى and related words stem from the root ر-س-و, with the root verb رَسَا meaning \"it was firm,\" \"it was fixed,\" or \"it was anchored.\" أَرْسَى means \"he made firm,\" \"he anchored,\" or \"he established.\" The connection reflects the act of making something stable or immovable, embodying the root's essence of firmness. In the Qur'an, it often refers to Allah (ﷻ) setting firm mountains or anchoring ships, highlighting His power in establishing stability.",
  "149": "أَرْضٌ and related words stem from the root أ-ر-ض, with the root verb أَرُضَ meaning \"he became low\" or \"he humbled himself.\" أَرْضٌ means \"earth\" or \"land.\" The connection lies in the earth being the lowest plane relative to the heavens, reflecting the root's emphasis on humility and groundedness. This term symbolizes the foundation of life and existence, reminding humans of their origins and the importance of humility before Allah (ﷻ). It encourages reflection on humanity's place in the universe and the transient nature of worldly life.",
  "150": "أَرْضَعَتْ and related words stem from the root ر-ض-ع, with the root verb رَضَعَ meaning \"he suckled\" or \"he nursed at the breast.\" أَرْضَعَتْ means \"she breastfed\" or \"she suckled.\" The connection lies in the act of providing nourishment and sustenance to an infant, embodying the root's emphasis on feeding and nurturing. This term highlights the essential bond between mother and child, reflecting the root's focus on the intimate act of nursing, which fosters growth and development.",
  "151": "أَرْكَسَ and related words stem from the root ر-ك-س, with the root verb رَكَسَ meaning \"he inverted\" or \"he turned upside down.\" أَرْكَسَ means \"He caused to relapse\" or \"He overturned.\" The connection lies in the action of reversing or reverting, directly relating to the root's meaning. In the Qur'an, it refers to Allah causing hypocrites to revert to their previous errors due to their actions, emphasizing the consequences of one's deeds leading to regression.",
  "152": "أَزَاغَ and related words stem from the root ز-ي-غ, with the root verb زَاغَ meaning \"he deviated,\" \"he swerved,\" or \"he turned away.\" أَزَاغَ means \"He caused to deviate\" or \"He led astray,\" describing the act of influencing someone to veer away from the correct path. The root conveys themes of turning, misalignment, and straying from uprightness, emphasizing the vulnerability of the heart and mind to external and internal influences. أَزَاغَ highlights the importance of self-reflection, humility, and supplicating to Allah (ﷻ) for steadfastness, as even subtle deviations can lead to profound misguidance.",
  "153": "أَزَلَّ and related words stem from the root ز-ل-ل, with the root verb زَلَّ meaning \"he slipped\" or \"he erred.\" أَزَلَّ means \"he caused to slip\" or \"he led astray.\" The root also conveys meanings of faltering, stumbling, or losing stability, emphasizing both physical and metaphorical slips. The connection lies in the direct and deliberate act of causing another to make a mistake or fall into error, reflecting the root's focus on destabilization. This term highlights the intentional influence or manipulation that can lead others toward wrongdoing, highlighting the gravity of causing deviation.",
  "154": "أَزِفَت and related words stem from the root أ-ز-ف, with the root verb أَزِفَ meaning \"it drew near\" or \"it approached,\" emphasizing the concept of proximity or imminence. The root conveys themes of nearness, urgency, and rapid approach, often carrying a sense of anticipation or inevitability. أَزِفَت is the feminine form, used to describe the Day of Resurrection as hastening and rapidly approaching, reflecting its inescapable reality and closeness.",
  "155": "أَزٌّ and related words stem from the root أ-ز-ز, with the root verb أَزَّ meaning \"he incited\" or \"he urged,\" often involving forceful motion or noise. أَزٌّ refers to \"incitement,\" \"agitation,\" or \"whispering\" and is commonly used to describe actions that provoke or intensify a state of unrest. For example, \"أَزَّ القِدْرُ\" describes the sound of a boiling pot, while \"أَزَّ النَّارَ\" means \"to kindle a fire,\" illustrating how incitement often amplifies an already agitated state. Metaphorically, it reflects the act of stirring or intensifying inner turmoil, as seen in the way devils incite disbelievers, deepening their unrest.",
  "156": "أَزْرٌ and related words stem from the root أ-ز-ر, with the root verb أَزَرَ meaning \"it surrounded\" or \"it encompassed.\" The root conveys concepts of strength, support, fortification, and binding firmly. أَزْرٌ means \"strength,\" \"support,\" or \"reinforcement,\" reflecting the root’s essence of providing stability and assistance. The connection lies in the encompassing and surrounding nature of strength or support, which fortifies and reinforces individuals or syand related words stem. This term emphasizes the act of bolstering or strengthening, drawing from the root’s core meanings of uniting, securing, and building resilience.",
  "157": "أَزْكَى and related words stem from the root ز-ك-و, with the root verb زَكَا meaning \"he was pure,\" \"he grew,\" or \"he increased in goodness.\" The root also conveys meanings of flourishing, thriving, and becoming better or more refined. أَزْكَى means \"purer,\" \"more virtuous,\" or \"better.\" The connection lies in the concept of increasing in purity or righteousness, reflecting the root's emphasis on both moral purity and growth. It highlights the pursuit of higher ethical standards and spiritual refinement, tying the notions of personal development and moral excellence to the broader themes of the root.",
  "158": "أَزْلَامٌ and related words stem from the root ز-ل-م, associated with \"arrows\" or \"divination arrows.\" أَزْلَامٌ refers to \"arrows\" or \"sticks\" used in pre-Islamic Arabia for divination purposes, such as making decisions or seeking omens. The root conveys meanings of drawing lots, seeking omens, and reliance on arbitrary decisions. The connection lies in practices involving chance and seeking guidance through arbitrary means, reflecting the root's association with divination tools. The Qur'an prohibits the use of أَزْلَامٌ, emphasizing reliance on Allah's (ﷻ) guidance over superstition and reinforcing the importance of faith over baseless practices.",
  "159": "أَسَاءَ and related words stem from the root س-و-أ, with the root verb سَاءَ meaning \"it became bad,\" \"evil,\" or \"unpleasant.\" أَسَاءَ means \"he did evil\" or \"he acted badly,\" emphasizing deliberate wrongdoing. The root conveys themes of harm, unpleasantness, and moral corruption, encompassing actions, intentions, and outcomes that cause physical, emotional, or spiritual damage. It is associated with things that are disliked, burdensome, or bring regret, reflecting how evil actions lead to hardship and consequences for both the doer and others.",
  "160": "أَساطِيرُ and related words stem from the root س-ط-ر, with the root verb سَطَرَ meaning \"he wrote,\" \"he lined,\" or \"he set in order.\" أُسْطُورَةٌ means \"tale,\" \"story,\" or \"fable,\" and أَساطِيرُ is its plural form, meaning \"tales\" or \"legends.\" The connection lies in the concept of writing or recording stories, reflecting the root's emphasis on inscribing and arranging words. This term often refers to ancient stories or myths.",
  "161": "أَسَاوِرُ and related words stem from the root س-و-ر, with the root verb سَارَ meaning \"he enclosed\" or \"he surrounded.\" أَسَاوِرُ (plural of سِوَارٌ) means \"bracelets\" or \"bangles.\" The connection lies in the root's emphasis on enclosure, as bracelets encircle the wrist. This term reflects adornments symbolizing beauty and honor, associated with divine reward. The root's broader meanings of journeying and proceeding metaphorically connect to life's trials and ultimate rewards, where these adornments signify the culmination of faith and righteous actions.",
  "162": "أَسَرَّ and related words stem from the root س-ر-ر, with the root verb سَرَّ meaning \"he concealed\" or \"he kept secret.\" أَسَرَّ is the causative form, emphasizing the deliberate and intentional act of making something hidden. The nuance lies in سَرَّ describing a state or action of concealment, while أَسَرَّ focuses on actively causing or ensuring that something remains hidden. This reflects the root’s emphasis on secrecy, privacy, and the inner aspects that are not revealed openly, highlighting themes of intentional secrecy and discretion in action or thought.",
  "163": "أَسَفٌ and related words stem from the root أ-س-ف, with the root verb أَسِفَ meaning \"he was grieved,\" \"he regretted,\" or \"he was sorrowful.\" أَسَفٌ means \"grief,\" \"sorrow,\" or \"regret,\" embodying the depth of emotional pain conveyed by the root. The connection captures profound sadness or remorse, highlighting the human experience of suffering due to loss or wrongdoing.",
  "164": "أَسَلْنَا and related words stem from the root س-ي-ل, with the root verb سَالَ meaning \"it flowed,\" \"it ran,\" or \"it streamed.\" أَسَلْنَا means \"We caused to flow,\" referring to an action where a stream or flow is set into motion by an external force. The root conveys broader dimensions of movement, continuity, and fluidity, emphasizing the natural course or progression of things. أَسَلْنَا highlights the power to initiate or control this flow, often reflecting Allah's (ﷻ) ability to bring forth resources or facilitate processes. The term connects to the root’s essence of dynamic motion and purposeful direction, highlighting themes of divine provision and control over nature.",
  "165": "أَسِفٌ and related words stem from the root أ-س-ف, with the root verb أَسِفَ meaning \"he was grieved,\" \"he regretted,\" or \"he was sorrowful.\" أَسِفٌ means \"grieving,\" \"sorrowful,\" or \"regretful,\" depicting someone immersed in sorrow. The connection embodies the root's emotional depth, illustrating a person experiencing profound grief or regret. Describing someone as أَسِفٌ highlights their state of ongoing emotional distress, often due to personal loss or remorse over actions.",
  "166": "أَسِيرٌ and related words stem from the root أ-س-ر,with the root verb أَسَرَ meaning \"he bound,\" \"he braced,\" or \"he tied,\" indicating restraint or securing something firmly. أَسِيرٌ means \"prisoner\" or \"captive,\" often in the context of warfare or conflict. The connection lies in the state of being bound or confined, reflecting the root's focus on capture and restraint. In the Qur'an, the term emphasizes the importance of compassion and generosity towards the vulnerable, including captives, highlighting the value of extending mercy beyond social or enemy lines.",
  "167": "أَسَّسَ and related words stem from the root أ-س-س, and as the root verb, it means \"he founded,\" \"he established,\" or \"he laid a foundation,\" indicating the act of creating a strong basis. This word emphasizes the importance of solid beginnings for enduring structures, foundations, or principles. In the Qur'an, it highlights the significance of establishing firm foundations, whether in physical construction, community building, or moral conduct, highlighting the need for strength and integrity in what is initiated.",
  "168": "أَسْبَغَ and related words stem from the root س-ب-غ, with the root verb سَبَغَ meaning \"he was ample\" or \"he was complete.\" أَسْبَغَ means \"He bestowed abundantly\" or \"He completed fully.\" The connection lies in providing generously or fully, embodying the root's concept of abundance. أَسْبَغَ emphasizes Allah’s (ﷻ) grace in bestowing ample blessings and favors upon His creation.",
  "169": "أَسْتَخْلِصْ and related words stem from the root خ-ل-ص, with the root verb خَلَصَ meaning \"he was pure\" or \"he became sincere.\" أَسْتَخْلِصْ means \"I will take purely for myself\" or \"I will choose exclusively.\" The root conveys purity, sincerity, and exclusivity. The connection lies in the act of setting something apart, making it free from impurities or external influences. This reflects the idea of selecting with purpose, emphasizing distinction, sincerity, and the absence of anything mixed or shared.",
  "170": "أَسْخَطَ and related words stem from the root س خ ط, with the verb سَخِطَ meaning 'he was displeased,' 'he was angry,' or 'he disapproved.' The verb أَسْخَطَ means 'he caused displeasure,' 'he incited anger,' or 'he provoked disapproval.' It indicates that an individual’s actions provoke severe disapproval or wrath, particularly from Allah (ﷻ). The usage of أَسْخَطَ serves as a serious reminder to be mindful of one's actions and words, constantly renew one's intentions, and strive for behavior that brings about Allah's (ﷻ) pleasure and approval.",
  "171": "أَسْرٌ and related words stem from the root أ-س-ر, with the root verb أَسَرَ meaning \"he bound,\" \"he braced,\" or \"he tied,\" indicating restraint or securing something firmly. أَسْرٌ refers to the \"strength of make or form,\" emphasizing how something is made firm and solid in structure. The connection to the root lies in the idea that, just as binding makes something firm and stable, humans have been made firmly bound in form and fashioned in the best manner, with precision and strength. This root also reflects that humans are bound and subject to Allah’s (ﷻ) will—in their creation, form, and fate.",
  "172": "أَسْرَعُ and related words stem from the root س-ر-ع, with the root verb سَرُعَ meaning \"he was quick\" or \"he hastened.\" أَسْرَعُ means \"swifter,\" \"more swift,\" or \"most swift.\" It emphasizes a higher degree of speed and urgency in actions or tendencies. The root conveys themes of swiftness and promptness, highlighting urgency and the importance of acting or responding quickly.",
  "173": "أَسْرَفَ and related words stem from the root س-ر-ف, with the root verb سَرَفَ meaning \"he exceeded,\" \"he was extravagant,\" or \"he transgressed limits.\" أَسْرَفَ means \"he committed excess,\" \"he acted extravagantly,\" or \"he was immoderate.\" The root also conveys themes of neglect and turning away from guidance, emphasizing how excess often involves overlooking boundaries and losing balance. Beyond material extravagance, it symbolizes moral and spiritual deviation, where indulgence disrupts harmony and leads to wastefulness.",
  "174": "أَسْرَىٰ and related words stem from the root س-ر-ى, with the root verb سَرَى meaning \"he travelled by night.\" أَسْرَىٰ means \"he took (someone) on a night journey\" or \"he made to travel by night.\" The connection lies in the causative aspect of this form, emphasizing the act of causing someone to journey at night. In the Qur'an, it refers to Allah (ﷻ) taking the Prophet Muhammad (ﷺ) on the Night Journey, highlighting themes of divine guidance.",
  "175": "أَسْفَارٌ and related words stem from the root س-ف-ر, with the root verb سَفَرَ meaning \"he traveled\" or \"he journeyed.\" سِفْرٌ (with a kasrah under the س) means \"book\" or \"scripture,\" and أَسْفَارٌ is its plural, meaning \"books\" or \"scriptures.\" The connection lies in the idea of unveiling or revealing knowledge, just as travel unveils new places. The root also carries the meaning of \"to uncover,\" relating to the revelation of wisdom through writings. This term underscores the importance of scriptures as sources of guidance, unveiling divine wisdom to humanity.",
  "176": "أَسْفَرَ and related words stem from the root س-ف-ر, with the root verb سَفَرَ meaning \"he traveled\" or \"he unveiled.\" أَسْفَرَ means \"he made bright,\" \"he illuminated,\" or \"he revealed.\" The connection lies in the act of unveiling or disclosing something, directly relating to the root's emphasis on uncovering. This term highlights the transition from darkness to light, both physically and metaphorically, symbolizing enlightenment and the revelation of truth that dispels ignorance.",
  "177": "أَسْفَلُ and related words stem from the root س-ف-ل, with the root verb سَفَلَ meaning \"he was low\" or \"he was beneath.\" أَسْفَلُ means \"the lowest\" or \"the bottommost.\" The connection lies in denoting the lowest degree or position, directly relating to the root's emphasis on lowness. In the Qur'anic context, it may refer to the lowest depths of Hell or the most degraded moral state, emphasizing the severe consequences of persistent wrongdoing and disobedience.",
  "178": "أَسْقَىٰ and related words stem from the root س-ق-ي, with the root verb سَقَىٰ meaning \"he gave to drink\" or \"he watered.\" أَسْقَىٰ means \"he provided drink\" or \"he irrigated.\" The connection lies in the act of supplying water, directly relating to the root's emphasis on quenching thirst. This term highlights the importance of providing sustenance and life through water, symbolizing generosity, care, and the nurturing aspects of creation.",
  "179": "أَسْكَنَ and related words stem from the root س-ك-ن, with the root verb سَكَنَ meaning \"he dwelt,\" \"he resided,\" or \"he became still or tranquil.\" أَسْكَنَ means \"he caused to dwell\" or \"he settled someone,\" reflecting the causative aspect of providing residence or tranquility to others. The connection lies in the act of instilling stillness or establishing a place of rest, directly relating to the root's emphasis on habitation and peace.",
  "180": "أَسْلَمَ and related words stem from the root س-ل-م, with the root verb سَلِمَ meaning \"he was safe,\" \"he was sound,\" or \"he was unharmed.\" أَسْلَمَ means \"he submitted,\" \"he surrendered,\" or \"he entered into peace.\" The connection lies in surrendering oneself to achieve safety and peace, reflecting the root's emphasis on soundness and well-being. In an Islamic context, it signifies submitting to the will of Allah (ﷻ), embracing faith to attain spiritual harmony. This highlights the transformative journey towards inner tranquility through submission.",
  "181": "أَسْلِحَةٌ and related words stem from the root س-ل-ح, with the basic noun سِلَاحٌ meaning \"weapon.\" أَسْلِحَةٌ means \"weapons.\" The connection lies in the tools used for defense or warfare, directly relating to the root's concept of arming oneself. It highlights the importance of preparedness and the means by which individuals or groups protect themselves, reflecting themes of strength, conflict, or security in various contexts.",
  "182": "أَسْمَعَ and related words stem from the root س-م-ع, with the root verb سَمِعَ meaning \"he heard\" or \"he listened.\" أَسْمَعَ means \"he made someone hear\" or \"he caused to hear.\" The connection lies in facilitating the act of hearing for another, extending the root's meaning from personal perception to enabling others to perceive. This emphasizes the importance of conveying messages and ensuring they reach the intended audience, highlighting active communication and the spread of knowledge.",
  "183": "أَسْوَأَ and related words stem from the root س-و-أ, with the root verb سَاءَ meaning \"it became bad,\" \"evil,\" or \"unpleasant.\" أَسْوَأَ means \"worse,\" \"worst,\" or \"most evil,\" denoting the extreme degree of badness or unpleasantness. The root conveys themes of harm, corruption, and regret, emphasizing the severity of evil outcomes and their impact. أَسْوَأَ highlights the ultimate consequences of actions that reach the furthest depths of wrongdoing, serving as a stark reminder of the moral responsibility to avoid such extremes.",
  "184": "أَسْوَدُ and related words stem from the root س-و-د, with the root verb سَوِدَ meaning \"he became black\" or \"it turned dark,\" and سَادَ meaning \"he became a leader\" or \"he attained sovereignty.\" أَسْوَدُ means \"black,\" describing the darkest color, symbolizing depth, intensity, and prominence. The root conveys both physical blackness and abstract notions of dignity and leadership. It also includes سَوَّدَ, meaning \"he blackened,\" often used metaphorically to denote sorrow or disgrace, highlighting the root's depth and versatility.",
  "185": "أَشَارَتْ and related words stem from the root ش-و-ر, with the root verb شَارَ meaning \"he pointed out\" or \"he indicated.\" أَشَارَتْ means \"she pointed\" or \"she indicated.\" The connection lies in the root's concept of directing attention or providing guidance. أَشَارَتْ emphasizes the act of signaling or making something known to others, highlighting the importance of non-verbal communication and guidance in human interactions.",
  "186": "أَشَدُّ and related words stem from the root ش-د-د, with the root verb شَدَّ meaning \"he tightened\" or \"he strengthened.\" أَشَدُّ means \"stronger\" or \"most severe,\" indicating a higher degree of strength or intensity. The connection lies in the root's emphasis on tightening and reinforcing, reflecting increased power or severity compared to others.",
  "187": "أَشَقُّ and related words stem from the root ش-ق-ق, with the root verb شَقَّ meaning \"he split,\" \"he cleft,\" or \"he made something difficult.\" أَشَقُّ means \"more difficult\" or \"most difficult.\" The connection lies in the root's concept of splitting or causing hardship, metaphorically extending to the idea of difficulty or toil. It embodies the notion of something being exceptionally arduous or challenging, emphasizing the intensity of hardship.",
  "188": "أَشُدٌّ and related words stem from the root ش-د-د, with the root verb شَدَّ meaning \"he tightened\" or \"he strengthened.\" أَشُدٌّ refers to \"full strength\" or \"maturity,\" indicating when a person reaches peak physical and intellectual development. The connection lies in the root's emphasis on strength and firmness, reflecting a state of complete development and vigor.",
  "189": "أَشِرٌ and related words stem from the root أ-ش-ر, with the root verb أَشَرَ meaning \"he divided a piece of wood\" or \"he sharpened teeth.\" أَشِرَ means \"he was insolent\" or \"he was exultant,\" describing arrogant, rude, and disrespectful behavior. أَشِرٌ refers to someone who is arrogant or boastful. Just as jagged wood or serrated teeth cut and tear, an arrogant person’s behavior harms social harmony, emotionally and mentally wounding others. Their pride acts as a divisive force, creating friction, hostility, and damaging relationships, ultimately alienating individuals within communities.",
  "190": "أَشْتاتٌ and related words stem from the root ش-ت-ت, with the root verb شَتَّ meaning \"it was scattered\" or \"it dispersed.\" أَشْتاتٌ means \"scattered groups\" or \"fragments,\" indicating things divided and spread out. The connection lies in the root's emphasis on dispersion and separation, reflecting how entities once united can become scattered into various parts.",
  "191": "أَشْرَاطٌ and related words stem from the root ش-ر-ط, with the root verb شَرَطَ meaning \"he marked\" or \"he stipulated.\" أَشْرَاطٌ refers to \"signs\" or \"conditions,\" particularly significant indicators or stipulations. The connection lies in the root's focus on marking or setting conditions, reflecting how signs serve as indicators of forthcoming events, such as the signs heralding the Day of Judgment.",
  "192": "أَشْرَقَتْ and related words stem from the root ش-ر-ق, with the root verb شَرَقَ meaning \"it rose\" or \"it shone.\" أَشْرَقَتْ means \"it shone brightly\" or \"it illuminated,\" emphasizing the act of shining or illuminating. The connection lies in the root's focus on the rising sun and spreading of light, symbolizing enlightenment and the dispelling of darkness.",
  "193": "أَشْرَكَ and related words stem from the root ش-ر-ك, with the root verb شَرَكَ meaning \"he shared\" or \"he participated.\" أَشْرَكَ means \"he associated partners,\" specifically referring to the act of polytheism or attributing partners to Allah (ﷻ). The root conveys themes of sharing and partnership, which in this context reflect associating others in something that should remain exclusive to Allah's (ﷻ) divine nature. The connection lies in the misuse of the concept of partnership, where what is meant to be singular and unique—Allah's (ﷻ) lordship and worship—is falsely divided.",
  "194": "أَشْفَقَ and related words stem from the root ش-ف-ق, with the root verb شَفِقَ meaning \"he was compassionate\" or \"he feared.\" أَشْفَقَ means \"he feared for\" or \"he showed concern.\" The connection lies in a deep, compassionate fear for someone's well-being, reflecting the root's concept of tender concern mixed with apprehension. It emphasizes proactive care and empathy.",
  "195": "أَشْقَىٰ and related words stem from the root ش-ق-و, with the root verb شَقِيَ meaning \"he was unfortunate,\" \"he was wretched,\" or \"he suffered hardship.\" أَشْقَىٰ means \"more wretched\" or \"most wretched.\" The connection lies in the root's concept of misery and hardship, emphasizing an increased level of misfortune. It denotes the pinnacle of suffering, highlighting the extreme state of being deeply afflicted or unfortunate.",
  "196": "أَشْكُو and related words stem from the root ش-ك-و, with the root verb شَكَا meaning \"he complained\" or \"he lamented.\" أَشْكُو means \"I complain\" or \"I lament.\" The connection lies in the root's concept of expressing grievance or distress. By saying أَشْكُو, one is articulating their suffering or hardship, seeking relief or empathy. It reflects the human tendency to share burdens and seek solace through expressing difficulties.",
  "197": "أَشْهَدَ and related words stem from the root ش-ه-د, with the root verb شَهِدَ meaning \"he witnessed.\" أَشْهَدَ means \"he caused to witness\" or \"he bore witness.\" The connection lies in the root's concept of witnessing. أَشْهَدَ emphasizes the act of bearing witness or making a declaration of testimony. In the Islamic context, it is associated with the declaration of faith (Shahada), affirming the oneness of Allah (ﷻ) and the prophethood of Prophet Muhammad (ﷺ).",
  "198": "أَصابَ and related words stem from the root ص-و-ب, with the root verb صَابَ meaning \"he aimed at\" or \"he hit the mark.\" أَصابَ means \"he afflicted,\" \"he struck,\" or \"he attained.\" The connection lies in the idea of something precisely reaching its target, whether it's an arrow hitting a mark or an event befalling someone. This term emphasizes accuracy and inevitability, reflecting how occurrences are decreed and reach individuals with precision, aligning with the root's concept of hitting the intended point.",
  "199": "أَصَابِعُ and related words stem from the root ص-ب-ع, with the basic noun إِصْبَعٌ meaning \"finger.\" أَصَابِعُ means \"fingers.\" The connection lies in the root's association with digits used for grasping and manipulation. أَصَابِعُ are essential tools for interaction with the physical world. In the Qur'an, fingers are sometimes used metaphorically to illustrate actions or reactions, emphasizing the root's focus on their functional significance.",
  "200": "أَصَرُّوا and related words stem from the root ص-ر-ر, with the root verb صَرَّ meaning \"he bound,\" or \"he tied.\" أَصَرُّوا means \"they persisted\" or \"they continued obstinately.\" The connection lies in the idea of binding or holding firm, symbolizing a refusal to release or change one's stance. This term emphasizes unwavering determination, particularly in the context of stubbornly maintaining a course of action or belief despite opposition or consequences.",
  "201": "أَصَمَّ and related words stem from the root ص-م-م, with the root verb صَمَّ meaning \"he was deaf\" or \"he was hard.\" أَصَمَّ means \"he made deaf\" or \"he caused to be deaf.\" The connection lies in the action of rendering someone incapable of hearing, either physically or metaphorically. It emphasizes the root’s focus on creating a barrier to sound or perception, symbolizing intentional or involuntary deafness. In a broader context, it reflects a state of being shut off from understanding or rejecting guidance, emphasizing the severity of the obstruction in perception or response.",
  "202": "أَصَمَّ and related words stem from the root ص-م-م, with the root verb صَمَّ meaning \"he was deaf.\" أَصَمَّ means \"he made deaf\" or \"he rendered someone unable to hear.\" The connection lies in causing deafness, reflecting the root's emphasis on blockage. In the Qur'an, it can refer to the sealing of hearts and ears of disbelievers, emphasizing the spiritual state of being unresponsive to guidance due to persistent rejection.",
  "203": "أَصِيلٌ and related words stem from the root أ-ص-ل, with the root verb أَصِلَ meaning \"it became firmly rooted, established, or strong\" or \"he was sound of judgment.\" أَصِيلٌ refers to the evening, specifically from 'Asr prayer to sunset. The connection lies in this being the foundational part of the day, symbolizing grounding and reflection. Just as أَصِلَ implies being firmly rooted, أَصِيلٌ represents a time to deepen one’s connection with Allah (ﷻ). During this period, Allah (ﷻ) calls for His remembrance, grounding the believer and bringing peace, preparing them to enter the night with sound judgment.",
  "204": "أَصْبَحَ and related words stem from the root ص-ب-ح, with the root verb صَبَحَ meaning \"he entered the morning.\" أَصْبَحَ means \"he became\" or \"he entered upon the morning.\" The connection lies in the transition to a new state, much like night turns into day. أَصْبَحَ signifies a change or transformation in condition. It reflects the root's concept of renewal and the beginning of something new, paralleling the fresh start each morning brings.",
  "205": "أَصْبُ and related words stem from the root ص-ب-و, with the root verb صَبَا meaning \"he inclined,\" \"he yearned,\" or \"he was attracted.\" أَصْبُ means \"I incline,\" \"I desire,\" or \"I yearn.\" The connection lies in expressing personal inclination or attraction toward something, reflecting the root's emphasis on longing and youthful desires. It highlights the inner pull one feels towards objects of affection or interest.",
  "206": "أَصْحَابٌ and related words stem from the root ص-ح-ب, with the root verb صَحِبَ meaning \"he accompanied,\" \"he befriended,\" or \"he associated with.\" أَصْحَابٌ means \"companions,\" \"friends,\" or \"associates.\" The connection lies in the shared experiences and close relationships inherent in companionship. In the Qur'an, أَصْحَابٌ often refers to groups linked by common beliefs or fates, such as \"أَصْحَابُ الْجَنَّةِ\" (companions of Paradise) or \"أَصْحَابُ النَّارِ\" (companions of the Fire), emphasizing how one's associations influence their ultimate destiny.",
  "207": "أَصْدَقُ and related words stem from the root ص-د-ق, with the root verb صَدَقَ meaning \"he spoke the truth\" or \"he was sincere.\" أَصْدَقُ means \"more truthful\" or \"most truthful.\" The connection lies in the root's emphasis on truthfulness and sincerity. أَصْدَقُ highlights the highest degree of honesty or accuracy. In the Qur'an, it highlights that Allah (ﷻ) is the most truthful in speech and promise, reinforcing the absolute reliability of divine words over any human assertion.",
  "208": "أَصْغَرُ and related words stem from the root ص-غ-ر, with the root verb صَغُرَ meaning \"he was small\" or \"he was insignificant.\" أَصْغَرُ means \"smaller\" or \"smallest.\" The connection lies in relative size or significance, indicating something that is lesser in comparison to others. This term emphasizes the idea of something being reduced in size, importance, or rank, highlighting a state of being smaller or more minor in relation to other things.",
  "209": "أَصْفَادٌ and related words stem from the root ص-ف-د, with the root verb صَفَدَ meaning \"he shackled\" or \"he bound.\" أَصْفَادٌ means \"shackles\" or \"fetters.\" The connection lies in the physical restraints used to bind someone, reflecting the root's focus on confinement and restriction. This term conveys the idea of something that binds or holds back, symbolizing control or limitation. The word emphasizes the act of restraining, either physically or metaphorically, highlighting the severity of being bound or restricted.",
  "210": "أَصْفَىٰ and related words stem from the root ص-ف-و, with the root verb صَفَا meaning \"it was pure\" or \"it was clear.\" أَصْفَىٰ means \"he chose\" or \"he selected exclusively.\" The connection lies in selecting something pure or refined, embodying the root's emphasis on purity and clarity. In the Qur'an, it signifies Allah (ﷻ) choosing prophets or granting special favors to certain individuals, highlighting the concept of divine selection based on purity of heart and purpose.",
  "211": "أَصْلٌ and related words stem from the root أ-ص-ل, with the root verb أَصِلَ meaning \"it became firmly rooted, established, or strong,\" \"he was sound of judgment,\" or \"it was honorable.\" أَصْلٌ refers to the lowest part of something, or its \"root.\" The connection lies in the idea of firmness and foundation—just as a root anchors a tree, أَصْلٌ represents the essential base or origin. This reflects the root's emphasis on being grounded, both physically, as a root secures a tree, and metaphorically, as sound judgment or a strong foundation supports one's character and actions.",
  "212": "أَصْلَحَ and related words stem from the root ص-ل-ح, with the root verb صَلَحَ meaning \"he was righteous\" or \"he was good.\" أَصْلَحَ means \"he reformed,\" \"he set right,\" or \"he improved.\" The connection lies in the act of making something good or correcting faults, embodying the root's focus on righteousness and rectification. In the Qur'an, it encourages believers to reform themselves and their communities, emphasizing proactive efforts to promote goodness, justice, and harmony in society.",
  "213": "أَصْنامٌ and related words stem from the root ص-ن-م, with the basic noun صَنَمٌ meaning \"an idol\" or \"a graven image.\" The connection lies in the act of shaping a lifeless figure that stands erect, symbolizing something fashioned and elevated yet devoid of life. This term underscores the futility of worshipping inanimate objects, emphasizing their inability to perceive or respond, thus highlighting the contrast between the Creator and the created idols.",
  "214": "أَصْوَافٌ and related words stem from the root ص-و-ف, meaning \"wool,\" the material derived from sheep. Historically, صُوفٌ symbolized simplicity and humility, as it was the choice of devotees known as صُوفِيَّة (Sufis), who wore woolen garments to reject worldly luxuries. These individuals were deeply devoted to Allah (ﷻ) and adhered strictly to the proper Sunnah of the Prophet Muhammad (ﷺ). Sheep, the source of wool, embody submission and reliance, reminding us of our dependence on Allah (ﷻ) for guidance and provision. The connection lies in wool's natural qualities, reflecting a life of humility, simplicity, and devotion.",
  "215": "أَضَاعُوا and related words stem from the root ض-ي-ع, with the root verb ضَاعَ meaning \"he was lost\" or \"he perished.\" أَضَاعَ means \"he caused to lose\" or \"he wasted,\" and أَضَاعُوا means \"they wasted\" or \"they neglected.\" The connection lies in the act of causing loss or neglect, directly relating to the root's emphasis on perishing or going astray. This term highlights the deliberate squandering or neglect of something valuable.",
  "216": "أَضَلُّ and related words stem from the root ض-ل-ل, with the root verb ضَلَّ meaning \"he went astray.\" أَضَلُّ means \"most astray\" or \"most misguided.\" The connection lies in intensifying the root's concept of error, highlighting the furthest deviation from guidance. This term serves as a stark warning against straying from the righteous path, emphasizing the severe consequences of veering away from truth and the importance of staying aligned with the right guidance.",
  "217": "أَضَلَّ and related words stem from the root ض-ل-ل, with the root verb ضَلَّ meaning \"he went astray.\" أَضَلَّ means \"he led astray\" or \"he misled.\" The connection lies in shifting from personal misguidance to causing others to err, reflecting the root's concept in a causative form. This term highlights the gravity of misleading others, emphasizing the moral responsibility to convey truth and avoid causing others to deviate from the correct path.",
  "218": "أَضْحَكَ and related words stem from the root ض-ح-ك, with the root verb ضَحِكَ meaning \"he laughed.\" أَضْحَكَ means \"he made [someone] laugh\" or \"he caused laughter.\" The connection lies in the act of inducing joy or amusement in others. This term highlights the ability to bring happiness and light-heartedness, reflecting the root's emphasis on laughter and its positive effects on the human spirit.",
  "219": "أَضْعَفُ and related words stem from the root ض-ع-ف, with the root verb ضَعُفَ meaning \"he became weak\" or \"he weakened.\" أَضْعَفُ means \"weaker\" or \"weakest,\" indicating a comparative degree of weakness. The root conveys themes of physical, emotional, or structural frailty, emphasizing human limitations and varying levels of strength. This word highlights the contrast between strength and weakness, serving as a reminder of the natural disparities in ability and the need for humility and compassion toward those who are less capable.",
  "220": "أَضْغَانٌ and related words stem from the root ض-غ-ن, with the root verb ضَغَنَ meaning \"he concealed malice.\" أَضْغَانٌ means \"grudges\" or \"hidden animosities.\" The connection lies in the root's focus on concealed ill will, highlighting the destructive nature of harboring malice. This term warns against internalizing hatred, which can corrode relationships and communities.",
  "221": "أَطَاعَ and related words stem from the root ط-و-ع, with the root verb طَاعَ meaning \"he obeyed\" or \"he complied willingly.\" أَطَاعَ means \"he obeyed\" or \"he complied.\" This word embodies the act of willing obedience or submission. The connection to the root emphasizes the voluntary nature of compliance, highlighting the importance of choosing to follow guidance. In a spiritual context, it highlights the value of willingly obeying Allah's (ﷻ) commandments as an expression of faith.",
  "222": "أَطْعَمَ and related words stem from the root ط-ع-م, with the root verb طَعِمَ meaning \"he tasted\" or \"he ate.\" أَطْعَمَ means \"he fed\" or \"he provided food.\" The connection lies in the act of giving nourishment for consumption, directly relating to the root's emphasis on taste and sustenance. This term highlights the act of feeding others, emphasizing generosity and care. In a moral context, it emphasizes the virtue of providing sustenance to those in need, reflecting compassion and charity.",
  "223": "أَطْغَىٰ and related words stem from the root ط-غ-ى, with the root verb طَغَىٰ meaning \"he exceeded bounds,\" \"he was insolent,\" or \"he overflowed.\" أَطْغَىٰ means \"to be more extreme in exceeding bounds\" or \"more excessive in rebellion.\" The broader root meanings convey the concept of overflowing or exceeding proper bounds, whether in rebellion, arrogance, or behavior. This highlights the destructive consequences of immoderation and excessiveness, emphasizing the harm caused by surpassing rightful limits.",
  "224": "أَطْغَيْتُ and related words stem from the root ط-غ-ى, with the root verb طَغَىٰ meaning \"he exceeded bounds,\" \"he was insolent,\" or \"he overflowed.\" أَطْغَيْتُ translates to \"I caused [him] to exceed bounds\" or \"I led [him] to excessive behavior,\" emphasizing the act of inciting or inducing someone to surpass proper limits. This reflects the root's concept of excessive behavior and transgression, highlighting the role of one who encourages or provokes another to act arrogantly or unjustly, pushing them beyond what is permissible.",
  "225": "أَطْفَأَ and related words stem from the root ط-ف-أ, with the root verb طَفَأَ meaning \"it was extinguished\" or \"it went out.\" أَطْفَأَ means \"he extinguished\" or \"he put out,\" emphasizing the act of causing a flame or light to cease. The connection lies in actively bringing something to an end, reflecting the root's concept of extinguishment. This term illustrates the ability to nullify or suppress, akin to extinguishing a fire or dimming a source of illumination.",
  "226": "أَطْهَرُ and related words stem from the root ط-ه-ر, with the root verb طَهَرَ meaning \"he was or became clean, pure, or free from impurities.\" أَطْهَرُ means \"more pure\" or \"cleaner,\" intensifying the concept of purity. This connects to the root's emphasis on being free from physical or spiritual impurities. It highlights the pursuit of greater purity in actions and intentions, encouraging continual self-improvement in faith.",
  "227": "أَطْوَارٌ and related words stem from the root ط-و-ر, with the root verb طَارَ meaning \"he moved around\" or \"he changed.\" أَطْوَارٌ is the plural of طَوْرٌ, meaning \"stages\" or \"phases.\" It refers to different states or periods in a process. The connection lies in the idea of progression and transformation, directly relating to the root's concept of movement and change. This term highlights the varying stages of development, whether in creation or human life, emphasizing the dynamic nature of existence as ordained by Allah (ﷻ).",
  "228": "أَظْفَرَ and related words stem from the root ظ-ف-ر, with the root verb ظَفِرَ meaning \"he acquired,\" or \"he attained what he desired.\" أَظْفَرَ means \"he granted victory\" or \"he made someone victorious.\" The connection lies in the act of helping someone achieve success or triumph, reflecting the root's concept of acquiring or attaining victory. This term emphasizes the power to bestow success, highlighting the role of the one who enables another's achievement.",
  "229": "أَظْلَمُ and related words stem from the root ظ-ل-م, with the root verb ظَلَمَ meaning \"he wronged\" or \"he acted unjustly.\" أَظْلَمُ means \"more unjust\" or \"more oppressive.\" The connection emphasizes an increase in the level of injustice or wrongdoing, highlighting a greater degree of oppression or unfairness. This term reflects the comparative form of the root, underlining a heightened sense of moral or ethical darkness.",
  "230": "أَظْلَمَ and related words stem from the root ظ-ل-م, with the root verb ظَلَمَ meaning \"he wronged\" or \"he acted unjustly.\" أَظْلَمَ means \"he darkens\" or \"he makes something darker.\" The connection reflects the root's concept of causing a state of darkness, both in a literal and metaphorical sense. This term emphasizes the act of obscuring or making something unclear, which can be extended to moral or ethical darkness, symbolizing further oppression or wrongdoing.",
  "231": "أَظْهَرَ and related words stem from the root ظ-ه-ر, with the root verb ظَهَرَ meaning \"he appeared\" or \"he became manifest.\" أَظْهَرَ means \"he revealed\" or \"he made apparent.\" The connection lies in bringing something hidden into view, reflecting the root's concept of emergence. This term emphasizes the act of disclosure or making something known, highlighting themes of clarity and enlightenment.",
  "232": "أَعَانَ and related words stem from the root ع-و-ن, with the root verb عَانَ meaning \"he helped,\" \"he assisted,\" or \"he supported.\" أَعَانَ involves one-sided aid or direct support, often provided without expectation of return. The root encompasses broader ideas of offering help, facilitating tasks, and providing strength or relief. These distinctions reflect the multifaceted nature of assistance, whether through general help, collaborative effort, or selfless intervention, emphasizing the importance of balance and the ultimate reliance on Allah (ﷻ) as the perfect source of aid.",
  "233": "أَعَدَّ and related words stem from the root ع-د-د, with the root verb عَدَّ meaning \"he counted\" or \"he enumerated.\" أَعَدَّ means \"he prepared\" or \"he made ready.\" The connection lies in the idea that preparation involves careful counting and consideration of all necessary elements, directly relating to the root's emphasis on enumeration. This term highlights the importance of meticulous planning and readiness, suggesting that just as one counts items to ensure nothing is missing, one must also prepare thoroughly in life's endeavors, particularly in fulfilling divine obligations.",
  "234": "أَعَزُّ and related words stem from the root ع-ز-ز, with the root verb عَزَّ meaning \"he was mighty,\" \"he was strong,\" or \"he was powerful.\" أَعَزُّ means \"more powerful,\" or \"mightier,\" or \"more honourable.\" The nuance here is a comparative or highest degree, emphasizing a higher level of might or honor. This connects to the root's concept of strength and honor, highlighting the superior status or power of someone or something in comparison to others, and often denotes utmost respect or authority.",
  "235": "أَعِيبَ and related words stem from the root ع-ي-ب, with the root verb عَابَ meaning \"it was defective,\" \"it was faulty,\" or \"he was blameworthy.\" أَعِيبَ means \"I make defective\" or \"I cause a flaw,\" describing the deliberate act of introducing a fault or imperfection into something. The connection lies in the root's emphasis on imperfection and fault, reflecting the intentional action of creating or assigning a defect. This term highlights the themes of purposeful alteration or criticism, illustrating how actions can render something imperfect, whether for a specific intent or through deliberate fault-finding.",
  "236": "أَعْتَدَتْ and related words stem from the root ع-ت-د, with the root verb عَتَدَ meaning \"he prepared\" or \"he made ready.\" أَعْتَدَ means \"he prepared,\" and أَعْتَدَتْ means \"she prepared.\" The connection lies in the act of making preparations, reflecting the root's concept of readiness. It emphasizes proactive effort in arranging or equipping for future needs.",
  "237": "أَعْثَرَ and related words stem from the root ع-ث-ر, with the root verb عَثَرَ meaning \"he stumbled\" or \"he discovered by chance.\" أَعْثَرَ means \"he caused to find\" or \"he revealed.\" The connection shifts from accidental discovery to intentional revelation, reflecting the root's concept of encountering something unexpectedly transformed into deliberate unveiling.",
  "238": "أَعْجازٌ and related words stem from the root ع-ج-ز, with the root verb عَجَزَ meaning \"he was weak\" or \"he failed.\" أَعْجازٌ is the plural of عَجُزٌ, meaning \"trunks\" or \"lower parts.\" The connection lies in the concept of the lower or hinder part, perhaps implying less strength. In the Qur'anic context, it refers to trunks of palm trees, symbolizing strength that has been uprooted, relating back to the root's theme of weakness or incapacity.",
  "239": "أَعْجَبَ and related words stem from the root ع-ج-ب, with the root verb عَجِبَ meaning \"he was amazed\" or \"he wondered.\" أَعْجَبَ means \"he amazed\" or \"he pleased.\" The connection shifts from experiencing amazement to causing amazement in others, reflecting the root's concept of wonder. It emphasizes the impact of something remarkable or extraordinary that evokes admiration or surprise, highlighting the ability to captivate and impress.",
  "240": "أَعْجَلَ and related words stem from the root ع-ج-ل, with the root verb عَجِلَ meaning \"he was hasty\" or \"he hurried.\" أَعْجَلَ means \"he hastened (someone)\" or \"he caused to hurry.\" The connection shifts from personal haste to causing others to be hasty, reflecting the root's concept of speed and urgency applied externally. It emphasizes prompting others into swift action.",
  "241": "أَعْجَمِينَ and related words stem from the root ع-ج-م, with the root verb عَجَمَ meaning \"he was unclear in speech\" or \"he spoke indistinctly.\" أَعْجَمِينَ means \"non-Arabs\" or \"those who do not speak Arabic fluently.\" The connection lies in the notion of unclear or indistinct speech, reflecting the root's emphasis on inarticulateness. This term highlights the distinction between Arabic speakers and others, emphasizing the uniqueness and clarity of the Arabic language in conveying the divine message.",
  "242": "أَعْجَمِيٌّ and related words stem from the root ع-ج-م, with the root verb عَجَمَ meaning \"he was unclear in speech\" or \"he spoke indistinctly.\" أَعْجَمِيٌّ means \"foreign\" or \"non-Arab,\" specifically referring to someone who is not an Arabic speaker. The connection lies in the concept of speech that is not easily understood or lacks the eloquence of Arabic, reflecting the root's emphasis on inarticulateness. This term highlights the contrast between the eloquent Arabic of the Qur'an and other languages, highlighting the importance of linguistic clarity in conveying profound truths.",
  "243": "أَعْرابٌ and related words stem from the root ع-ر-ب, with the root verb عَرَبَ meaning \"he was eloquent\" or \"he expressed clearly.\" أَعْرابٌ refers to the Bedouins or nomadic Arabs. The connection lies in the distinctive linguistic and cultural characteristics of the Bedouins, who are considered the original Arabs with pure eloquence and unadulterated language, directly relating to the root's emphasis on clarity and expressiveness in speech. This term highlights the cultural significance of eloquence and the preservation of linguistic purity among the nomadic tribes.",
  "244": "أَعْرَافٌ and related words stem from the root ع-ر-ف, with the root verb عَرَفَ meaning \"he knew\" or \"he recognized.\" أَعْرَافٌ means \"heights,\" \"elevations,\" or \"partitions,\" and in the Qur'anic context, it refers to the Heights between Paradise and Hell where certain individuals will stand on the Day of Judgment. The connection lies in the concept of recognition and awareness, as those on the Heights will recognize the inhabitants of both Paradise and Hell by their distinguishing features, reflecting the root’s emphasis on knowing and perceiving. This term highlights the moral importance of awareness, understanding, and the consequences of actions in determining one’s ultimate fate.",
  "245": "أَعْرَجُ and related words stem from the root ع-ر-ج, with the root verb عَرَجَ meaning \"he ascended,\" \"he went up,\" or \"he climbed,\" and عَرِجَ meaning \"he limped\" or \"he was lame.\" أَعْرَجُ means \"lame\" or \"one who limps.\" The connection lies in the concept of movement, whether ascending with effort or being hindered by a physical impairment. This reflects the root's emphasis on motion and ascent, highlighting the parallel between striving upward and the challenges of movement when impeded.",
  "246": "أَعْرَضَ and related words stem from the root ع-ر-ض, with the root verb عَرَضَ meaning \"he presented,\" \"he offered,\" or \"he displayed.\" أَعْرَضَ means \"he turned away,\" \"he avoided,\" or \"he shunned,\" indicating a deliberate act of distancing oneself or turning away from something. The connection lies in the shift from presenting or facing something to intentionally refraining from engagement or interaction, reflecting the root's theme of direction and orientation. This term emphasizes conscious avoidance, whether in a physical, emotional, or moral context.",
  "247": "أَعْطَىٰ and related words stem from the root ع-ط-و, with the root verb عَطَا meaning \"he gave generously\" or \"he bestowed abundantly.\" أَعْطَىٰ means \"he gave\" or \"he granted,\" emphasizing an intentional and generous act of transferring something to another. The root reflects themes of generosity, provision, and abundance, highlighting the significance of giving as an act of kindness and selflessness. This term emphasizes the noble virtue of generosity, fostering compassion and benevolence in human interactions.",
  "248": "أَعْظَمُ and related words stem from the root ع-ظ-م, with the root verb عَظُمَ meaning \"he was great,\" \"he became mighty,\" or \"he was magnificent.\" أَعْظَمُ is the elative form meaning \"greater\" or \"greatest.\" The connection lies in the concept of greatness or magnitude, reflecting the root's emphasis on grandeur and significance. This term is used to compare and highlight the superiority or excellence of something or someone in terms of greatness.",
  "249": "أَعْقَبَ and related words stem from the root ع-ق-ب, with the root verb عَقِبَ meaning \"he followed\" or \"he came after.\" أَعْقَبَ means \"he caused to follow,\" \"he brought forth in succession,\" or \"he imposed as a consequence.\" It can also signify \"to penalize\" or \"to punish,\" highlighting the deliberate act of causing a result or consequence to follow an action. This reflects the root's themes of continuity, succession, and the outcomes of prior deeds, whether in bringing about sequential events or imposing retribution. The term highlights the interconnectedness of actions and their consequences.",
  "250": "أَعْلامٌ and related words stem from the root ع-ل-م, with the root verb عَلِمَ meaning \"he knew,\" \"he became aware,\" or \"he understood,\" and عَلَّمَ meaning \"he taught\" or \"he caused to know.\" أَعْلامٌ, while commonly meaning \"signs\" or \"landmarks,\" also refers to \"mountains,\" highlighting their role as prominent markers in the landscape. The connection lies in mountains serving as natural indicators or guides, aiding navigation and recognition, particularly in the context of travel or geography. This meaning aligns with the root’s emphasis on knowledge and awareness through observable features, with mountains symbolizing grandeur, stability, and the clarity of discernible signs in creation.",
  "251": "أَعْلَمُ and related words stem from the root ع-ل-م, with the root verb عَلِمَ meaning \"he knew,\" \"he became aware,\" or \"he understood,\" and عَلَّمَ meaning \"he taught\" or \"he caused to know.\" أَعْلَمُ means \"knows best\" or \"most knowing,\" signifying a heightened level of awareness or understanding, often used to emphasize that one has greater or complete knowledge in a specific context. This word aligns with the root's focus on knowledge and comprehension, emphasizing the perfection or supremacy of understanding, particularly in relation to Allah (ﷻ), where it highlights His absolute and unparalleled knowledge of all things, both apparent and concealed.",
  "252": "أَعْلَنَ and related words stem from the root ع-ل-ن, with the root verb عَلَنَ meaning \"it became manifest\" or \"it became known.\" أَعْلَنَ means \"he announced\" or \"he made public.\" The connection is in causing something to be known openly, reflecting the root's concept of making information apparent and emphasizing transparency and disclosure.",
  "253": "أَعْلَوْنَ and related words stem from the root ع-ل-و, with the root verb عَلا meaning \"he rose\" or \"he ascended.\" أَعْلَىٰ means \"higher\" or \"highest,\" and أَعْلَوْنَ is the plural form meaning \"those who are higher\" or \"the superior ones.\" The connection is in elevation and superiority, reflecting the root's concept of height and exaltation, indicating those who hold higher status or rank.",
  "254": "أَعْمَىٰ and related words stem from the root ع-م-ي, with the root verb عَمِيَ meaning \"he became blind\" or \"he was unable to see.\" أَعْمَىٰ means \"blind.\" The connection lies in the absence of sight, both physical and spiritual, reflecting the root's emphasis on lack of vision. In a metaphorical sense, it denotes those who are unable or unwilling to perceive truth and guidance, highlighting the consequences of turning away from enlightenment and understanding.",
  "255": "أَعْنَتَ and related words stem from the root ع-ن-ت, with the root verb عَنَتَ meaning \"he suffered hardship\" or \"he was distressed.\" أَعْنَتَ means \"he caused hardship\" or \"he imposed distress,\" bringing someone into a state that is difficult or hard to bear. The connection lies in actively creating difficulty, directly reflecting the root's focus on hardship and its consequences.",
  "256": "أَغْطَشَ and related words stem from the root غ-ط-ش, with the root verb غَطَشَ meaning \"it became dark\" or \"it was obscure.\" أَغْطَشَ means \"He made it dark\" or \"He covered with darkness.\" The connection lies in causing darkness or obscurity, directly relating to the root's meaning. This term highlights the divine act of bringing about night, emphasizing Allah's (ﷻ) power over creation and the cycles of day and night.",
  "257": "أَغْفَلَ and related words stem from the root غ-ف-ل, with the root verb غَفَلَ meaning \"he was heedless,\" \"negligent,\" or \"unmindful.\" أَغْفَلَ means \"he caused to be heedless\" or \"he made negligent,\" emphasizing the act of leading someone into a state of unawareness or neglect. This reflects the root's theme of heedlessness and its broader implications of inattention and the consequences of such a state.",
  "258": "أَغْنَتْ and related words stem from the root غ-ن-ي, with the root verb غَنِيَ meaning \"he was rich,\" \"self-sufficient,\" or \"free from want.\" أَغْنَتْ means \"it enriched,\" \"it sufficed,\" or \"she availed.\" This form indicates causing enrichment or sufficiency for someone else. The connection lies in extending the root's concept of wealth to the act of providing for others, emphasizing generosity or the effectiveness of something in fulfilling needs. It highlights the impact of actions that render others content or free from want.",
  "259": "أَغْنَىٰ and related words stem from the root غ-ن-ي, with the root verb غَنِيَ meaning \"he was rich,\" \"self-sufficient,\" or \"free from want.\" أَغْنَىٰ means \"he enriched,\" \"he sufficed,\" or \"he availed.\" This form signifies causing someone to become rich or self-sufficient. The connection lies in the transition from personal wealth to enabling others, reflecting the root's emphasis on abundance. It highlights the role of generosity and the capacity of actions to meet needs and provide assistance.",
  "260": "أَغْوَيْتَ and related words stem from the root غ-و-ي, with the root verb غَوَىٰ meaning \"he went astray,\" \"he erred,\" or \"he was misled.\" أَغْوَيْتَ means \"you led astray\" or \"you caused to err,\" emphasizing the act of actively influencing or causing someone else to deviate from the correct path.",
  "261": "أَفَاءَ and related words stem from the root ف-ي-أ, with the root verb فَاءَ meaning \"he returned\" or \"he went back.\" أَفَاءَ means \"he restored\" or \"he caused to return.\" The connection lies in actively bringing something back to its original state, directly relating to the root's meaning of returning. It emphasizes restoration and the returning of rights or possessions, often used in the context of spoils of war returned to the community, highlighting justice and the re-establishment of balance.",
  "262": "أَفَاضَ and related words stem from the root ف-ي-ض, with the root verb فَاضَ meaning \"it overflowed\" or \"it poured forth.\" أَفَاضَ means \"he caused to overflow\" or \"he spread abundantly.\" The connection lies in actively causing an abundant flow, directly reflecting the root's idea of overflowing. In the context of Hajj, it describes pilgrims pouring forth from Arafat, symbolizing a vast multitude moving together like a flowing river, emphasizing unity and the overwhelming mercy and blessings from Allah (ﷻ).",
  "263": "أَفَاقَ and related words stem from the root ف-و-ق, with the root verb فَاقَ meaning \"he surpassed\" or \"he excelled.\" أَفَاقَ means \"he awoke\" or \"he regained consciousness,\" reflecting the action of rising above a state of unconsciousness or inactivity. The root conveys themes of elevation, superiority, or transcendence, which align with the notion of overcoming or moving beyond a prior state. أَفَاقَ highlights the act of reawakening or recovering clarity, symbolizing a return to awareness or the ability to act, rooted in the broader concepts of surpassing limitations or achieving a higher state.",
  "264": "أَفَلَ and related words stem from the root أ-ف-ل, and as the root verb, it means \"it was absent, hidden, or concealed.\" It is used to describe the setting or disappearance of celestial bodies like the sun, moon, or stars. The connection lies in the root’s emphasis on disappearance and transience. In the Qur'an, this concept is illustrated in the story of Prophet Abraham (ﷺ), who observes the setting of celestial bodies to demonstrate that only Allah (ﷻ), who is Everlasting, is worthy of worship.",
  "265": "أَفَّاكٌ and related words stem from the root أ-ف-ك, with the root verb أَفَكَ meaning \"he turned away,\" \"he lied,\" or \"he changed his/its manner of being.\" أَفَّاكٌ is an intensive form, meaning \"habitual liar\" or \"great deceiver,\" describing someone who frequently turns away from the truth and distorts it. This form intensifies the root’s concept of deviation, emphasizing the severity of persistent falsehood and misdirection. In the Qur'an, أَفَّاكٌ refers to those who continuously reject the truth and spread lies, serving as a warning against the moral degradation caused by habitual dishonesty.",
  "266": "أَفْرِغْ and related words stem from the root ف-ر-غ, with the root verb فَرَغَ meaning \"he emptied,\" \"he became free,\" or \"he finished.\" أَفْرَغَ means \"he poured out\" or \"he bestowed abundantly.\" أَفْرِغْ means \"pour out!\" or \"bestow abundantly!\" The connection lies in the act of emptying or pouring out fully, aligning with the root's concept of becoming void. This term often expresses a plea for generous bestowal, emphasizing a desire for complete fulfillment or support.",
  "267": "أَفْسَدُوا and related words stem from the root ف-س-د, with the root verb فَسَدَ meaning \"it became corrupt,\" \"it spoiled,\" or \"it deteriorated.\" أَفْسَدُوا means \"they caused corruption\" or \"they corrupted.\" The connection lies in actively spreading corruption or disorder, reflecting the root's emphasis on decay and spoilage. This term highlights the impact of actions that lead to moral or societal degradation, highlighting the responsibility to maintain harmony and integrity.",
  "268": "أَفْصَحَ and related words stem from the root ف-ص-ح, with the root verb فَصَحَ meaning \"he spoke clearly\" or \"he was eloquent,\" referring to an inherent ability to express oneself clearly. أَفْصَحَ means \"he made clear,\" \"he expressed eloquently,\" or \"he clarified,\" emphasizing the deliberate act of making something understandable. The root conveys themes of clarity, articulation, and eloquence. While فَصَحَ focuses on natural clarity in speech, أَفْصَحَ highlights intentional effort to articulate thoughts effectively. This distinction reflects the root’s emphasis on clear communication, whether as an inherent trait or purposeful action.",
  "269": "أَفْضَىٰ and related words stem from the root ف-ض-و, with the root verb فَضَا meaning \"it became spacious,\" \"it was empty or void,\" or \"it spread forth.\" أَفْضَىٰ means \"he reached to,\" \"he went in unto,\" or \"he communicated deeply,\" often referring to close contact or intimate relations. The root conveys themes of extending, spreading, and filling space, emphasizing the idea of reaching or arriving at something through proximity or direct connection. أَفْضَىٰ reflects the act of establishing closeness, whether physically, emotionally, or communicatively, highlighting a transition from separation to connection.",
  "270": "أَفْلَحَ and related words stem from the root ف-ل-ح, with the root verb فَلَحَ meaning \"he cleaved,\" \"he split,\" or \"he succeeded.\" أَفْلَحَ means \"he succeeded\" or \"he prospered.\" The connection lies in achieving success through effort, much like cleaving the earth to cultivate crops. This term emphasizes triumph and attainment of goals, often associated with spiritual success in the Qur'an, highlighting the ultimate prosperity of those who are righteous.",
  "271": "أَفْنَانٌ and related words stem from the root ف-ن-ن, with the root verb فَنَّ meaning \"it branched\" or \"it diversified.\" أَفْنَانٌ means \"branches\" or \"boughs,\" often symbolizing diversity and abundance. The connection lies in the spreading and branching out of trees, reflecting variety and richness. This term can represent the multitude of blessings or the diversity of creation, emphasizing the beauty and complexity of what Allah (ﷻ) has provided.",
  "272": "أَفْوَاهٌ and related words stem from the root ف-و-ه, with the root verb فَاهَ meaning \"he uttered\" or \"he pronounced.\" أَفْوَاهٌ means \"mouths.\" The root conveys themes of speech, articulation, and verbal expression, as the mouth is the primary means of communication.",
  "273": "أَقامَ and related words stem from the root ق-و-م, with the root verb قامَ meaning \"he stood\" or \"he rose.\" The root conveys concepts of standing upright, rising, establishing, maintaining, and ensuring stability. أَقامَ means \"he established,\" \"he made stand,\" or \"he set up,\" emphasizing the action of causing something to stand firmly or be upheld. The term reflects an active role in maintaining order, balance, and continuity, transforming individual uprightness into the act of supporting and sustaining others or systems. This embodies the root's essence of stability and alignment, highlighting the importance of upholding what is just, steadfast, and enduring.",
  "274": "أَقَاوِيلُ and related words stem from the root ق-و-ل, with the root verb قَالَ meaning \"he said\" or \"he spoke.\" أَقَاوِيلُ (plural of قَوْلٌ) means \"sayings\" or \"utterances,\" often implying false, exaggerated, or fabricated statements. The root conveys themes of communication, expression, and the power of words, with أَقَاوِيلُ specifically highlighting the multiplicity and, in certain contexts, the unreliability of such statements. This reflects the root’s dual focus on speech as a means of conveying both truth and misrepresentation.",
  "275": "أَقَلُّ and related words stem from the root ق-ل-ل, with the root verb قَلَّ meaning \"it decreased,\" \"it diminished,\" or \"it became little.\" أَقَلُّ means \"less\" or \"least.\" This connects to the root's concept of smallness or scarcity, emphasizing a reduced quantity or degree. It highlights comparison by denoting something as being lesser in amount or significance.",
  "276": "أَقَلَّتْ and related words stem from the root ق-ل-ل, with the root verb قَلَّ meaning \"it decreased\" or \"it became little.\" أَقَلَّتْ means \"it carried,\" or \"it lifted, and raised it from the ground.\" The connection lies in the act of lifting or carrying, which aligns with the root’s theme of reduction by removing or lightening a burden. This concept extends to physical elevation, as in carrying something upward, reflecting the broader notion of lessening or transferring weight.",
  "277": "أَقْبَرَ and related words stem from the root ق-ب-ر, with the root verb قَبَرَ meaning \"he buried.\" أَقْبَرَ means \"he caused to be buried\" or \"he provided a grave.\" The connection lies in actively arranging for burial, reflecting the root's concept of interment. It highlights the respect and honor in ensuring the deceased are properly buried, emphasizing the importance of burial rites and the dignity afforded to humans in death.",
  "278": "أَقْبَلَ and related words stem from the root ق-ب-ل, with the root verb قَبِلَ meaning \"he took, received, or admitted willingly,\" or \"he accepted.\" أَقْبَلَ means \"he advanced\" or \"he approached,\" emphasizing the act of turning oneself toward something with purpose. The connection lies in the root’s theme of facing or engaging, as أَقْبَلَ reflects a deliberate movement or orientation toward a goal, person, or task. This highlights readiness, attention, and the willingness to engage actively, symbolizing focus, intention, and acceptance in both physical and metaphorical contexts.",
  "279": "أَقْدَمُونَ and related words stem from the root ق-د-م, with the root verb قَدُمَ meaning \"he was ancient,\" \"he was old,\" or \"he preceded.\" أَقْدَمُونَ means \"more ancient,\" \"earlier,\" or \"oldest,\" emphasizing precedence and priority in time. The root conveys themes of being ahead, preceding others, or existing before. This term reflects the idea of antiquity or early origins, highlighting the significance of those who came first or existed in earlier times.",
  "280": "أَقْرَبُ and related words stem from the root ق-ر-ب, with the root verb قَرُبَ meaning \"he was near\" or \"he approached.\" أَقْرَبُ means \"nearer\" or \"closest,\" emphasizing a relative degree of nearness. Broader root meanings highlight proximity, intimacy, and closeness, whether physical, emotional, or spiritual. The connection lies in the idea of being closer than others, symbolizing priority, immediacy, or intimacy due to proximity. This term reflects the root’s emphasis on reducing distance and fostering closeness, whether to people, objects, or ideals.",
  "281": "أَقَرَّ and related words stem from the root ق-ر-ر, with the root verb قَرَّ meaning \"he settled,\" \"he remained,\" or \"he became cool.\" أَقَرَّ means \"he confirmed\" or \"he acknowledged.\" The connection lies in reinforcing or establishing something firmly, reflecting the root's concept of settling or making stable. By acknowledging or confirming, one solidifies a statement or fact, settling it into place. This highlights the importance of affirming truths and accepting responsibility.",
  "282": "أَقْرَضُوا and related words stem from the root ق-ر-ض, with the root verb قَرَضَ meaning \"he cut off\" or \"he clipped.\" أَقْرَضُوا means \"they lent\" or \"they gave as a loan.\" The connection lies in metaphorically \"cutting off\" a portion of one's wealth to lend to another, reflecting the root's concept of separating or parting with something. This emphasizes the act of selfless giving, where one temporarily parts with possessions for the benefit of others, highlighting the virtues of generosity and trust in divine recompense.",
  "283": "أَقْسَطُ and related words stem from the root ق-س-ط, with the root verb قَسَطَ meaning \"he was unjust\" or \"he deviated from justice.\" أَقْسَطُ means \"more just,\" emphasizing a higher degree of fairness or equity. This term reflects an elevated standard of justice, requiring not only the absence of injustice but also the deliberate pursuit of what is most fair and equitable. It highlights themes of righteousness, impartiality, and striving for excellence in ensuring fairness, highlighting the importance of surpassing basic justice to embody the highest moral standards.",
  "284": "أَقْسَمُوا and related words stem from the root ق-س-م, with the root verb قَسَمَ meaning \"he divided\" or \"he allotted.\" أَقْسَمُوا means \"they swore an oath,\" emphasizing the act of making a solemn declaration or promise. The connection lies in the symbolic act of dividing or dedicating one’s word to affirm truthfulness, reflecting a binding commitment. This term highlights the gravity and ethical responsibility of promises, highlighting the importance of truthfulness and integrity in one’s declarations. It conveys themes of accountability, sincerity, and the moral obligation to uphold one's word.",
  "285": "أَقْصَىٰ and related words stem from the root ق-ص-ي, with the root verb قَصَا meaning \"it was distant\" or \"it became remote.\" أَقْصَىٰ means \"farthest end,\" emphasizing the concept of being far removed or at the utmost distance. The root conveys themes of remoteness, separation, and reaching the farthest point. In the Qur'an, الْمَسْجِدُ الأَقْصَىٰ refers to the \"Farthest Mosque,\" identified as Masjid al-Aqsa in Jerusalem. It symbolizes a sacred place of immense spiritual significance that unites Muslims across great distances, reflecting the unity of faith despite physical separation. While distant to many Muslims, it serves as a point of unity, strengthening hearts and grounding them in Islam.",
  "286": "أَقْطَارٌ and related words stem from the root ق-ط-ر, with the root verb قَطَرَ meaning \"he dripped\" or \"he distilled.\" أَقْطَارٌ (plural of قُطْرٌ) refers to \"regions,\" \"horizons,\" or \"extents,\" emphasizing the vastness and diversity of different areas. The connection lies in the notion of measured or delineated expanses, much like how a diameter measures across a circle, symbolizing breadth and extension. The root conveys a sense of division or delineation, reflecting the distinct and far-reaching expanses of the earth or horizons. It highlights themes of vastness, diversity, and the structured distribution of space.",
  "287": "أَقْفَالٌ and related words stem from the root ق-ف-ل, with the root verb قَفَلَ meaning \"he locked,\" \"he closed,\" or \"he returned.\" أَقْفَالٌ (plural of قُفْلٌ) means \"locks.\" The connection lies in the act of securing or sealing to prevent access, emphasizing closure and restriction. The root also conveys meanings such as \"to dry up\" or \"to wither,\" reflecting a sense of finality or conclusion. This connection becomes even clearer when considering that something locked up, whether literal or metaphorical, is akin to drying up and withering, symbolizing stagnation or the cessation of movement.",
  "288": "أَقْلِعِي and related words stem from the root ق-ل-ع, with the root verb قَلَعَ meaning \"he uprooted,\" \"he extracted,\" or \"he removed forcefully.\" أَقْلِعِي means \"cease!\" or \"desist!\" It commands an abrupt stop, reflecting the root's idea of forcefully removing or uprooting something. Just as one might uproot a plant from the ground, أَقْلِعِي signifies a decisive cessation of action.",
  "289": "أَقْنَىٰ and related words stem from the root ق-ن-ي, with the root verb قَنَا meaning \"he acquired\" or \"he possessed.\" أَقْنَىٰ is the causative form, meaning \"He enriched\" or \"He made someone possess wealth.\" The root conveys themes of sufficiency, contentment, and preservation, reflecting both material acquisition and the state of having enough. This term highlights wealth as a divine provision that fulfills needs while fostering gratitude. It emphasizes Allah's (ﷻ) role in granting abundance and inner contentment, balancing provision with sufficiency and reminding us that true enrichment lies in both material blessings and satisfaction of the heart.",
  "290": "أَقْوَاتٌ and related words stem from the root ق-و-ت, with the root verb قَاتَ meaning \"he fed, nourished, or sustained,\" specifically with food sufficient to sustain life. أَقْوَاتٌ refers to \"provisions\" or \"sustenance,\" emphasizing essential means for survival. The root embodies the idea of sustaining existence and maintaining vitality, highlighting the indispensable role of nourishment in supporting life. أَقْوَاتٌ extends this concept to the provisions granted by Allah (ﷻ), symbolizing His care, support, and comprehensive nurturing of His creation.",
  "291": "أَقْوَمُ and related words stem from the root ق-و-م, with the root verb قامَ meaning \"he stood\" or \"he rose.\" The root encompasses concepts of standing upright, rising, and maintaining balance. أَقْوَمُ means \"more upright,\" \"straighter,\" or \"most just.\" It signifies the highest degree of uprightness or correctness. The connection lies in elevating the idea of standing to embody the epitome of righteousness and justice, reflecting the root's emphasis on uprightness and stability.",
  "292": "أَكَلَ and related words stem from the root أ ك ل, with the root verb itself being أَكَلَ meaning 'he ate' or 'he consumed.' أَكَلَ refers to the act of eating or consuming sustenance. The connection is direct, as it reflects the root's primary action of consumption necessary for life. In the Qur'an, it pertains to both the literal act of eating food and the metaphorical devouring of what is unlawful, such as sins or forbidden gains, emphasizing both the physical and moral dimensions of consumption.",
  "293": "أَكِنَّةٌ and related words stem from the root ك-ن-ن, with the root verb كَنَّ meaning \"he concealed\" or \"he hid.\" أَكِنَّةٌ refers to \"coverings,\" \"veils,\" or \"concealments,\" emphasizing physical or metaphorical barriers that obscure or hide something. The connection lies in objects or states that prevent perception, understanding, or access, directly reflecting the root’s idea of hiding. This term highlights the notion of separation or protection, whether physical, mental, or spiritual, highlighting the deliberate act of obscuring or shielding.",
  "294": "أَكَّالُونَ and related words stem from the root أ-ك-ل, with the root verb أَكَلَ meaning \"he ate\" or \"he consumed.\" أَكَّالُونَ is an intensive form meaning \"devourers\" or \"great eaters,\" describing people who consume excessively. The word emphasizes overindulgence and greed, amplifying the root concept of consumption. In moral contexts, being labeled أَكَّالُونَ reflects unethical behavior, often associated with those who habitually seek ill-gotten gains or indulge in unlawful consumption, linking to the broader root meaning of gradual destruction caused by unchecked, immoral consumption.",
  "295": "أَكْبَرُ and related words stem from the root ك-ب-ر, with the root verb كَبُرَ meaning \"he became great\" or \"he grew.\" أَكْبَرُ means \"greater\" or \"greatest,\" embodying the root's concepts of greatness, magnitude, and importance. It appears in the phrase \"اللهُ أَكْبَرُ\" (Allah is the Greatest), a declaration used to glorify Allah (ﷻ) and affirm His unmatched majesty and supreme authority. This phrase highlights Allah’s (ﷻ) unparalleled greatness, inspiring humility and submission in the believer, while reminding us that all greatness belongs solely to Him.",
  "296": "أَكْبَرْنَ and related words stem from the root ك-ب-ر, with the root verb كَبُرَ meaning \"he became great\" or \"he grew.\" أَكْبَرْنَ means \"they greatly admired\" or \"they were in awe of,\" reflecting a profound acknowledgment of greatness or magnitude. The root embodies themes of growth, prominence, and significance, whether in physical size, importance, or emotional impact. أَكْبَرْنَ highlights how the perception of greatness evokes awe and admiration, capturing the transformative effect of recognizing something extraordinary or beyond ordinary limits.",
  "297": "أَكْثَرَ and related words stem from the root ك-ث-ر, with the root verb كَثُرَ meaning \"it became numerous,\" \"it increased,\" or \"it multiplied.\" أَكْثَرَ means \"most\" or \"more,\" referring to the larger part of something, whether in terms of quantity, number, or magnitude. It conveys a comparative or highest degree, emphasizing abundance in relation to other parts. The connection to the root lies in its focus on multiplicity and profusion, with أَكْثَرَ reflecting the dominance or majority of a group, object, or concept. It highlights themes of overwhelming abundance or the larger portion, often used to describe the greater share in various contexts.",
  "298": "أَكْدَىٰ and related words stem from the root ك-د-ي, with the root verb كَدَىٰ meaning \"it became hard,\" \"it became barren,\" or \"it yielded little,\" often describing unproductive land or a well yielding little water. The root conveys themes of barrenness, cessation, and unproductiveness, reflecting a shift from giving or producing to withholding. أَكْدَىٰ means \"he withheld,\" \"he cut short,\" or \"he ceased,\" highlighting an abrupt halting of action. It describes someone who begins giving or acting but stops, whether due to stinginess, lack of sincerity, or obstacles. These terms emphasize inconsistency, unsustainability, and a lack of follow-through, symbolizing actions neither enduring nor deeply invested.",
  "299": "أَكْرَمُ and related words stem from the root ك-ر-م, with the root verbs كَـرُمَ meaning \"he or it was highly esteemed, valued, precious, or rare,\" and كَرَّمَ meaning \"he honored greatly\" or \"he ennobled.\" أَكْرَمُ means \"most noble\" or \"most generous,\" denoting the pinnacle of nobility, generosity, and value. It highlights the highest embodiment of the root’s qualities, reflecting something precious and rare in its perfection. When used to describe Allah (ﷻ), such as in رَبُّكَ الْأَكْرَمُ, it signifies His unmatched nobility and limitless capacity to bestow blessings, honor, and generosity. This term encourages reflection on Allah’s (ﷻ) supreme nobility as the standard for human conduct, inspiring generosity and moral excellence.",
  "300": "أَكْرَمَ and related words stem from the root ك-ر-م, with the root verbs كَـرُمَ meaning \"he or it was highly esteemed, valued, precious, or rare,\" and كَرَّمَ meaning \"he honored greatly\" or \"he ennobled.\" أَكْرَمَ means \"he honored\" or \"he bestowed generosity upon.\" This form emphasizes initiating acts of honor or generosity, reflecting the transition from inherent nobility (كَـرُمَ) to active, deliberate deeds. The term highlights the transformative nature of noble qualities, where dignity and generosity manifest as conscious actions to uplift others. In a divine context, أَكْرَمَ reflects Allah’s (ﷻ) active role in bestowing honor and blessings, highlighting His position as the ultimate source of all dignity and nobility.",
  "301": "أَكْفَرَ and related words stem from the root ك-ف-ر, with the root verb كَفَرَ meaning \"he covered,\" \"he concealed,\" or \"he disbelieved.\" أَكْفَرَ can mean \"he declared someone an unbeliever,\" \"he attributed disbelief,\" or \"he caused disbelief.\" The root’s meaning of concealing connects to hiding or denying truth, whether by attributing disbelief to others or leading them astray. In expressions like مَا أَكْفَرَ, the term shifts to an exclamatory form, marveling at or condemning extreme disbelief or ingratitude. It emphasizes the enormity of rejecting or \"covering\" what is evident—blessings, faith, or truth—and highlights the moral responsibility in engaging with truth and disbelief.",
  "302": "أَكْفِلْ and related words stem from the root ك-ف-ل, with the root verb كَفَلَ meaning \"he took care of,\" \"he guaranteed,\" or \"he supported.\" أَكْفِلْ means \"entrust\" or \"cause someone to take care,\" emphasizing an active delegation of responsibility or guardianship. This connects to the root's themes of accountability, support, and ensuring care is provided through deliberate trust. The term highlights the importance of placing confidence in others to fulfill obligations with integrity and highlights the mutual reliance and responsibility central to maintaining trust and harmony. It reflects the broader concept of ensuring that duties are not only assigned but carried out with sincerity and care.",
  "303": "أَكْلٌ and related words stem from the root أ-ك-ل, with the root verb أَكَلَ meaning \"he ate\" or \"he consumed.\" أَكْلٌ means \"eating\" or \"consuming,\" representing the general act or process of consuming food. The connection abstracts the root's action into a concept, encompassing all aspects of eating. In Qur'anic and ethical discussions, أَكْلٌ can relate to guidelines on lawful consumption, gratitude for sustenance, and warnings against unjustly consuming others' property. This ties into the broader root meaning of consumption leading to depletion of resources and eventual destruction. ",
  "304": "أَكْمَامٌ and related words stem from the root ك-م-م, with the root verb كَمَّ meaning \"he covered\" or \"he concealed.\" أَكْمَامٌ refers to \"buds,\" \"sheaths,\" or \"coverings\" of plants, emphasizing enclosures that protect and conceal developing fruits, flowers, or other plant parts. The connection lies in the act of covering, directly aligning with the root's concept of shielding something for protection. These coverings nurture and safeguard growth, allowing concealed potential to develop before emerging. Symbolically, أَكْمَامٌ reflects latent potential, careful preparation, and the transformative process of emergence, where hidden beauty and sustenance are revealed in time.",
  "305": "أَكْمَلَ and related words stem from the root ك-م-ل, with the root verb كَمُلَ meaning \"he or it was complete\" or \"he or it was perfect.\" أَكْمَلَ means \"he completed\" or \"he perfected,\" indicating the action of bringing something to a state of fullness or flawlessness. The root conveys themes of completeness, perfection, and achieving an ideal state without deficiencies. The term emphasizes deliberate effort in completing or perfecting something, often associated with actions that enhance or elevate something to its intended or optimal form. This reflects the broader concept of progress toward fulfillment and excellence.",
  "306": "أَكْمَهُ and related words stem from the root ك-م-ه, referring to an individual who is congenitally blind, meaning blind from birth. The root conveys themes of inherent blindness, both literally and metaphorically, indicating an absence of vision or insight present from the beginning. This term underscores the state of being devoid of sight from birth, highlighting the condition of blindness without prior experience of vision.",
  "307": "أَكْنَانٌ and related words stem from the root ك-ن-ن, with the root verb كَنَّ meaning \"he concealed\" or \"he hid.\" أَكْنَانٌ refers to \"shelters,\" \"hiding places,\" or \"places of concealment,\" emphasizing locations that provide cover, refuge, or protection. The connection lies in spaces designed to safeguard or hide something, aligning directly with the root’s concept of concealment. This term reflects the themes of safety, security, and retreat, offering solace and protection through the act of concealment.",
  "308": "أَكْنَنْتُمْ and related words stem from the root ك-ن-ن, with the root verb كَنَّ meaning \"he concealed\" or \"he hid.\" أَكْنَنْتُمْ means \"you cause to be concealed\" or \"you cause to be hidden,\" focusing on the deliberate action of hiding or covering something. The connection lies in intentionally ensuring something remains unseen or protected, embodying the root’s central idea of concealment. This term emphasizes deliberate effort and intention in creating a state of hiding or safeguarding.",
  "309": "أَكْوابٌ and related words stem from the root ك-و-ب, with the root verb كَبَّ meaning \"he turned over,\" \"he inverted,\" or \"he poured out.\" أَكْوابٌ is the plural of كُوبٌ, referring specifically to cups designed for drinking. The connection to the root lies in the inherent functionality of a cup, which involves tilting or inverting to pour or dispense liquids. Cups, as vessels for sharing drinks, embody notions of hospitality, provision, and abundance, often associated with generosity and sustenance. The design and purpose of أَكْوابٌ reflect a balance between utility and elegance, resonating with themes of nourishment and communal sharing.",
  "310": "The particle أَلا is used to capture attention and emphasize the importance of the message. In the Qur'an, it conveys meanings like \"no doubt!\" or \"unquestionably!\" and often introduces negative questions, implying surprise or an expectation of an affirmative answer. It highlights key statements and draws attention to significant messages. Additionally, it can express surprise or set up an expectation, often used rhetorically. أَلَا frequently precedes important revelations or admonitions, acting as a divine signal to alert the audience to crucial messages.",
  "311": "أَلَنَّا and related words stem from the root ل-ي-ن, with the root verb لَانَ meaning \"he was soft,\" \"he was gentle,\" or \"he was yielding.\" أَلَنَّا means \"We made pliable\" or \"We made soft,\" emphasizing the act of rendering something flexible, manageable, or easy to use. The connection lies in the root's focus on softness and adaptability, reflecting an intentional transformation of a rigid or hard state into one of pliability. This highlights the ability to shape, influence, or prepare something for ease and utility, demonstrating both control and gentleness in effecting change.",
  "312": "أَلَتْنَا and related words stem from the root أ-ل-ت, with the root verb أَلَتَ meaning \"he diminished,\" \"he lessened,\" or \"he deprived.\" أَلَتْنَا means \"we diminished\" or \"we caused loss,\" reflecting the root's emphasis on reduction and deprivation. It is used to signify actions resulting in a loss of benefit. In the Qur'an, Allah (ﷻ) reassures believers that He will not diminish their good deeds, highlighting His justice and mercy. The root also carries the notion of a binding oath, further reinforcing the commitment that nothing will be diminished from their reward.",
  "313": "أَلَدُّ stems from the root ل-د-د, with the verb لَدَّ meaning \"he disputed\" or \"he was stubborn.\" أَلَدُّ means \"most argumentative\" or \"most obstinate.\" The root conveys the idea of intense disputation or twisting in argumentation, highlighting the extreme degree of stubbornness and resistance in an individual. This term reflects someone excessively argumentative, whose resistance makes reasoning or reconciliation difficult.",
  "314": "أَلِيمٌ and related words stem from the root أ-ل-م, with the root verb أَلِمَ meaning \"he felt pain\" or \"he suffered.\" أَلِيمٌ means \"painful\" or \"severe,\" often used to describe punishment. The root's broader meanings encompass physical and emotional suffering, reflecting the deep discomfort or affliction one experiences. The connection emphasizes the intensity and sharpness of the pain, whether in punishment or hardship, highlighting the severity of the experience. The root can also imply the endurance of prolonged distress, reinforcing the weight and magnitude of suffering tied to the word.",
  "315": "أَلَّفَ and related words stem from the root أ-ل-ف, with the root verb أَلِفَ meaning \"he became familiar with,\" \"he was accustomed to,\" or \"he was fond of.\" أَلَّفَ means \"he united\" or \"he joined together.\" The root suggests familiarity, affinity, and comfort, indicating a natural closeness or bond. The connection transforms personal familiarity into the act of fostering unity, harmony, and understanding. It also encompasses the idea of \"forming\" or \"creating bonds,\" reflecting the establishment of lasting connections that transcend differences.",
  "316": "أَلْبَابٌ and related words stem from the root ل-ب-ب, with the root verb لَبَّ meaning \"he was or became possessed of understanding, intellect, or intelligence.\" لُبٌّ refers to \"the innermost part,\" \"heart,\" \"kernel,\" or \"purest essence,\" emphasizing the core free from extraneous elements. Applied to humans, it signifies \"intellect,\" \"understanding,\" or \"mind,\" the purest and most refined faculty, akin to the heart of a kernel as its most valuable part. أَلْبَابٌ, the plural, means \"intellects\" or \"understanding,\" highlighting reason, insight, and clarity untainted by impurities. Like a kernel’s core, true intellect arises from reflection and purification, embodying wisdom and discernment.",
  "317": "أَلْحَقْنَا and related words stem from the root ل-ح-ق, with the root verb لَحِقَ meaning \"he overtook,\" \"he reached,\" or \"he caught up.\" This root encompasses pursuit, arrival, and attachment, often implying effort to bridge a gap or achieve connection. أَلْحَقْنَا specifically means \"We caused to join,\" directly tying to the root’s essence of reaching or overtaking to establish connection. It signifies a deliberate action by which something is brought to align or unite with another, embodying the transition from separation to attachment. This causative form reflects the root’s inherent meanings of pursuit and joining, emphasizing the deliberate effort and resulting unity or inclusion.",
  "318": "أَلْفٌ and related words stem from the root أ-ل-ف, with the root verb أَلِفَ meaning \"he became familiar\" or \"he was accustomed.\" أَلْفٌ means \"thousand.\" The connection lies in the root's association with familiarity, gathering, and affinity. Just as the root implies bringing together or uniting, أَلْفٌ can symbolize a multitude, reflecting the idea of unity in large numbers. The concept of \"thousand\" conveys strength and cohesion, suggesting that familiarity and closeness multiply within a collective, reinforcing the broader idea of bringing elements together into a unified whole.",
  "319": "أَلْفَافٌ and related words stem from the root ل-ف-ف, with the root verb لَفَّ meaning \"he wrapped,\" \"he wound,\" or \"he folded.\" أَلْفَافٌ means \"dense vegetation,\" \"entwined growth,\" or \"thickly wrapped plants.\" The connection lies in the intertwining and wrapping together of plants or trees, reflecting the root's emphasis on folding or enveloping. This term vividly describes lush, dense vegetation where branches and leaves are tightly interwoven, symbolizing the richness and abundance of nature as a manifestation of Allah’s (ﷻ) infinite bounty and care.",
  "320": "أَلْفَوْا and related words stem from the root ل-ف-و, with the root verb لَفِيَ meaning \"to find,\" \"to discover,\" or \"to encounter.\" The verb أَلْفَوْا means \"they found\" or \"they discovered,\" emphasizing encountering something intentionally or unexpectedly. The connection lies in the root's focus on realization or coming upon something. This term highlights not only the physical act of finding but also the situational or mental realization accompanying discovery, aligning with the root’s sense of encountering or uncovering. It often implies a significant or complete act of finding, highlighting the readiness or awareness involved.",
  "321": "أَلْقَابٌ and related words stem from the root ل-ق-ب, with the root verb لَقَّبَ meaning \"he gave a surname,\" \"he bestowed a nickname,\" or \"he assigned a title.\" أَلْقَابٌ means \"surnames,\" \"nicknames,\" or \"titles.\" The connection lies in the act of naming or labeling, reflecting the root's emphasis on ascribing identifiers to individuals. This term highlights the importance and impact of names and titles in shaping perceptions and identities, and in the Qur'anic context, warns against using derogatory nicknames that harm others, emphasizing respect and honor in addressing one another.",
  "322": "أَلْقَىٰ and related words stem from the root ل-ق-ي, with the root verb لَقِيَ meaning \"he met,\" \"he encountered,\" or \"he found.\" This root encompasses ideas of coming face to face, experiencing, or confronting something. أَلْقَىٰ means \"he threw,\" \"he cast,\" or \"he offered.\" The connection lies in the notion of bringing something forth to be encountered or engaged with by others. When one \"casts\" or \"throws\" an object, it is sent forth to meet its destination or to be encountered. Similarly, \"offering\" something—whether an object, words, or peace—is a deliberate act of presenting it for others to receive, emphasizing the root's focus on meeting, interaction, and purposeful engagement.",
  "323": "أَلْهَمَ and related words stem from the root ل-ه-م, with the root verb لَهِمَ meaning \"he eagerly desired,\" \"he swallowed greedily,\" or \"he devoured.\" أَلْهَمَ means \"he inspired,\" \"he instilled,\" or \"he put into the mind or heart.\" The connection lies in the notion of placing something deeply within, much like ingesting, reflecting the root's emphasis on internalization and intense desire. This term highlights the act of divine inspiration or intuition being instilled in a person by Allah (ﷻ), emphasizing the profound and intrinsic nature of such guidance, which is absorbed and internalized like nourishment to the soul.",
  "324": "أَمَاتَ and related words stem from the root م-و-ت, with the root verb مَاتَ meaning \"he died.\" أَمَاتَ means \"he caused to die\" or \"he gave death,\" emphasizing Allah’s (ﷻ) power over life and death. ٱلْمُمِيتُ, one of Allah’s (ﷻ) perfect names, means \"The Bringer of Death\" or \"The Life-Taker,\" signifying His authority to end life according to His will at an appointed time. The root conveys themes of mortality and the transition from life to death, reminding us of life’s temporality and the need to prepare for the Hereafter, knowing that Allah (ﷻ) alone determines our time.",
  "325": "The particle أَمَامَ translates to \"in front of,\" \"ahead of,\" or \"before,\" and is used to indicate spatial or metaphorical positioning. It serves as an adverb of place to describe physical locations, such as someone standing in front of an object, or abstract contexts, like future events or consequences awaiting an individual. In the Qur'an, أَمَامَ symbolizes the idea of persistently sinning while disregarding the consequences that lie ahead. This serves as an important reminder to think carefully before acting, consider inevitable outcomes, and reflect on past wrongdoing to avoid repetition.",
  "326": "الْأَمَانَةَ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he trusted,\" or \"he was reliable.\" الْأَمَانَةَ means \"the trust,\" \"trustworthiness,\" or \"something entrusted,\" specifically referring to the obligatory duties prescribed by Allah (ﷻ). The root encompasses themes of safety, security, and reliability, emphasizing the moral and spiritual responsibility placed upon the one entrusted. The connection lies in the profound accountability to protect, fulfill, and uphold what has been entrusted with sincerity and faithfulness, reflecting the broader root dimensions of dependability and integrity.",
  "327": "أَمَانَةٌ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he trusted,\" or \"he was reliable.\" أَمَانَةٌ means \"trust\" or \"entrusted responsibility.\" This word connects to the root through the ideas of reliability and security, highlighting the concept of entrusting something valuable to someone dependable. It reflects the moral weight and accountability involved in safeguarding and upholding a trust.",
  "328": "أَمَدٌ and related words stem from the root أ-م-د, with the root verb أَمَدَ meaning \"he extended\" or \"he prolonged.\" أَمَدٌ refers to a \"term,\" \"duration,\" or \"extent,\" emphasizing the concept of reaching a set limit or end point. Unlike زَمَانٌ (which considers both the beginning and end of a period), أَمَدٌ focuses on time or space with regard to its final boundary, highlighting the finite nature of periods and distances. This root concept reminds one of the importance of limits, whether in time or in actions.",
  "329": "أَمَدَّ and related words stem from the root م-د-د, with the root verb مَدَّ meaning \"he extended,\" \"he stretched,\" or \"he prolonged.\" أَمَدَّ means \"he extended,\" \"he supplied,\" or \"he reinforced.\" The connection lies in the active provision of additional support or resources, reflecting the root’s essence of enhancement and extension. It emphasizes the act of strengthening or enhancing something by adding to it, whether through material aid, reinforcement, or other means, aligning with the root’s focus on expansion and increase.",
  "330": "أَمَرَ and related words stem from the root أ-م-ر, and as the root verb, it means \"he commanded\" or \"he ordered.\" It denotes the act of giving a command, directive, or instruction. The connection to the root is direct, with أَمَرَ embodying the central concept of enjoining or directing with authority. Broader root concepts include order, authority, and purposefulness, as the root conveys a sense of managing or establishing order, often implying deliberate and structured actions taken to guide or influence others.",
  "331": "أَمَرُّ and related words stem from the root م-ر-ر, with the root verb مَرَّ meaning \"he passed by\" or \"he was or became bitter.\" أَمَرُّ means \"more bitter\" or \"most bitter,\" intensifying the concept of bitterness. The root conveys ideas of harshness, sharpness, and difficulty, with أَمَرُّ representing an extreme degree of bitterness—whether in taste or in experiences that are exceedingly harsh or challenging. This ties back to the root's themes of sharpness and endurance, highlighting the heightened intensity of something difficult to bear, both physically and metaphorically.",
  "332": "أَمَلٌ and related words stem from the root أ-م-ل, with the root verb أَمَلَ meaning \"he hoped\" or \"he expected.\" أَمَلٌ translates to \"hope,\" \"expectation,\" or \"desire,\" reflecting the root’s association with looking forward in anticipation. Broadly, أَمَلٌ conveys optimism and patience. In spiritual contexts, it encourages trust in Allah’s (ﷻ) mercy, while warning against long hopes that might distract from the hereafter, balancing hope with mindfulness of one’s ultimate priorities.",
  "333": "أَمَنَةٌ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he felt secure,\" or \"he trusted.\" أَمَنَةٌ means \"security,\" \"freedom from fear,\" or \"ease of mind.\" The connection lies in embodying a state of calm and reassurance derived from trust and safety, reflecting the root’s emphasis on protection and reliability. Unlike أَمْنٌ, the word أَمَنَةٌ highlights the psychological and personal aspect of security, focusing on the inner peace that arises from trust and a sense of safety.",
  "334": "أَمِنَ and related words stem from the root أ-م-ن and is the root verb meaning \"he was safe,\" \"he felt secure,\" or \"he trusted.\" This word represents the fundamental state of safety and the feeling of trust. It forms the foundation for many related words concerning trust, security, faith, and reliability. أَمِنَ emphasizes the essential human experience of seeking safety, placing trust in others, and entrusting oneself to Allah (ﷻ). It highlights the basis for personal and societal bonds, as well as the moral responsibility inherent in trustworthiness and mutual reliance.",
  "335": "أَمِينٌ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he trusted,\" or \"he was reliable.\" أَمِينٌ means \"trustworthy,\" \"faithful,\" or \"reliable.\" The connection lies in being worthy of trust, reflecting the root’s emphasis on security and trustworthiness. A person described as أَمِينٌ is one who can be relied upon, who safeguards what is entrusted to them, embodying honesty and integrity. This term highlights the moral virtue of reliability and the value of being a safe haven for others' trust.",
  "336": "أَمَّارَةٌ and related words stem from the root أ-م-ر, with the root verb أَمَرَ meaning \"he commanded\" or \"he ordered.\" أَمَّارَةٌ is an intensive form meaning \"persistently commanding\" or \"instigating.\" In the phrase إِنَّ النَّفْسَ لَأَمَّارَةٌ بِالسُّوءِ (Indeed, the soul surely persistently commands toward evil), it describes the inner self that repeatedly urges one toward wrongdoing. This usage intensifies the root’s concept of commanding, highlighting the internal struggle and the need for self-control.",
  "337": "أَمْتٌ and related words stem from the root أ-م-ت, with the root verb أَمَتَ meaning both \"to make uneven\" or \"to create irregularities\" and \"to measure\" or \"set a limit.\" أَمْتٌ means \"unevenness,\" \"irregularity,\" \"ridges,\" or \"imperfections.\" The connection lies in the presence of variations or imperfections, reflecting the root's emphasis on a lack of uniformity along with the idea of setting boundaries or specific limits. This suggests that imperfections or variations aren’t just random flaws. Rather, they are distinct breaks or markers interrupting an otherwise continuous or smooth form.",
  "338": "أَمْثَلُ and related words stem from the root م-ث-ل, with the root verb مَثَلَ meaning \"he resembled,\" \"he was like,\" or \"he set forth an example.\" أَمْثَلُ means \"most exemplary,\" \"more excellent,\" or \"better,\" signifying superiority or distinction within a group or context. The connection lies in surpassing others as a superior model, reflecting the root's concept of resemblance and exemplification. It highlights the idea of standing out by embodying higher standards or qualities that distinguish one as an ideal example for others to follow.",
  "339": "أَمْرٌ and related words stem from the root أ-م-ر, with the root verb أَمَرَ meaning \"he commanded\" or \"he ordered.\" أَمْرٌ translates to \"command\" as well as \"affair\" or \"matter,\" connecting the idea of authority with issues that require attention or action. The root concept involves authority, structure, and the need for action, as أَمْرٌ denotes any issue or matter that requires direction or resolution. This highlights a sense of purposeful management and accountability across various contexts.",
  "340": "أَمْسِ is a noun translated to \"yesterday\" or \"a short time before,\" referring to the day just passed, as if it is still within reach. It emphasizes how the immediate past remains relevant and impactful. This term reflects the immediacy of the past and its ongoing influence on the present moment. In both classical Arabic and everyday usage, أَمْسِ denotes recent past events, serving as a reminder of the continuity between past actions and their consequences in the present. Its usage highlights the importance of reflection on recent events to shape better decisions moving forward.",
  "341": "أَمْسَكَ and related words stem from the root م-س-ك, with the root verb مَسَكَ meaning \"he held\" or \"he grasped.\" أَمْسَكَ means \"he withheld\" or \"he restrained.\" The connection lies in the act of holding back or restraining, reflecting the root's core concept of grasping. This emphasizes control or the prevention of something from proceeding, highlighting themes of restraint and containment.",
  "342": "أَمْشَاجٌ and related words stem from the root م-ش-ج, with the root verb مَشَجَ meaning \"he mixed\" or \"he blended.\" أَمْشَاجٌ means \"mixed substances\" or \"mingled elements.\" The connection lies in combining different components to create a unified entity. This reflects the root's core concept of mixing, emphasizing the complexity and diversity within a single creation, such as the mingled fluids in human reproduction.",
  "343": "أَمْعاءُ and related words stem from the root م-ع-ي, meaning \"intestines\" or \"bowels.\" The term أَمْعاءُ specifically refers to the internal digestive organs, with its singular form مِعًى denoting a single intestine. It is a precise anatomical term describing the internal workings of the body, emphasizing the complexity and vital role of these organs in sustaining life. Its connection to internal structures underscores themes of depth, internal processes, and the unseen yet essential mechanisms that enable physical existence.",
  "344": "أَمْكَنَ and related words stem from the root م-ك-ن, with the root verb مَكَنَ meaning \"he was firm,\" \"he was strong,\" or \"he was established.\" أَمْكَنَ means \"he enabled,\" \"he made possible,\" or \"he empowered,\" emphasizing the act of granting the means or capability to achieve something. The connection lies in the root’s concept of firmness and establishment, extending to the idea of facilitating strength, stability, or ability for others.",
  "345": "أَمْلَى and related words stem from the root م-ل-و, with the root verb مَلِيَ meaning \"it lasted long\" or \"it endured.\" أَمْلَى means \"he granted respite,\" \"he deferred,\" or \"he extended time.\" The connection lies in the root's concept of prolongation, reflecting the act of granting additional time for dictation, reflection, or amendment. This term emphasizes patience in allowing opportunities for improvement or preservation of information.",
  "346": "أَمْنٌ and related words stem from the root أ-م-ن, with the root verb أَمِنَ meaning \"he was safe,\" \"he felt secure,\" or \"he trusted.\" أَمْنٌ means \"security,\" \"safety,\" or \"protection.\" The connection is direct, representing the state or condition of being secure and free from fear. This term encapsulates the root’s overarching concept, emphasizing the fundamental human need for safety and the assurance that comes from trust and protection. أَمْنٌ is broader, referring to security in a societal or physical sense, such as the protection of a community.",
  "347": "أَمْهِلْ and related words stem from the root م-ه-ل, with the root verb مَهَلَ meaning \"he delayed\" or \"he was gentle.\" أَمْهَلَ means \"he gave respite\" or \"he granted delay,\" and أَمْهِلْ is the command form, meaning \"grant respite\" or \"give time.\" This word conveys the idea of allowing time with a focus on patience and gentleness. It often implies granting an opportunity for reflection or action without haste, emphasizing leniency and forbearance.",
  "348": "أَنَابَ and related words stem from the root ن-و-ب, with the root verb نَابَ meaning \"he returned\" or \"he turned back,\" including a spiritual return to Allah (ﷻ) in repentance. أَنَابَ similarly means \"he turned to Allah in repentance\" or \"he returned in submission.\" The distinction lies in emphasis: نَابَ conveys a more general act of returning or turning back, while أَنَابَ emphasizes a deliberate and sustained effort in seeking forgiveness and obedience to Allah (ﷻ). This connection reflects the root’s overarching themes of renewal, repentance, and turning toward righteousness, highlighting the importance of consistently seeking Allah’s (ﷻ) mercy and guidance.",
  "349": "أَنامٌ and related words stem from the root أ-ن-م, though its exact root is debated. أَنامٌ means \"creatures,\" \"all created beings,\" or \"all those subject to sleep,\" encompassing all living beings that experience cycles of rest and wakefulness. The connection lies in the shared characteristics of creation, particularly dependence and vulnerability, reflecting the interconnectedness of all life under Allah’s (ﷻ) care and His provision of rest as a sign of His mercy and wisdom.",
  "350": "أَنامِلُ and related words stem from the root ن-م-ل, with the root verb نَمَلَ meaning \"he whispered\" or \"he wrote quickly,\" reflecting themes of subtlety and precision. أَنامِلُ (plural of أُنْمُلَةٌ) means \"fingertips,\" referring to the most delicate and sensitive part of the hand. The connection lies in the fingertips’ role in intricate tasks such as writing, crafting, or feeling, embodying the root’s emphasis on refinement and precision. This term highlights the significance of attention to detail and the unique capabilities endowed to humans, even in the smallest aspects of their creation.",
  "351": "أَنْجَىٰ and related words stem from the root ن-ج-و, with the root verb نَجَا meaning \"he became safe\" or \"he escaped.\" أَنْجَىٰ means \"He saved\" or \"He delivered,\" referring to the act of causing someone to be saved. The connection lies in the act of delivering from harm or danger, highlighting themes of salvation, mercy, and divine protection. It emphasizes Allah’s (ﷻ) role as the ultimate savior, rescuing individuals from peril through His mercy.",
  "352": "أَنْدَادٌ and related words stem from the root ن-د-د, with the root verb نَدَّ meaning \"he opposed,\" \"he deviated,\" or \"he fled.\" The root conveys ideas of resistance, separation, and divergence. أَنْدَادٌ (plural of نِدٌّ) means \"equals\" or \"rivals,\" referring to those set as competitors to Allah (ﷻ). The connection lies in the root’s emphasis on opposition, as associating rivals with Allah (ﷻ) reflects a departure from His oneness. This term highlights the gravity of shirk (associating partners with Allah) and warns of the severe consequences of attributing equals to Him. It calls for unwavering recognition of Allah's (ﷻ) unmatched sovereignty and a complete rejection of anything that compromises His unique divinity.",
  "353": "أَنْذَرَ and related words stem from the root ن-ذ-ر, with the root verb نَذَرَ meaning \"he vowed,\" \"he made a solemn promise,\" or \"he warned,\" emphasizing seriousness and commitment. The root conveys dedication, caution, and responsibility in significant matters. أَنْذَرَ means \"he warned\" or \"he cautioned,\" reflecting the act of alerting others to potential danger with sincerity and urgency. This embodies the root’s essence, where warning is a moral duty to guide and protect, highlighting accountability in serious communication.",
  "354": "أَنْزَلَ and related words stem from the root ن-ز-ل, with the root verb نَزَلَ meaning \"he descended,\" \"he came down,\" or \"he settled.\" أَنْزَلَ means \"he sent down\" or \"he revealed,\" emphasizing the act of causing something to descend. The root also conveys meanings such as \"to move from a higher to a lower position,\" \"to alight,\" and \"to stay or pause.\" This word often refers to divine messages, signs, or blessings being sent down intentionally by Allah (ﷻ). The root highlights the controlled and purposeful nature of descent, with أَنْزَلَ capturing the act of transmitting guidance, mercy, or provision from Allah (ﷻ) to humanity, reflecting the central theme of descent from above with intent and precision.",
  "355": "أَنْسَى and related words stem from the root ن-س-ي, with the root verb نَسِيَ meaning \"he forgot.\" أَنْسَى means \"he caused to forget\" or \"he made someone forget.\" The broader root encompasses themes of memory lapse, neglect, and abandonment, extending to deliberate and unintentional acts of forgetting. The verb أَنْسَى highlights an active influence in inducing forgetfulness, which could be intentional or circumstantial. This reflects the dynamic aspect of the root, where forgetfulness is not only an internal lapse but also something that can be externally prompted, reinforcing the theme of memory and its fragility.",
  "356": "أَنْشَأَ and related words stem from the root ن-ش-أ, with the root verb نَشَأَ meaning \"he grew up,\" \"he arose,\" or \"he originated.\" أَنْشَأَ means \"he produced,\" \"he initiated,\" or \"he brought into existence.\" The root conveys the themes of growth, origination, and emergence, highlighting the act of bringing something into being or causing it to develop. The connection lies in the dynamic process of raising or forming something from a latent state into existence. أَنْشَأَ reflects the power of initiation, where the act of starting something leads to its eventual development and establishment.",
  "357": "أَنشَرَ and related words stem from the root ن-ش-ر, with the root verb نَشَرَ meaning \"he spread out,\" \"he unfolded,\" or \"he revived.\" أَنشَرَ means \"he resurrected,\" \"he brought to life,\" or \"he revived.\" The root emphasizes the act of bringing something back to vitality or existence, similar to spreading out what was once folded or constrained. This term highlights the power of restoration and renewal, particularly in the context of life after death. It highlights the divine ability to resurrect and restore life, with Allah (ﷻ) alone having the ultimate authority over life and death.",
  "358": "أَنصِتُوا and related words stem from the root ن-ص-ت, with the root verb نَصَتَ meaning \"he was silent\" or \"he listened attentively.\" The root conveys the idea of quieting oneself to focus and absorb information. أَنصِتُوا means \"be silent\" or \"listen attentively,\" emphasizing the dual actions of refraining from speech and paying close attention. The connection lies in creating stillness to facilitate understanding, reflecting the root's emphasis on respect and thoughtful engagement. This term highlights the importance of silence as a tool for deep concentration, showing respect, and internalizing knowledge.",
  "359": "أَنْطَقَ and related words stem from the root ن-ط-ق, with the root verb نَطَقَ meaning \"he spoke\" or \"he uttered words.\" أَنْطَقَ means \"He made (someone or something) speak\" or \"He caused to speak,\" focusing on granting the ability to express or articulate words. The root emphasizes purposeful and clear speech, and أَنْطَقَ highlights the act of enabling expression, whether physical or metaphorical. This reflects the significance of speech as a means to convey thoughts, bring clarity, and give voice to what was silent, highlighting its role in understanding and communication.",
  "360": "أَنفٌ and related words stem from the root أ-ن-ف, with the root verb أَنِفَ meaning \"he was proud,\" \"he was high,\" or \"he took offense.\" أَنفٌ means \"nose.\" The connection lies in the nose as the most prominent, forward part of the face, reflecting the root’s emphasis on height, prominence, and being at the forefront. Across many cultures, the nose symbolizes pride or self-regard, as in \"holding one’s nose high.\" This aligns with the root’s connotations of pride, separation, and distinction—qualities that, when excessive, may lead to an inflated sense of self or create distance from others.",
  "361": "أَنْفَالٌ and related words stem from the root ن-ف-ل, with the root verb نَفَلَ meaning \"he gave extra\" or \"he granted as a gift.\" أَنْفَالٌ means \"spoils of war\" or \"additional gains.\" The connection lies in the concept of receiving extra or surplus benefits beyond what is due, directly relating to the root's meaning. It highlights the notion of additional rewards or bounties granted.",
  "362": "أَنْفَقَ and related words stem from the root ن-ف-ق, with the root verb نَفَقَ meaning \"it expired,\" \"it was depleted,\" or \"it diminished.\" أَنْفَقَ means \"he spent\" or \"he expended,\" referring to the deliberate use of resources, often for charitable or beneficial purposes. The connection lies in the idea of depletion, where wealth is reduced, but in this case, purposefully and positively. Unlike negative depletion, أَنْفَقَ highlights generosity and fulfilling obligations, transforming the act into a noble investment in others, such as supporting the needy or funding righteous causes. This reflects selflessness and aligns with the root’s broader themes of purposeful use and benefit.",
  "363": "أَنْقَذَ and related words stem from the root ن-ق-ذ, with the root verb نَقَذَ meaning \"he saved\" or \"he rescued.\" أَنْقَذَ also means \"he rescued\" or \"he delivered,\" but it differs in its more intensive and deliberate usage, emphasizing a focused effort to bring someone or something out of harm. While نَقَذَ broadly conveys the act of saving, أَنْقَذَ often highlights a decisive or complete act of rescue, particularly in urgent or critical circumstances. The connection lies in pulling someone out of danger or harm, directly reflecting the root’s emphasis on deliverance.",
  "364": "أَنْقَضَ and related words stem from the root ن-ق-ض, with the root verb نَقَضَ meaning \"he broke,\" \"he nullified,\" or \"he undid,\" emphasizing breaking apart or loosening. أَنْقَضَ means \"he made (something) crack\" or \"he burdened to the point of cracking.\" The connection lies in causing strain or pressure so intense that it threatens to break or weaken, reflecting the root’s focus on undoing or breaking a structure. أَنْقَضَ symbolizes overwhelming burdens, evoking the imagery of weight or hardship that strains the back, both physically and metaphorically, highlighting the profound effects of such challenges on one’s strength and resilience.",
  "365": "أَنْكَاثًا and related words stem from the root ن-ك-ث, with the root verb نَكَثَ meaning \"he broke (a pledge)\" or \"he unraveled.\" أَنْكَاثًا means \"broken threads\" or \"unraveled fibers.\" The connection lies in the act of undoing or breaking something woven, directly relating to the root's meaning. It symbolizes the undoing of commitments or the dismantling of agreements.",
  "366": "أَنكالٌ and related words stem from the root ن-ك-ل, with the root verb نَكَلَ meaning \"he refrained,\" \"he desisted out of fear,\" or \"he punished severely.\" أَنكالٌ (plural of نِكْلٌ) means \"shackles\" or \"fetters,\" referring to restraints that prevent movement or escape. The connection lies in deterrence and restraint: just as severe punishment instills fear and causes one to desist from wrongdoing, shackles physically restrain transgression. The root embodies themes of fear-based deterrence, restraint, and accountability, with أَنكالٌ symbolizing the corrective nature of punishment to maintain justice and prevent further transgression.",
  "367": "أَنْكَرَ and related words stem from the root ن-ك-ر, with the root verb نَكِرَ meaning \"he did not know,\" \"he was ignorant of,\" or \"he found strange.\" The root conveys themes of unfamiliarity, rejection, and disapproval. أَنْكَرَ is a comparative form meaning \"most foul,\" \"most abominable,\" or \"most objectionable.\" It signifies actions, speech, or characteristics that are condemned at the highest degree for being morally reprehensible or extremely unpleasant. The connection lies in the root's focus on disapproval and aversion, emphasizing a strong reaction to what is considered unacceptable or improper.",
  "368": "The particle أَنَّ means \"that\" and is used to introduce supporting parts of a sentence, emphasizing statements, explanations, or certainty. It plays a key role in linking ideas and clarifying intent in speech, often highlighting important points or affirming beliefs. This particle allows abstract thoughts to be expressed clearly, transforming inner reflections into structured communication that conveys meaning with precision and emphasis.",
  "369": "The interrogative adverb أَنَّىٰ means \"how\" or \"from where,\" often used to ask about the origin or process behind an event, especially in contexts of awe or wonder. It shares the root أ-ن-ى with the verb \"أَنَىٰ,\" meaning \"its time came\" or \"it matured.\" This root’s focus on timing and maturity adds depth to \"أَنَّىٰ,\" linking it to inquiries about how and why something occurred, with an emphasis on the development or timing of events. The connection reflects the idea of questioning the manner or origin of something, in line with the root’s meaning of maturation and finality.",
  "370": "أَنْعَمَ and related words stem from the root ن-ع-م, with the root verb نَعِمَ meaning \"he was at ease,\" \"he enjoyed comfort.\" أَنْعَمَ means \"he bestowed favor\" or \"he granted blessings.\" The focus is on the act of granting bounties broadly, including both tangible and intangible blessings, often referring to Allah’s (ﷻ) divine generosity in the Qur'anic context. This term reflects the root's emphasis on ease and enjoyment, highlighting gratitude for bestowed blessings and the all-encompassing nature of divine favors.",
  "371": "أَنْبَأَ and related words stem from the root ن-ب-أ, with the root verb نَبَأَ meaning \"he informed,\" \"he brought news,\" or \"he announced.\" أَنْبَأَ means \"he informed\" or \"he caused someone to be informed,\" emphasizing the deliberate act of ensuring important information is shared. The root conveys themes of communication, significance, and impact, focusing on the transmission of knowledge or truths that shape understanding and decisions. أَنْبَأَ highlights the role of purposeful communication in conveying meaningful and impactful news.",
  "372": "أَنْبَتَ and related words stem from the root ن-ب-ت, with the root verb نَبَتَ meaning \"it grew,\" \"it sprouted,\" or \"it emerged.\" أَنْبَتَ means \"He caused to grow\" or \"He brought forth growth,\" emphasizing the initiation of development. The root also conveys themes of natural emergence, flourishing, and the nurturing of life, particularly in the context of vegetation. In classical usage, it extends to all that grows from the earth by Allah’s (ﷻ) will, illustrating His power in initiating and sustaining creation. This highlights divine care not only in physical growth but also in spiritual and moral development, reflecting the comprehensive nature of Allah’s (ﷻ) sustenance and guidance.",
  "373": "أَهَانَ and related words stem from the root ه-و-ن, with the root verb هَانَ meaning \"he was despised\" or \"he became insignificant.\" أَهَانَ means \"he humiliated\" or \"he degraded.\" The connection lies in actively causing someone to become lowly or contemptible, directly relating to the root’s focus on lowness and insignificance.",
  "374": "أَهَمَّتْ and related words stem from the root ه-م-م, with the root verb هَمَّ meaning \"he intended,\" \"he desired,\" or \"he was concerned.\" أَهَمَّتْ means \"she/it caused worry or anxiety,\" reflecting an external force inducing mental unease or preoccupation. The root conveys meanings of forming plans, engaging in deep thought, or experiencing care and anxiety. The connection lies in the transition from the internal state of intention or concern to an external influence that creates worry. This term highlights the interplay between internal emotions and external provocations, emphasizing the fragility of the human mind when faced with trials and the need to remain anchored in resilience and faith.",
  "375": "أَهُشُّ and related words stem from the root ه-ش-ش, with the root verb هَشَّ meaning \"he shook (branches),\" \"he was cheerful,\" or \"he was lively.\" أَهُشُّ means \"I beat down leaves\" or \"I shake branches to cause leaves to fall.\" This term captures the root’s emphasis on active motion and vitality, specifically in the context of using a staff to gently dislodge leaves for livestock to feed on. The action reflects care, provision, and attentiveness, highlighting the relationship between human effort and sustenance. The root further embodies themes of energy, dynamism, and the purposeful actions required to nurture and support others.",
  "376": "أَهِلَّةٌ and related words stem from the root ه-ل-ل, with the root verb هَلَّ meaning \"it appeared\" or \"he pronounced.\" هِلَالٌ refers to the \"crescent moon,\" specifically its initial visibility at the beginning of a lunar month, and أَهِلَّةٌ is its plural form, meaning \"crescent moons\" or \"new moons.\" The root emphasizes emergence, visibility, and declaration, aligning with the significance of the new moon's appearance in marking time and cycles.",
  "377": "أَهْدَىٰ and related words stem from the root ه-د-ي, with the root verb هَدَىٰ meaning \"he guided\" or \"he led aright.\" أَهْدَىٰ means \"more guided\" or \"better guided,\" emphasizing a comparative state of being closer to the correct path. This term reflects the idea of heightened guidance and aligns with the root’s themes of clarity and direction. Often used to signify progress toward truth and enlightenment, أَهْدَىٰ also highlights Allah's (ﷻ) role as the ultimate source of superior guidance that brings creation closer to righteousness.",
  "378": "أَهْلٌ and related words stem from the root أ-ه-ل, with the root verb أَهَلَ meaning \"he became fit\" or \"he was suitable.\" It also encompasses meanings like \"he became sociable,\" \"he entered upon marriage,\" or \"he adapted to a situation.\" أَهْلٌ refers to \"family,\" \"household,\" or \"close kin.\" The connection lies in the concept of suitability, familiarity, and belonging, reflecting those most fittingly connected to an individual through kinship, shared residence, or close association. This term highlights the strength of family bonds, mutual rights, responsibilities, and familiarity that bind individuals together.",
  "379": "أَهْلَكَ and related words stem from the root ه-ل-ك, with the root verb هَلَكَ meaning \"he perished,\" \"he died,\" or \"he was destroyed.\" أَهْلَكَ means \"he destroyed\" or \"he caused to perish,\" extending the meaning beyond individuals to include the destruction of wealth, property, or other possessions. The term emphasizes the act of causing ruin or bringing something to an end, whether through deliberate action or neglect. It reflects themes of annihilation, loss, and the fragility of worldly matters, highlighting the power to bring about both physical and metaphorical demise.",
  "380": "أَهْوَاءٌ and related words stem from the root ه-و-ى, with the root verb هَوَىٰ meaning \"he fell,\" \"he descended,\" or \"he desired passionately.\" هَوًى means \"desire,\" \"whim,\" or \"passion,\" while أَهْوَاءٌ, the plural, means \"desires\" or \"passions,\" encompassing multiple inclinations or whims. The root conveys themes of falling or inclining, both physically and metaphorically, emphasizing the human tendency to be drawn toward personal wants. In the Qur'an, following one's desires is cautioned against, as it can lead individuals astray, highlighting the importance of self-control and adherence to Allah's (ﷻ) guidance.",
  "381": "أَهْوَنُ and related words stem from the root ه-و-ن, with the root verb هَانَ meaning \"he was easy\" or \"he was insignificant.\" أَهْوَنُ means \"easier\" or \"less severe.\" The connection lies in comparing levels of difficulty or significance, directly reflecting the root’s emphasis on relative ease or simplicity. This term highlights the notion of one thing being less burdensome or more manageable compared to another.",
  "382": "أَوَّابٌ and related words stem from the root أ-و-ب, with the root verb آبَ meaning \"he returned\" or \"he came back.\" أَوَّابٌ is an intensive form meaning \"one who constantly returns or repents.\" This term conveys a continuous act of returning to Allah (ﷻ) in repentance and remembrance, reflecting a deep spiritual commitment. It emphasizes the root’s essence of returning, highlighting the importance of repeatedly turning back to Allah (ﷻ) for forgiveness and guidance.",
  "383": "أَوَّاهٌ and related words stem from the root أ-و-ه, with the root verb أَوَّهَ meaning \"he sighed\" or \"he groaned.\" أَوَّاهٌ is an intensive form meaning \"one who sighs often,\" \"compassionate,\" or \"tender-hearted,\" reflecting the frequent expression of deep emotion. This word highlights a person's sensitivity and sincere responsiveness to spiritual and moral concerns. In the Qur'an, أَوَّاهٌ describes Prophet Abraham (ﷺ), emphasizing his deep piety, compassion, and empathy for others. The term signifies a believer's profound awareness, heartfelt prayer, and confidence in Allah (ﷻ), highlighting the importance of empathy and devotion in a believer’s life.",
  "384": "أَوَّلٌ and related words stem from the root أ-و-ل, with the root verb آلَ meaning \"he returned\" or \"he resorted to,\" and أَوِلَ meaning \"he was first, foremost, or preceded.\" أَوَّلٌ means \"first\" or \"foremost,\" capturing the sense of returning to the origin or initial point. It can also refer to former people or earlier generations. ٱلأوَّلُ, one of Allah’s (ﷻ) beautiful names, means \"The First\" or \"The One Who Came Before All,\" signifying Allah’s (ﷻ) pre-existence as the beginning and source of all things, with nothing preceding Him. This name highlights Allah’s (ﷻ) eternal primacy, reminding us that all creation originates from Him and that He is to be placed foremost in our lives as the ultimate source and guide.",
  "385": "أَوِّبِي and related words stem from the root أ-و-ب, with the root verb آبَ meaning \"he returned\" or \"he came back.\" أَوِّبِي means \"echo\" \"repeat\" or \"return\" specifically in the context of praises to Allah (ﷻ). In the Qur'an, it is a command to the mountains and birds to join Prophet David (ﷺ) in echoing praises. The connection lies in the concept of \"returning\" praises to Allah (ﷻ), symbolizing harmony in creation and embodying the root’s themes of return, repetition, and continuous reverence. This cyclical act reflects how all of creation \"returns\" to praising Allah (ﷻ) in the manner He deserves.",
  "386": "أَوْبَارٌ and related words stem from the root و-ب-ر, with the root verb وَبَرَ meaning \"it was covered with hair\" or \"it grew hair.\" أَوْبَارٌ (plural of وَبَرٌ) refers specifically to \"camel hair,\" though it can also denote coarse hair of other animals. The root conveys themes of growth, coverage, and natural provision, emphasizing the abundance of hair or fur as a protective and functional covering on animals. أَوْبَارٌ highlights the utility of such resources, particularly camel hair, which has been used traditionally for making tents, ropes, and other furnishings. This term highlights both the sufficiency and generosity of Allah’s (ﷻ) blessings in creation.",
  "387": "أَوْتَادٌ and related words stem from the root و-ت-د, with the root verb وَتَدَ meaning \"he fixed\" or \"he fastened firmly.\" أَوْتَادٌ is the plural of وَتَدٌ, meaning \"stakes,\" \"pegs,\" or \"nails.\" The connection lies in objects used to secure or anchor something firmly in place, directly reflecting the root's emphasis on fastening. In the Qur'an, mountains are sometimes referred to as أَوْتَادٌ (pegs), symbolizing their role in stabilizing the earth and highlighting the concept of firmness and stability.",
  "388": "أَوْثَانٌ and related words stem from the root و-ث-ن, with the root verb وَثَنَ meaning \"he fashioned\" or \"he carved an idol.\" أَوْثَانٌ is the plural of وَثَنٌ, meaning \"idols\" or \"graven images.\" The connection lies in the act of carving or shaping physical representations for worship, directly reflecting the root's emphasis on fashioning idols. This term is associated with idolatry, highlighting the prohibition against worshipping created images instead of Allah (ﷻ).",
  "389": "أَوْجَسَ and related words stem from the root و-ج-س, with the root verb وَجَسَ meaning \"he felt secretly\" or \"he perceived.\" أَوْجَسَ means \"he felt apprehension,\" \"he conceived fear,\" or \"he sensed inwardly.\" The connection lies in experiencing a subtle or inner feeling, directly relating to the root's emphasis on hidden perception. This term conveys the sense of concealed emotions or intuitions, highlighting internal reactions to situations.",
  "390": "أَوْجَفَ and related words stem from the root و-ج-ف, with the root verb وَجَفَ meaning \"it palpitated,\" \"it moved quickly,\" or \"it trembled.\" أَوْجَفَ means \"he rapidly moved,\" \"he swiftly advanced,\" or \"he made to move quickly,\" emphasizing the act of inciting swift motion. The root conveys themes of agitation, rapidity, and urgency, often linked to quick or forceful movement. The term is frequently associated with urging animals like horses or camels into action, reflecting deliberate speed and intensity, embodying hastened movement driven by urgency.",
  "391": "أَوْحَى and related words stem from the root و-ح-ى, with the root verb وَحَى meaning \"he revealed,\" \"he signaled,\" or \"he inspired.\" أَوْحَى means \"he inspired,\" \"he revealed,\" or \"he communicated by inspiration.\" The connection lies in the act of conveying a message subtly or divinely, directly reflecting the root's emphasis on inspiration. This term is often used to describe divine revelation from Allah (ﷻ) to His prophets, emphasizing the sacred and subtle nature of this communication.",
  "392": "أَوْدِيَةٌ and related words stem from the root و-د-ي, with the root verb وَدَى meaning \"it flowed\" or \"it went.\" أَوْدِيَةٌ is the plural of وَادٍ (وَادِي) meaning \"valley.\" The connection lies in valleys being pathways through which water flows, directly relating to the root's concept of movement and flow. Valleys channel life-giving water, symbolizing sustenance and the journey of life. In classical Arabic and the Qur'an, valleys often represent passages or trials that one must navigate, emphasizing the importance of guidance and perseverance.",
  "393": "أَوْرَثَ and related words stem from the root و-ر-ث, with the root verb وَرِثَ meaning \"he inherited.\" أَوْرَثَ means \"He caused to inherit\" or \"He bestowed as inheritance.\" This form signifies the act of granting or passing on inheritance to others, connecting to the root's concept of legacy and succession. In the Qur'an, Allah (ﷻ) is described as the One who bestows inheritance, both material and spiritual, emphasizing His sovereignty and the transient stewardship of human ownership.",
  "394": "أَوْرَدَ and related words stem from the root و-ر-د, with the root verb وَرَدَ meaning \"he came,\" \"he arrived,\" or \"he approached.\" أَوْرَدَ means \"he brought\" or \"he caused to arrive.\" This form signifies the action of leading or bringing something to a place or state, connecting to the root's concept of approaching a destination. It emphasizes the role of facilitating movement or transition, whether physically or metaphorically, such as guiding others toward knowledge or outcomes.",
  "395": "أَوْزِعْ and related words stem from the root و-ز-ع, with the root verb وَزَعَ meaning \"he restrained\" or \"he controlled.\" أَوْزِعْ means \"enable\" or \"inspire.\" The connection lies in prompting someone to hold back or to instill discipline, reflecting the root's focus on control and regulation. In the Qur'an, it can be a supplication for guidance to remain steadfast in good deeds, highlighting the desire for divine assistance in self-restraint and righteous action.",
  "396": "أَوْسَطُ and related words stem from the root و-س-ط, with the root verb وَسَطَ meaning \"he was in the middle\" or \"he was moderate.\" أَوْسَطُ means \"middle,\" \"most moderate,\" or \"best.\" The connection lies in occupying a central or balanced position, reflecting the root's concept of moderation and excellence. In the Qur'an, it describes the Muslim community as a \"middle nation\" (أُمَّةً وَسَطًا), emphasizing balance, justice, and moderation as key virtues in Islam.",
  "397": "أَوْصَى and related words stem from the root و-ص-ي, with the root verb وَصَّى meaning \"he enjoined\" or \"he advised earnestly.\" أَوْصَى means \"he enjoined,\" \"he commanded,\" or \"he made a will.\" The connection to the root emphasizes the action of giving directives or important advice, particularly regarding responsibilities or bequests. It reflects the seriousness and obligation associated with the instructions given, often in the context of final wills or important commandments.",
  "398": "أَوْضَعَ and related words stem from the root و-ض-ع, with the root verb وَضَعَ meaning \"he placed\" or \"he set down.\" أَوْضَعَ means \"he hastened\" or \"he sped up,\" especially in travel. The connection to the root involves the idea of causing something to be set in motion quickly or lowering oneself into rapid movement. It reflects the act of increasing speed or urging oneself or others to move swiftly, highlighting urgency and promptness.",
  "399": "أَوْعَى and related words stem from the root و-ع-ى, with the root verb وَعَى meaning \"he comprehended\" or \"he retained.\" أَوْعَى means \"he gathered,\" \"he stored.\" The connection lies in the deliberate act of collecting or storing, whether information, wealth, or goods, or even keeping thoughts and intentions within oneself, reflecting a conscious effort to retain and preserve. In some contexts, it conveys a negative aspect, emphasizing the excessive accumulation of wealth and the moral implications of hoarding without benefit to others.",
  "400": "أَوْفَىٰ and related words stem from the root و-ف-ى, with the root verb وَفَىٰ meaning \"he fulfilled\" or \"he completed.\" أَوْفَىٰ means \"he fulfilled completely\" or \"he gave in full,\" emphasizing the deliberate and intentional action of ensuring obligations are met. This connection highlights thoroughness in fulfilling commitments, reflecting the root's focus on completeness and faithfulness. It conveys the importance of not just meeting commitments but doing so with intentionality and sincerity, reinforcing integrity and trustworthiness.",
  "401": "أَوْلَىٰ and related words stem from the root و-ل-ي, with the root verb وَلِيَ meaning \"he was near,\" \"he befriended,\" or \"he protected.\" أَوْلَىٰ means \"more deserving\" or \"closer,\" reflecting proximity in terms of physical nearness, rights, or responsibilities. The root conveys concepts of nearness, guardianship, authority, and relational responsibility. The connection lies in the root’s focus on closeness and priority, emphasizing precedence or entitlement due to stronger ties, greater relevance, or rightful authority.",
  "402": "أَوْلَيَانِ and related words stem from the root و-ل-ي, with the root verb وَلِيَ meaning \"he was near,\" \"he befriended,\" or \"he governed.\" The root conveys broader concepts of nearness, guardianship, authority, and relational responsibility. أَوْلَيَانِ means \"two close ones\" or \"two individuals more entitled,\" emphasizing proximity in relationship or responsibility. The connection lies in the root’s focus on nearness and trust, highlighting the bond between individuals closely tied by friendship, guardianship, or rightful duty.",
  "403": "أَوْهَنَ and related words stem from the root و-ه-ن, with the root verb وَهَنَ meaning \"he weakened\" or \"he became feeble.\" أَوْهَنَ means \"weaker\" or \"weakest,\" reflecting the root's concept of frailty and diminished strength. It emphasizes heightened vulnerability and inevitable failure, describing something inherently unstable and bound to collapse.",
  "404": "أَيَامَىٰ and related words stem from the root أ-ي-م, with the root verbs آمَ (for men) and آمَتْ (for women), meaning \"he had no wife\" or \"he lost his wife by death,\" and \"she had no husband\" or \"she lost her husband by death.\" أَيْمَانُ refers to a man whose wife has died, and أَيْمَىٰ to a woman whose husband has died. أَيَامَىٰ is the plural form, encompassing both terms and meaning \"those whose spouses have died.\" The connection lies in a state of singleness or detachment, reflecting the root’s concept of being unaccompanied or separated.",
  "405": "The pronoun أَيٌّ means \"which\" or \"what\" and is used to ask questions that require specification or clarification. It serves to pinpoint particular details or distinctions, emphasizing precision and clarity in communication. This word encourages thoughtful inquiry, guiding the seeker toward a more accurate understanding of the subject at hand. Its use reflects the value of asking clear and purposeful questions to promote deeper insight and foster meaningful dialogue, highlighting the importance of mindful exploration in the pursuit of knowledge.",
  "406": "أَيَّدَ and related words stem from the root أ-ي-د, with the root verb آدَ meaning \"he was strong\" or \"he possessed strength.\" أَيَّدَ means \"he supported\" or \"he strengthened,\" particularly in the sense of empowering or reinforcing. This connection emphasizes stability and steadfastness, reflecting the idea of bolstering someone physically, morally, or spiritually to make them resolute and resilient. In the Qur'an, أَيَّدَ describes how Allah (ﷻ) strengthens His prophets and believers, highlighting divine empowerment, resilience, and the unwavering support provided to those under Allah’s (ﷻ) care.",
  "407": "أَيُّوبُ stems from the root أ-و-ب, with the verb آبَ meaning \"he returned\" or \"he repented.\" أَيُّوبُ is the name of Prophet Job (ﷺ), renowned for his patience and unwavering faith during severe trials. The connection lies in his continual \"return\" to Allah (ﷻ) through prayer and steadfastness, embodying the essence of turning back to Allah (ﷻ) in hardship. His story teaches that patience and repentance are pathways to Allah’s (ﷻ) mercy and relief.",
  "408": "أَيْقَاظٌ and related words stem from the root ي-ق-ظ, with the root verb يَقِظَ meaning \"he was awake\" or \"he became alert.\" أَيْقَاظٌ means \"those who are awake\" or \"vigilant ones,\" reflecting a heightened state of awareness. The root conveys broader concepts of awareness, vigilance, and attentiveness, emphasizing the state of being conscious and alert to one’s surroundings or circumstances. The connection lies in embodying the root's emphasis on mental and spiritual alertness, highlighting the value of being perceptive and prepared, both physically and spiritually.",
  "409": "أَيْكَةُ and related words stem from the root أ-ي-ك, with the root verb أَيَكَ meaning \"it was dense\" or \"it intertwined,\" often referring to trees or vegetation. أَيْكَةُ refers to a dense thicket or tangled grove, characterized by intertwined branches forming a thick, lush area. In the Qur'an, the people of Al-Aykah are described as the \"People of the Thicket,\" referring to their dwelling in such dense vegetation. The root emphasizes themes of intertwining, enclosure, and density, symbolizing both the physical environment they inhabited and their moral state. The connection lies in their entanglement in disbelief and moral corruption, akin to being ensnared in a dense thicket.",
  "410": "أَيْمَنُ and related words stem from the root ي-م-ن, with the root verb يُمِنَ meaning \"he was prosperous\" or \"he was fortunate.\" أَيْمَنُ means \"right side,\" often used in contexts of favor, blessings, or spatial description. The root conveys broader concepts of prosperity, blessings, favor, and positive outcomes. The connection lies in the right side being associated with fortune and well-being, reflecting the root’s emphasis on success and favorable outcomes.",
  "411": "The particle أَيْنَ means \"where,\" used to inquire about a location. It shares the root أ-ي-ن with the verb آنَ, meaning \"its time came.\" This connection highlights the relationship between presence and timing. While أَيْنَ asks about a specific place, \"آنَ\" signifies the culmination of time, emphasizing the importance of knowing both where something is and when it occurs. In classical texts, أَيْنَ encourages reflection on one's current physical and spiritual state, promoting self-awareness and contemplation of one's path.",
  "412": "أَيْدٍ (also written as أَيْيۡدٍ) and related words stem from the root أ-ي-د, with the root verb آدَ meaning \"he was strong\" or \"he possessed strength.\" أَيْدٍ translates as \"strength\" or \"power.\" The connection lies in the idea of resilience, stability, and firm support, emphasizing the root’s themes of empowerment and steadfastness. This word reflects not only physical strength but also a broader sense of support and reinforcement, highlighting an enduring and inherent power.",
  "413": "أُبْسِلُوا and related words stem from the root ب-س-ل, with the root verb بَسَلَ meaning \"he exposed him to destruction or evil as a consequence of his crime or sin\" or \"he surrendered him into the custody of another.\" أُبْسِلُوا is a passive form, meaning \"they were surrendered\" or \"they were exposed.\" This form suggests being given over to a consequence or fate, often implying helplessness or abandonment to one's actions. In a broader sense, أُبْسِلُوا reflects the idea of being left to face inevitable consequences, often as a result of wrongdoing, with no intervention to prevent the outcome.",
  "414": "أُتْرِفُوا and related words stem from the root ت-ر-ف, with the root verb تَرِفَ meaning \"he lived in luxury,\" \"he enjoyed a life of ease and plenty,\" or \"he indulged himself in pleasures and desires.\" أُتْرِفُوا is a passive form meaning \"they were given luxuries,\" reflecting a state of comfort that often leads to heedlessness. This root implies that excessive ease can foster complacency and moral decline, where material abundance blinds one to humility and responsibility.",
  "415": "أُجَاجٌ and related words stem from the root أ-ج-ج, with the root verb أَجَّ meaning \"it burned fiercely\" or \"it was intense.\" أُجَاجٌ means \"bitter,\" \"salty,\" or \"undrinkable,\" typically describing water unpalatable due to its salinity or bitterness. The connection lies in the intensity and harshness of the taste, aligning with the root's emphasis on fierceness and burning. Just as fire is fierce and consuming, the taste of intensely bitter or salty water overwhelms the senses, making it unfit for consumption.",
  "416": "أُجِيبَت and related words stem from the root ج-و-ب, with the root verb جَابَ meaning \"he cut through\" or \"he pierced.\" The root broadly conveys meanings of cutting, piercing, breaking through, or creating a path. أَجَابَ means \"he answered,\" and أُجِيبَت is a passive form meaning \"it was answered.\" The connection lies in the way an answer metaphorically cuts through uncertainty, confusion, or doubt, much like piercing through a barrier. This highlights how receiving a response brings clarity, resolution, and guidance, whether addressing one’s inquiries or fulfilling prayers.",
  "417": "أُحْصِرُوا and related words stem from the root ح-ص-ر, with the root verb حَصَرَ meaning \"he confined,\" \"he restricted,\" or \"he besieged.\" أُحْصِرُوا is a passive form meaning \"they were prevented\" or \"they were confined,\" reflecting a state of being restricted or held back. The root conveys themes of enclosure, limitation, and being hemmed in, often with an emphasis on obstacles or pressures. In a broader sense, it includes being prevented from physical movement, hindered by circumstances, or overwhelmed by difficulties. This connection highlights the experience of being obstructed from fulfilling intentions, emphasizing the interplay between effort, external barriers, and the resulting limitation.",
  "418": "أُحْكِمَتْ and related words stem from the root ح-ك-م, with the root verb حَكَمَ meaning \"he judged\" or \"he governed.\"  أُحْكِمَتْ is a passive form meaning \"it was made firm\" or \"it was perfected,\" reflecting the process of something being established with precision, wisdom, and stability. The root also conveys meanings of restraining, controlling, making firm, and ensuring precision in action or decision. This ties back to the root's focus on judgment, governance, and the deliberate application of control and balance to achieve perfection and reliability.",
  "419": "أُخْتٌ and related words stem from the root أ-خ-و, with the root verb آخَى meaning \"he took as a brother\" or \"he fraternized,\" describing the formation of a brotherly bond. Sharing the same root as أَخٌ (brother), أُخْتٌ means \"sister,\" referring to a female sibling or a close female associate. The root emphasizes familial ties, unity, and mutual support. In Islamic teachings, the term also extends to sisterhood among believers, highlighting the importance of compassion, solidarity, and cooperation among women in the community.",
  "420": "أُخْدُودٌ and related words stem from the root خ-د-د, with the root verb خَدَّ meaning \"he dug\" or \"he furrowed.\" أُخْدُودٌ means \"trench\" or \"ditch,\" referring to a long, narrow excavation in the ground. The root conveys meanings of engraving, marking, and creating visible impressions, often linked to permanence or depth. The connection lies in how أُخْدُودٌ is the lasting imprint of digging, a deep groove or channel that alters the landscape, emphasizing the idea of something carved into existence with force and permanence.",
  "421": "أُخْفِيَ and related words stem from the root خ-ف-ي, with the root verb خَفِيَ meaning \"he or it was hidden or concealed\" or \"he or it became unapparent.\" أُخْفِيَ is a passive form meaning \"it was concealed\" or \"it was hidden.\" The root encompasses themes of hiding, concealing, or making something unseen, whether physically, metaphorically, or spiritually. It conveys the idea of keeping something secret, shrouded, or beyond direct perception.",
  "422": "أُدْخِلَ and related words stem from the root د-خ-ل, with the root verb دَخَلَ meaning \"he entered.\" أُدْخِلَ is a passive form meaning \"he was made to enter\" or \"he was admitted.\" The root revolves around entry, penetration, mixture, and involvement, conveying both physical entry and metaphorical engagement. Just as something that enters becomes part of a space or situation, this word reflects the idea of being brought into a place, state, or condition—whether willingly or by external force—emphasizing transition and integration.",
  "423": "أُذُنٌ and related words stem from the root أ-ذ-ن, with the root verb أَذِنَ meaning \"he listened\" or \"he permitted.\" أُذُنٌ means \"ear,\" the organ of hearing. The connection is direct, as the ear is crucial for listening, embodying the root's emphasis on receiving sounds and information. This term highlights the importance of attentiveness and the ability to perceive and understand through hearing.",
  "424": "أُزْلِفَتْ and related words stem from the root ز-ل-ف, with the root verb زَلَفَ meaning \"he approached\" or \"he brought near.\" أُزْلِفَتْ is a passive form meaning \"it was brought near\" or \"it was made to approach.\" The root also conveys meanings of closeness, advancement, or being drawn near in position or time. The connection lies in something being drawn close or made accessible, reflecting the root's emphasis on nearness and advancement. It often refers to the Day of Judgment or Paradise being brought near to the righteous, symbolizing the culmination of reward and closeness to divine favor.",
  "425": "أُسْوَةٌ and related words stem from the root أ-س-و, with the root verb أَسَا meaning \"he treated a wound,\" \"he remedied,\" or \"he made peace.\" أُسْوَةٌ means \"an example,\" \"a model,\" or \"a pattern to be followed.\" The connection lies in the root's concept of healing and consolation, suggesting that following a good example acts as a remedy or comfort. أُسْوَةٌ implies that the person being followed offers solace, guidance, and a path to moral and spiritual healing. In the Qur'an, أُسْوَةٌ refers to the Prophet Muhammad (ﷺ), Prophet Abraham (ﷺ), and their companions as exemplary models, highlighting the importance of following in their footsteps to attain righteousness and solace in faith.",
  "426": "أُشْرِبَ and related words stem from the root ش-ر-ب, with the root verb شَرِبَ meaning \"he drank.\" أُشْرِبَ is a passive form, meaning \"he was made to drink\" or \"it was infused.\" The root conveys the idea of drinking, which is an act of absorbing something necessary for sustenance. In the case of أُشْرِبَ, it emphasizes not just the physical act of drinking but also the deeper metaphorical absorption of something, whether it be an idea, emotion, or desire. This reflects how something can be so deeply ingrained or infused into a person’s heart or mind, much like a liquid is absorbed into the body when consumed.",
  "427": "أُصْلِي and related words stem from the root ص-ل-ي, with the root verb صَلِيَ meaning \"he was burned\" or \"he was exposed to fire.\" أُصْلِي means \"I will burn\" or \"I will cause to burn.\" The connection lies in the act of being subjected to or causing exposure to heat or fire. The root emphasizes the act of burning, whether in the sense of enduring fire or using it as a means to affect something else. This form reflects an active role in either being affected by or inducing the burning process, signifying the intensity of fire’s effect. The use of أُصْلِي conveys an intentional or future act of burning or being subjected to fire, which is central to the root's thematic focus on heat and destruction.",
  "428": "أُعِيدُوا and related words stem from the root ع-و-د, with the verb عَادَ meaning \"he returned\" or \"he reverted.\" أُعِيدُوا means \"you all return\" or \"you all are made to return,\" emphasizing the act of returning or reverting to a previous state or condition. The connection lies in the root's focus on returning, suggesting a collective action of coming back or repeating something, whether in terms of action, place, or practice. This term highlights the process of returning, often with the implication of restoration or repetition.",
  "429": "أُعِيذُ and related words stem from the root ع-و-ذ, with the root verb عَاذَ meaning \"he sought refuge.\" أَعَاذَ means \"he granted refuge\" or \"he protected,\" while أُعِيذُ means \"I seek to protect\" or \"I seek refuge for.\" The connection lies in seeking or providing protection, reflecting the root's focus on refuge and safety. This term emphasizes invoking Allah's (ﷻ) protection over oneself or others, highlighting reliance on His safeguarding and care.",
  "430": "أُغْرِقُوا and related words stem from the root غ-ر-ق, with the root verb غَرِقَ meaning \"he was drowned\" or \"he sank.\" أُغْرِقُوا means \"they were drowned,\" emphasizing the passive nature of being overwhelmed or submerged by water. This term reflects the root's themes of complete submersion and overpowering forces, symbolizing the inescapable and total nature of such an event. It highlights the state of being engulfed, whether physically in water or metaphorically in circumstances beyond one’s control.",
  "431": "أُغْشِيَتْ and related words stem from the root غ-ش-و, with the root verb غَشِيَ meaning \"he covered,\" \"he enveloped,\" or \"he came over (someone).\" أُغْشِيَتْ is a passive form meaning \"she was covered\" or \"it was enveloped.\" The connection lies in the act of being covered or enveloped, directly relating to the root's meaning of covering or overshadowing. This term may describe darkness covering the land or a veil being placed over something, emphasizing transformation or concealment that occurs.",
  "432": "أُفَوِّضُ and related words stem from the root ف-و-ض, with the root verb فَوَّضَ meaning \"he entrusted\" or \"he consigned.\" أُفَوِّضُ means \"I entrust\" or \"I delegate.\" The connection emphasizes handing over matters to someone else, reflecting reliance and trust. In the Qur'an, it denotes entrusting one's affairs to Allah (ﷻ), acknowledging His supreme authority and wisdom.",
  "433": "أُفُقٌ and related words stem from the root أ-ف-ق, with the root verb أَفَقَ meaning \"to travel or go away into the land.\" أُفُقٌ means \"horizon,\" referring to the sides, borders, or extremities of the earth. The connection suggests a natural alignment between journeying outward and the concept of the horizon, emphasizing vastness and breadth, symbolizing the immense scope of creation and the unknown that lies ahead. In the Qur'an, أُفُقٌ reflects the grandeur of Allah’s (ﷻ) creation, fostering a sense of awe and humility before His limitless power.",
  "434": "أُفِكَ and related words stem from the root أ-ف-ك, with the root verb أَفَكَ meaning \"he turned away,\" \"he lied,\" or \"he changed his/its manner of being.\" أُفِكَ is a passive form, meaning \"he was turned away,\" \"he was deceived,\" or \"he was misled.\" This form highlights the state of deviation from the truth, emphasizing being turned away or misled. It serves as a reminder to be vigilant against falsehood, stressing the importance of discernment and steadfastness in following the Qur'an and Sunnah.",
  "435": "أُفٌّ and related words stem from the root أ-ف-ف, with the root verb أَفَّ meaning \"he expressed disgust\" or \"he showed annoyance.\" أُفٌّ is an exclamation similar to \"ugh\" and also refers to dirt or filth. While it directly expresses irritation, the connection to filth suggests that saying أُفٌّ is not just a reaction but also something undesirable. Just as filth is avoided, using أُفٌّ reflects disrespect and negativity, especially toward others. This emphasizes how expressing annoyance in this manner, even mildly, is seen as dishonorable and harmful, akin to impurity in behavior.",
  "436": "أُقِّتَتْ and related words stem from the root و-ق-ت, with the root verb وَقَتَ meaning \"he fixed a time\" or \"he appointed.\" أُقِّتَتْ is a passive form meaning \"it was appointed\" or \"it was fixed in time.\" The connection lies in the precise determination of a specific time for an event, reflecting the root's emphasis on timing and scheduling. This term highlights the concept of predestination and the importance of appointed times in the unfolding of events, reflecting divine planning and order.",
  "437": "أُكُلٌ and related words stem from the root أ-ك-ل, with the root verb أَكَلَ meaning \"he ate\" or \"he consumed.\" أُكُلٌ means \"produce,\" \"yield,\" \"fruit,\" or \"food,\" referring to that which is consumed. The connection transforms the root's action of eating into the object of consumption, highlighting the provisions and sustenance granted. In the Qur'an, أُكُلٌ often describes the bounties of Paradise or on earth, emphasizing Allah's (ﷻ) abundant provision in both this life and the hereafter.",
  "438": "أُكْرِهَ and related words stem from the root ك-ر-ه, with the root verb كَـرِهَ meaning \"he disliked\" or \"he hated.\" أُكْرِهَ is a passive form meaning \"he was compelled\" or \"he was forced.\" This term emphasizes the state of being subjected to actions or circumstances against one’s will. The connection lies in the root’s concept of aversion or reluctance, highlighting the experience of coercion as a violation of personal freedom and choice. In classical usage, أُكْرِهَ is often tied to moral and legal discussions, such as the permissibility of certain actions performed under duress, highlighting the profound impact of compulsion on human autonomy and ethical responsibility.",
  "439": "أُمٌّ and related words stem from the root أ-م-م, with the root verb أَمَّ meaning \"he intended,\" \"he aimed at,\" \"he directed his course toward,\" or \"he led.\" أُمٌّ means \"mother\" and also signifies \"the foundation or basis of anything,\" as well as \"a place of habitation or abode.\" The connection lies in the mother’s role as a central, nurturing figure to whom one is closely tied, embodying the root’s emphasis on centrality and direction. These meanings highlight أُمٌّ as both a guiding foundation and a place of close connection where one remains—reflecting a relationship of lasting significance.",
  "440": "أُمَّةٌ and related words stem from the root أ-م-م, with the root verb أَمَّ meaning \"he intended,\" \"he aimed at,\" \"he directed his course toward,\" or \"he led.\" أُمَّةٌ holds meanings such as \"a way of life,\" \"a path people follow in religion,\" \"a nation, people, or community,\" \"a generation,\" \"one who follows the true religion,\" or \"a period of time.\" The connection lies in the root’s emphasis on direction and unity of purpose, as أُمَّةٌ reflects a collective bound by shared beliefs or goals. Whether describing a group, a shared path, or an era, أُمَّةٌ conveys a unified course and identity shaped by purpose.",
  "441": "أُمِّيٌّ and related words stem from the root أ-م-م, with the root verb أَمَّ meaning \"he intended,\" \"he aimed at,\" \"he directed his course toward,\" or \"he led.\" أُمِّيٌّ refers to someone who has not learned reading or writing, thereby remaining in a natural state as originally birthed by the mother (أُمٌّ). This term is often translated as \"unlettered.\" The connection lies in remaining in one’s original, unaltered state from birth, reflecting the root’s broader concept of staying true to one’s origin or essential state.",
  "442": "أُمْطِرَتْ and related words stem from the root م-ط-ر, with the root verb مَطَرَ meaning \"it rained.\" أُمْطِرَتْ is a passive form meaning \"it was rained upon\" or \"it received rain,\" emphasizing the act of rain being bestowed upon a place. This reflects the dual nature of the root's concept, as rain can serve as a source of nourishment, fostering growth and sustenance, or, in certain contexts, as a manifestation of divine retribution. The term highlights the profound impact of rain, symbolizing both blessing and warning, depending on the context in which it is experienced.",
  "443": "أُمْنِيَّةٌ stems from the root م-ن-ي, with the root verb مَنَى meaning \"he wished\" or \"he desired.\" أُمْنِيَّةٌ refers to \"a wish,\" \"a desire,\" or \"an aspiration,\" representing what one hopes to achieve. The root also encompasses meanings like \"to measure\" or \"to determine,\" linking aspirations to the idea of deliberate and measured goals. In classical usage, it can also mean \"recitation\" or \"utterance,\" emphasizing the expression of one’s wishes through speech. This term embodies the human inclination to articulate and pursue aspirations, whether through longing or spoken word.",
  "444": "أُنثَىٰ and related words stem from the root أ-ن-ث, with the root verb أَنُثَ meaning \"it was feminine\" or \"it was soft and delicate.\" أُنثَىٰ translates to \"female.\" The connection lies in qualities associated with femininity, reflecting the root’s emphasis on softness, gentleness, and nurturing. This term denotes gender, highlighting the diversity and balance within creation.",
  "445": "أُنثَيَيْنِ and related words stem from the root أ-ن-ث, with the root verb أَنُثَ meaning \"it was feminine\" or \"it was soft and delicate.\" أُنثَيَيْنِ is the dual form of أُنثَىٰ, meaning \"two females.\" The connection lies in the root’s association with gentleness and softness, here expressed in a dual form.",
  "446": "أُهِلَّ and related words stem from the root ه-ل-ل, with the root verb هَلَّ meaning \"he pronounced,\" \"he cried out,\" or \"he sacrificed.\" أُهِلَّ is a passive form meaning \"it was proclaimed\" or \"it was invoked,\" often referring to an announcement or declaration made during an act of dedication, such as the invocation of a deity's name during sacrifice. The root emphasizes vocalization and ritualistic pronouncement, capturing the act of calling out to sanctify or dedicate an offering.",
  "447": "أُوذِيَ and related words stem from the root أ-ذ-ى, with the root verb أَذَى meaning \"he harmed,\" \"he injured,\" or \"he caused annoyance or discomfort.\" أُوذِيَ is a passive form meaning \"he was harmed\" or \"he was afflicted,\" highlighting the experience of enduring harm or annoyance. The root also encompasses broader concepts of slight affliction, irritation, or emotional distress. ",
  "448": "إِبِلٌ and related words stem from the root أ-ب-ل, with the root verb أَبِلَ meaning \"he became skilled in managing camels or sheep\" or \"became numerous.\" The root conveys abundance and expertise. إِبِلٌ means \"camels\" or \"a herd of camels,\" emphasizing their vital role in Arab culture and desert life. Camels symbolized wealth, status, and survival, serving as essential assets for transportation and trade. The root reflects the skill required to manage camels, highlighting their importance as a cornerstone of desert life.",
  "449": "إِبْرَاهِيمُ is the name of Prophet Abraham (ﷺ). While the name does not derive from a standard Arabic root, some suggest a connection to the root ب-ر-ه, with بَرَاهَةٌ meaning \"innocence\" or \"purity.\" Prophet Abraham (ﷺ) is celebrated for his pure monotheism and rejection of idolatry, embodying spiritual purity. His life exemplifies the journey toward recognizing and submitting to the one true God, emphasizing inner purification and devotion to faith.",
  "450": "إِبْكارٌ and related words stem from the root ب-ك-ر, with the root verb بَكَرَ meaning \"he did something early,\" \"he went forth early in the morning, in the first part of the day,\" or \"he hastened.\" إِبْكارٌ means \"early morning,\" emphasizing the act of beginning this time early, with a focus on doing something at the start of the day. The root conveys themes of ideas of freshness, new beginnings, and readiness, capturing the energy and purity of the early hours as an optimal time for focus, action, or renewal, conveying the importance of taking initiative and embracing opportunities with promptness.",
  "451": "إِبْلِيسُ stems from the root ب-ل-س, with the root verb بَلِسَ meaning \"he despaired\" or \"he lost hope.\" إِبْلِيسُ is the name of Satan, who refused to bow to Adam (ﷺ), rejected responsibility for his actions, and instead blamed Allah (ﷻ) for his transgression. As a result, he was expelled from Allah’s (ﷻ) mercy. The connection lies in Iblis embodying despair, as he was cut off from hope due to his arrogance and disobedience. This highlights that turning away from Allah’s (ﷻ) commands, failing to accept responsibility, and failing to ask for forgiveness leads to spiritual ruin and hopelessness.",
  "452": "إِثْمٌ and related words stem from the root أ-ث-م, with the root verb أَثِمَ meaning \"he sinned\" or \"he committed a misdeed.\" إِثْمٌ means \"sin,\" \"transgression,\" or \"offense.\" The root also conveys the idea of hindrance and deprivation, emphasizing how sin obstructs spiritual growth and distances one from Allah (ﷻ). In the Qur'an, إِثْمٌ encompasses all forms of disobedience and unethical behavior, highlighting its role as a barrier to attaining righteousness and the importance of seeking repentance to restore one's connection to Allah (ﷻ).",
  "453": "إِجْرَامٌ and related words stem from the root ج-ر-م, with the root verb جَرَمَ meaning \"he cut off\" or \"he committed a crime.\" إِجْرَامٌ means \"criminality\" or \"sinfulness,\" describing a state of habitual or characteristic wrongdoing. The root emphasizes the idea of severing ties, particularly from morality, righteousness, or lawful conduct. إِجْرَامٌ reflects a condition where repeated transgressions solidify a disconnection from upright behavior, capturing the severity of being entrenched in sin or crime.",
  "454": "إِحْدَى and related words stem from the root أ-ح-د, with the root verb وَحَّدَ meaning \"he made one,\" \"he unified,\" or \"he declared the oneness (of God).\" أَحَدٌ means \"one,\" \"someone,\" or \"anyone,\" and إِحْدَى is its feminine form, meaning \"one\" or \"someone\" among a group of feminine nouns. The root emphasizes singularity and uniqueness.",
  "455": "إِحْسَانٌ and related words stem from the root ح-س-ن, with the root verb حَسُنَ meaning \"he was good\" or \"he became beautiful,\" and أَحْسَنَ meaning \"he did excellently\" or \"he did good.\" إِحْسَانٌ translates as \"excellence\" or \"benevolence,\" describing the act of doing good with utmost care and intention. The root reflects themes of virtue, beauty, and striving for perfection, emphasizing both outward actions and inward character. The connection lies in embodying and manifesting goodness, directly tied to the root's focus on beauty and moral excellence. This term represents the pinnacle of ethical conduct, encompassing not only acts of kindness but also the pursuit of spiritual and moral refinement.",
  "456": "إِخْراجٌ and related words stem from the root خ-ر-ج, with the root verb خَرَجَ meaning \"he went out\" or \"he exited.\" إِخْراجٌ means \"bringing out\" or \"expulsion.\" The root conveys themes of exiting, emergence, and removal. The connection lies in how إِخْراجٌ shifts the action from voluntary departure to an external force causing something to be brought out, whether by expulsion, extraction, or production, emphasizing an intentional act of making something leave its original state or place.",
  "457": "إِخْوَةٌ and related words stem from the root أ-خ-و, with the root verb آخَى meaning \"he took as a brother\" or \"he fraternized,\" describing the formation of a brotherly bond. إِخْوَةٌ is the plural of أَخٌ, meaning \"brothers\" or \"brethren.\" It reflects collective kinship and shared values, emphasizing unity and communal support. In the Qur'an, إِخْوَةٌ describes relationships among siblings or members of a community, highlighting mutual respect, cooperation, and harmony. In Islam, the term highlights the importance of family bonds and extends to friendship, signifying broader ties beyond kinship.",
  "458": "إِدٌّ and related words stem from the root أ-د-د, with the root verb أَدَّ meaning \"a calamity befell, oppressed, distressed, or afflicted.\" إِدٌّ means \"a very evil, abominable, severe thing,\" or \"monstrous,\" representing something exceedingly grievous or heinous. The root also conveys the idea of burden or weight, emphasizing the oppressive nature of such acts. In the Qur'an, it is used once to describe the enormity of those who claim that Allah (ﷻ) has taken a son, emphasizing the severity of this transgression. The connection lies in the fact that such a claim oversteps Allah’s (ﷻ) limits, and by doing so, they bring calamity upon themselves, ultimately wronging their own souls.",
  "459": "إِدْبَارٌ and related words stem from the root د-ب-ر, with the root verb دَبَرَ meaning \"it came after or followed\" or \"he turned his back or went away.\" The root revolves around sequential occurrence, management, and decline, conveying the idea of things following one another, planning, and retreat over time. إِدْبَارٌ means \"decline,\" \"retreat,\" or \"setting\" (as in the setting of the sun), emphasizing the process of withdrawal or fading. The connection to the root highlights the idea of something passing away or moving out of prominence, whether in physical movement, the passage of time, or the decline of strength, status, or light.",
  "460": "إِدْرِيسُ stems from the root د-ر-س, with the root verb دَرَسَ meaning \"he studied\" or \"he learned.\" إِدْرِيسُ is the name of Prophet Enoch (ﷺ), renowned for his wisdom and dedication to knowledge. The connection lies in his devotion to learning and understanding divine revelations, reflecting the root concept of study. His life serves as an example of the importance of seeking knowledge and wisdom as a means of growing closer to Allah (ﷻ).",
  "461": "The particle إِذْ means \"when,\" used to reference a specific point in time, especially in past events. In the Qur'an, it introduces past occurrences or divine interventions, emphasizing lessons and Allah’s (ﷻ) guidance. It can also indicate simultaneous actions, highlighting events happening under specific circumstances. Additionally, إِذْ denotes causality, explaining why events occur. While mainly used for past events, it can rhetorically describe future events with certainty, as if they have already happened.",
  "462": "إِذْنٌ and related words stem from the root أ-ذ-ن, with the root verb أَذِنَ meaning \"he listened\" or \"he permitted.\" إِذْنٌ means \"permission\" or \"consent.\" The connection lies in granting authorization after listening and consideration, reflecting the root's emphasis on attentive decision-making. This term highlights the importance of mutual respect and acknowledgment in social and interpersonal interactions.",
  "463": "إِرَمَ stems from the root أ-ر-م, with the root verb أَرِمَ meaning \"to decay\" or \"to be consumed.\" إِرَمَ also refers to stone markers used to guide travelers in the desert. In the Qur'an, it denotes Iram of the Pillars, the grand city of the tribe of 'Ād. The connection lies in إِرَمَ serving as both a physical marker for travelers and a symbolic one for future generations, reminding both believers and disbelievers of their once-great existence and eventual destruction. Their annihilation by a fierce wind consumed them, leaving them lifeless, like hollow trunks of palm trees.",
  "464": "إِرْبَةٌ and related words stem from the root أ-ر-ب, with the root verb أَرِبَ meaning \"he was skillful,\" \"he was clever,\" or \"he had a need or desire.\" إِرْبَةٌ means \"need,\" \"desire,\" or \"purpose,\" reflecting a clear focus on fulfilling specific requirements. The root broadly conveys ideas of ingenuity, resourcefulness, and purpose, emphasizing human capability in addressing needs and achieving goals.  The connection lies in the root's emphasis on intentionality and skillful pursuit, highlighting the drive to fulfill aspirations through thoughtful planning and resourceful action.",
  "465": "إِرْصَادٌ and related words stem from the root ر-ص-د, with the root verb رَصَدَ meaning \"he watched,\" \"he observed attentively,\" or \"he lay in wait.\" إِرْصَادٌ means \"watching,\" \"ambushing,\" or \"lying in wait.\" The connection lies in the deliberate and vigilant preparation for an event or encounter, embodying the root's emphasis on attentiveness and readiness. This term captures the essence of being on guard, awaiting an opportunity or guarding against a threat, reflecting the root's connotations of careful observation and strategic anticipation.",
  "466": "إِسْتَبْرَقٌ and related words stem from the root ب-ر-ق, with the root verb بَرَقَ meaning \"it flashed\" or \"it glittered.\" إِسْتَبْرَقٌ refers to a thick, closely woven silk brocade, made with or interwoven with gold. The connection lies in the shimmering quality of the fabric, which gleams like flashes of lightning, reflecting the root's meaning. This term evokes the splendor and opulence of heavenly garments described in the Qur'an, symbolizing the luxurious rewards awaiting the faithful in the afterlife and emphasizing the beauty and comfort promised to believers.",
  "467": "إِسْحَاقُ stems from the root س-ح-ق, with the root verb سَحَقَ meaning \"to crush\" or \"to pulverize.\" إِسْحَاقُ is the name of Prophet Isaac (ﷺ), and while the root typically signifies crushing or grinding, it can metaphorically represent a powerful and transformative process. The connection lies in how Prophet Isaac's (ﷺ) birth, against all odds, \"crushed\" the doubts surrounding the possibility of his parents conceiving in old age. His story highlights how Allah's (ﷻ) will can break through human limitations and expectations, emphasizing the crushing of obstacles in the path of faith.",
  "468": "إِسْرَائِيلُ is a compound of two Hebrew elements: \"Isra\", meaning \"to strive\" or \"to struggle,\" and \"El\", meaning \"God.\" The name is interpreted as \"One who strives with God\" or \"One who struggles in the presence of God.\" This name, given to Prophet Jacob (ﷺ), reflects his life of perseverance and trust in Allah (ﷻ) through significant trials, including his unwavering patience during separation from his son Prophet Joseph (ﷺ) and his steadfast hope in Allah’s (ﷻ) mercy. While his original name remains distinct, إِسْرَائِيلُ symbolizes his enduring reliance on Allah (ﷻ) during challenges. His reliance was not passive but rather an active struggle marked by patience, prayer, and unwavering faith.",
  "469": "إِسْرَارٌ and related words stem from the root س-ر-ر, with the root verb سَرَّ meaning \"he concealed\" or \"he kept secret.\" إِسْرَارٌ means \"concealing,\" \"keeping secret,\" or \"secrecy.\" The connection lies in the act of hiding or keeping something undisclosed, directly reflecting the root's emphasis on secrecy. This term highlights the importance of inner thoughts and intentions that are not outwardly expressed.",
  "470": "إِسْرَافٌ and related words stem from the root س-ر-ف, with the root verb سَرَفَ meaning \"he exceeded,\" \"he was extravagant,\" or \"he transgressed limits.\" إِسْرَافٌ means \"extravagance,\" \"excess,\" or \"immoderation.\" The connection lies in the act of going beyond proper limits, directly reflecting the root's emphasis on overindulgence. This term highlights the concept of exceeding bounds, emphasizing the importance of moderation.",
  "471": "إِسْلَامٌ and related words stem from the root س-ل-م, with the root verb سَلِمَ meaning \"he was safe,\" \"he was sound,\" or \"he was unharmed.\" إِسْلَامٌ means \"submission,\" \"surrender,\" or \"entering into peace,\" referring to Islam itself. The connection lies in surrendering to Allah’s (ﷻ) will, achieving safety and peace, which reflects the root's essence of soundness and well-being. It signifies the religion based on submission to Allah (ﷻ), emphasizing spiritual harmony and moral integrity through alignment with Allah’s (ﷻ) guidance.",
  "472": "إِسْمَاعِيلُ stems from the root س-م-ع, with the root verb سَمِعَ meaning \"he heard.\" The name reflects qualities of attentiveness and responsiveness, which are evident in Prophet Ishmael’s (ﷺ) character. His life embodies a willingness to listen, obey, and submit to Allah’s (ﷻ) commands, showing both spiritual and physical responsiveness. This attentiveness is particularly demonstrated in his acceptance of divine instruction with patience and steadfastness, making his name a reflection of his exemplary qualities of obedience and submission.",
  "473": "إِشْرَاقٌ and related words stem from the root ش-ر-ق, with the root verb شَرَقَ meaning \"it rose\" or \"it shone.\" إِشْرَاقٌ means \"shining\" or \"illumination,\" representing the act of emitting light. The connection lies in the root's emphasis on the rising sun, highlighting enlightenment and the dawn of new understanding.",
  "474": "إِصْبَاحٌ and related words stem from the root ص-ب-ح, with the root verb صَبَحَ meaning \"he entered the morning.\" إِصْبَاحٌ means \"morning\" or \"dawn.\" The connection lies in the root's focus on the arrival of daylight. إِصْبَاحٌ represents the time when darkness gives way to light, symbolizing hope, clarity, and the dispelling of ignorance or uncertainty.",
  "475": "إِصْرٌ and related words stem from the root أ-ص-ر, with the root verb أَصَرَ meaning \"he confined\" or \"he prevented.\" إِصْرٌ means \"burden\" or \"covenant.\" The connection lies in the idea of being bound by a burden or responsibility. The burden refers to the constraints humans place upon themselves through worldly attachments and misguidance. In contrast, the covenant is the divine responsibility Allah (ﷻ) gave to the children of Adam (ﷺ) through the prophets to relieve them of these burdens and lead them toward light and guidance, freeing them from worldly evils and lower desires.",
  "476": "إِصْلَاحٌ and related words stem from the root ص-ل-ح, with the root verb صَلَحَ meaning \"he was righteous.\" إِصْلَاحٌ means \"reformation,\" \"improvement,\" or \"rectification.\" The connection lies in the process of making things right, reflecting the root's focus on restoring righteousness and order. It conveys not just personal goodness but the correction of wrongs, whether moral or social. In the Qur'an, إِصْلَاحٌ emphasizes the importance of reconciliation, repairing relationships, and seeking harmony, aligning human actions with divine guidance for collective well-being and moral rectitude.",
  "477": "إِطْعَامٌ and related words stem from the root ط-ع-م, with the root verb طَعِمَ meaning \"he tasted\" or \"he ate.\" إِطْعَامٌ means \"feeding\" or \"providing food.\" The connection lies in the act of giving nourishment, directly relating to the root's emphasis on taste and sustenance. This term encapsulates the concept of feeding others, highlighting generosity and benevolence. It emphasizes the moral importance of caring for the hungry and promoting social welfare.",
  "478": "إِعْراضٌ and related words stem from the root ع-ر-ض, with the root verb عَرَضَ meaning \"he presented\" or \"he offered.\" إِعْراضٌ means \"turning away,\" \"avoidance,\" or \"aversion.\" The term embodies the action of deliberately avoiding or shunning something, directly connected to the root's concept of presentation but indicating a rejection or refusal. This highlights the moral consequences of turning away from guidance or truth, emphasizing the need for openness and acceptance in spiritual and ethical pursuits.",
  "479": "إِعْصارٌ and related words stem from the root ع-ص-ر, with the root verb عَصَرَ meaning \"he squeezed\" or \"he pressed.\" إِعْصارٌ refers to a \"whirlwind\" or \"tornado.\" The connection lies in the spiraling, twisting motion of a whirlwind that resembles the action of twisting or squeezing. This term captures the powerful and destructive force of such natural phenomena, reflecting the root's emphasis on pressing movements."
};
